window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
/* C-10 Electrical — California trade-exam practice questions (500, 5 blocks of 100).
   ORIGINAL practice questions in the STYLE of the CSLB C-10 Trade exam — NOT actual
   exam questions. Organized on the official CSLB C-10 content outline (Planning &
   Estimation · Rough Wiring · Finish Wiring & Trim · Startup, Troubleshooting &
   Maintenance · Safety) and built on stable NEC / California Electrical Code rules.
   EN + RU. Each question: id, sec, block (1-5), q/opts/correct/re + RU qr/optsr/rr.
   ⚠ Verify every figure against the current code edition (2025 CEC / 2023 NEC for
   2026) — this is a study aid, not a guarantee. */
window.COURSE_REGISTRY["c10-exam"] = [
  {"id":1,"sec":"Planning & Estimation","block":1,"q":"A 120 V circuit supplies a heating element with a resistance of 20 ohms; what is the current draw?","opts":["2 A","0.17 A","6 A","2400 A"],"correct":2,"re":"By Ohm's law, I = V/R = 120/20 = 6 A."},
  {"id":2,"sec":"Rough Wiring","block":1,"q":"Which conductor insulation type is rated 90°C in dry locations but is NOT approved for use in wet locations?","opts":["THWN-2","THHN","XHHW-2","USE-2"],"correct":1,"re":"THHN is a 90°C dry/damp-location insulation; for wet locations THWN-2 or XHHW-2 is used. See NEC Table 310.4(A)."},
  {"id":3,"sec":"Finish Wiring & Trim","block":1,"q":"In a dwelling unit habitable room, what is the maximum horizontal distance from any point along the wall line to a receptacle outlet?","opts":["3 feet","12 feet","10 feet","6 feet"],"correct":3,"re":"NEC 210.52(A) requires that no point along the floor line of a wall be more than 6 ft from a receptacle, so that an appliance cord of 6 ft can reach an outlet from either direction."},
  {"id":4,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Per NEC 430.22, what is the minimum branch-circuit conductor ampacity required for a single continuous-duty motor with a full-load current of 28 amps?","opts":["28 amps","31 amps","40 amps","35 amps"],"correct":3,"re":"NEC 430.22 requires branch-circuit conductors for a single motor to have an ampacity of at least 125% of the motor full-load current: 28 A x 1.25 = 35 A."},
  {"id":5,"sec":"Safety","block":1,"q":"Under Cal/OSHA Title 8 Section 3314, what is the primary purpose of a lockout/tagout procedure?","opts":["To control hazardous energy so equipment cannot be unexpectedly energized or started during service or maintenance","To document the qualifications of each electrician on the job site","To reduce the available fault current at the equipment terminals","To provide a backup ground path for the electrical system"],"correct":0,"re":"Cal/OSHA T8 Section 3314 requires control of hazardous energy through lockout/tagout so machines or equipment are isolated and cannot start up unexpectedly during servicing."},
  {"id":6,"sec":"Rough Wiring","block":1,"q":"What does the 'W' in the conductor insulation designation THWN-2 indicate?","opts":["Wound (stranded) construction","Wire is solid","White color coding","Suitable for wet locations"],"correct":3,"re":"In NEC insulation lettering, 'W' means the conductor is rated for wet locations. See NEC Table 310.4(A) and Annex."},
  {"id":7,"sec":"Planning & Estimation","block":1,"q":"What is the power dissipated by a 240 V appliance that draws 12.5 A?","opts":["3000 W","19.2 W","252.5 W","1920 W"],"correct":0,"re":"Using P = V x I = 240 x 12.5 = 3000 W."},
  {"id":8,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"When sizing branch-circuit conductors for a single motor under NEC 430.22, which value should be used as the basis for the calculation?","opts":["The full-load current value from the NEC tables","The full-load current from the motor nameplate","The locked-rotor current of the motor","The service-factor amperage stamped on the nameplate"],"correct":0,"re":"NEC 430.6(A) specifies that conductor and overcurrent device sizing per 430.22 is based on the table values (such as Table 430.248/430.250), not the nameplate FLA."},
  {"id":9,"sec":"Safety","block":1,"q":"According to NFPA 70E, what is the general rule regarding working on electrical equipment?","opts":["Equipment must be placed in an electrically safe work condition (de-energized) unless de-energizing introduces additional hazards or is infeasible","Equipment may stay energized as long as a second worker is present","Equipment must remain energized so voltage can be verified at all times","Energized work is always acceptable if rubber gloves are worn"],"correct":0,"re":"NFPA 70E requires establishing an electrically safe work condition before work begins; energized work is only permitted when de-energizing introduces additional or increased hazards or is infeasible due to equipment design or operational limitations."},
  {"id":10,"sec":"Rough Wiring","block":1,"q":"Which insulation type is specifically intended for underground service-entrance use and is suitable for direct burial?","opts":["THHN","USE","RHW","TW"],"correct":1,"re":"USE (Underground Service Entrance) is rated for direct burial and underground use. See NEC Table 310.4(A)."},
  {"id":11,"sec":"Planning & Estimation","block":1,"q":"A resistor of 8 ohms carries a current of 5 A; how much power does it dissipate?","opts":["200 W","40 W","1.6 W","320 W"],"correct":0,"re":"Using P = I squared x R = 5 squared x 8 = 25 x 8 = 200 W."},
  {"id":12,"sec":"Finish Wiring & Trim","block":1,"q":"Under the dwelling receptacle spacing rule, what is the maximum spacing permitted between adjacent general-use receptacles along a wall?","opts":["6 feet","20 feet","15 feet","12 feet"],"correct":3,"re":"Because no point may be more than 6 ft from a receptacle, receptacles spaced evenly along a wall may be up to 12 ft apart (6 ft reach from each), per NEC 210.52(A)."},
  {"id":13,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A three-phase continuous-duty motor has a full-load current of 80 amps; what is the minimum branch-circuit conductor ampacity required by NEC 430.22?","opts":["100 amps","92 amps","80 amps","125 amps"],"correct":0,"re":"NEC 430.22 requires 125% of the motor FLC: 80 A x 1.25 = 100 A minimum conductor ampacity."},
  {"id":14,"sec":"Safety","block":1,"q":"Which procedure is used to verify that a circuit is de-energized before a qualified person begins work?","opts":["The live-dead-live (test-before-touch) method using an adequately rated voltage tester","Confirming the utility meter has stopped spinning","Visual inspection of the panel labels only","Touching the conductor briefly with the back of the hand"],"correct":0,"re":"The live-dead-live method requires testing the voltage tester on a known live source, testing the de-energized conductors, then re-testing on the known live source to confirm the tester still works, verifying the absence of voltage."},
  {"id":15,"sec":"Rough Wiring","block":1,"q":"RHW insulation is rated for which maximum operating temperature?","opts":["75°C","90°C","60°C","105°C"],"correct":0,"re":"RHW is a thermoset insulation rated 75°C for wet and dry locations. See NEC Table 310.4(A)."},
  {"id":16,"sec":"Planning & Estimation","block":1,"q":"A 120 V source is connected across a 60 ohm resistor; what power is dissipated?","opts":["2 W","7200 W","240 W","120 W"],"correct":2,"re":"Using P = V squared / R = 120 squared / 60 = 14400 / 60 = 240 W."},
  {"id":17,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"For a continuous-duty motor with a marked service factor of 1.15, what percentage of the motor nameplate full-load current is used to size the separate overload protection per NEC 430.32?","opts":["125%","115%","140%","250%"],"correct":0,"re":"NEC 430.32(A)(1) permits overload protection at 125% of nameplate FLA when the service factor is 1.15 or greater (or the temperature rise is 40°C or less)."},
  {"id":18,"sec":"Safety","block":1,"q":"Per NFPA 70E, which boundary may only be crossed by a qualified person using appropriate shock PPE?","opts":["The arc-flash boundary for unqualified observers","The limited approach boundary for escorted visitors","The restricted approach boundary","The outer property fence line"],"correct":2,"re":"Under NFPA 70E, the restricted approach boundary may be crossed only by a qualified person who has a documented plan and is using appropriate shock-protection PPE because of the increased risk of contact with energized parts."},
  {"id":19,"sec":"Rough Wiring","block":1,"q":"XHHW is a thermoset insulation; what is its temperature rating in a dry location?","opts":["60°C","75°C","110°C","90°C"],"correct":3,"re":"XHHW is rated 90°C in dry/damp locations (and 75°C in wet locations). See NEC Table 310.4(A)."},
  {"id":20,"sec":"Planning & Estimation","block":1,"q":"Three resistors of 10 ohms, 15 ohms, and 25 ohms are connected in series; what is the total resistance?","opts":["4.84 ohms","5 ohms","50 ohms","3750 ohms"],"correct":2,"re":"Series resistances add: 10 + 15 + 25 = 50 ohms."},
  {"id":21,"sec":"Finish Wiring & Trim","block":1,"q":"For the purpose of dwelling receptacle spacing, any wall space how wide or wider must be provided with a receptacle outlet?","opts":["12 inches (1 ft) or wider","24 inches (2 ft) or wider","18 inches or wider","36 inches (3 ft) or wider"],"correct":1,"re":"NEC 210.52(A)(2) defines a wall space that must be counted as any space 2 ft (600 mm) or more in width, including space measured around corners."},
  {"id":22,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A continuous-duty motor has a service factor of 1.0 and a temperature rise of 50°C; what percentage of nameplate full-load current is allowed for sizing its overload protection under NEC 430.32?","opts":["100%","130%","125%","115%"],"correct":3,"re":"NEC 430.32(A)(1) limits overload protection to 115% of nameplate FLA for motors that do not have a service factor of 1.15+ or a temperature rise of 40°C or less."},
  {"id":23,"sec":"Rough Wiring","block":1,"q":"A run requires conductors in a conduit that will be installed in a continuously wet underground location; which insulation is appropriate?","opts":["THWN-2","TW only","THHN only","RHH"],"correct":0,"re":"THWN-2 carries a 'W' rating and is suitable for wet locations; THHN, TW (60°C), and RHH (dry) are less appropriate here. See NEC Table 310.4(A)."},
  {"id":24,"sec":"Safety","block":1,"q":"What document is required by NFPA 70E before performing justified energized work inside the restricted approach or arc-flash boundary?","opts":["A material safety data sheet","A building occupancy certificate","An energized electrical work permit","A load calculation worksheet"],"correct":2,"re":"NFPA 70E requires an energized electrical work permit, signed by authorized management, when work is performed inside the restricted approach boundary or where an arc-flash hazard exists and the work cannot be done de-energized."},
  {"id":25,"sec":"Planning & Estimation","block":1,"q":"Two 20 ohm resistors are connected in parallel; what is the equivalent resistance?","opts":["40 ohms","10 ohms","20 ohms","0.1 ohms"],"correct":1,"re":"For two equal parallel resistors, R = R/2 = 20/2 = 10 ohms."},
  {"id":26,"sec":"Rough Wiring","block":1,"q":"Compared to copper, an aluminum conductor of the same AWG size generally has which characteristic?","opts":["Higher ampacity","No listed ampacity","Identical ampacity","Lower ampacity"],"correct":3,"re":"Aluminum has higher resistivity than copper, so an equal-size aluminum conductor has a lower ampacity. See NEC Table 310.16."},
  {"id":27,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A motor nameplate lists 16 amps full-load current and a service factor of 1.25; what is the maximum overload protection setting permitted by NEC 430.32?","opts":["16 amps","20 amps","18.4 amps","24 amps"],"correct":1,"re":"With a service factor of 1.15 or more, NEC 430.32(A)(1) allows 125% of nameplate FLA: 16 A x 1.25 = 20 A."},
  {"id":28,"sec":"Safety","block":1,"q":"How does NFPA 70E define a qualified person?","opts":["Any worker who has been employed by the company for at least five years","Any person holding a valid driver's license and first-aid card","Only a licensed professional engineer","One who has demonstrated skills and knowledge related to the construction and operation of electrical equipment and has received safety training to recognize and avoid the hazards involved"],"correct":3,"re":"NFPA 70E defines a qualified person as one who has demonstrated skills and knowledge related to the construction and operation of the electrical equipment and installations and has received safety training to identify and avoid the hazards involved."},
  {"id":29,"sec":"Planning & Estimation","block":1,"q":"A 6 ohm and a 12 ohm resistor are connected in parallel; what is the total resistance?","opts":["18 ohms","4 ohms","9 ohms","0.25 ohms"],"correct":1,"re":"Parallel: R = (6 x 12)/(6 + 12) = 72/18 = 4 ohms."},
  {"id":30,"sec":"Rough Wiring","block":1,"q":"Per NEC Table 310.16, what is the ampacity of a 14 AWG copper conductor in the 60°C column?","opts":["25 A","20 A","15 A","30 A"],"correct":2,"re":"In the 60°C column of Table 310.16, 14 AWG copper is rated 15 A."},
  {"id":31,"sec":"Finish Wiring & Trim","block":1,"q":"Along a kitchen countertop, receptacles serving the counter must be installed so that no point along the wall countertop is more than what distance from a receptacle?","opts":["24 inches","20 inches","12 inches","30 inches"],"correct":0,"re":"NEC 210.52(C) requires that receptacles be placed so no point along the wall line of the countertop is more than 24 in. from a receptacle, supporting the 'no point more than 24 in.' rule for a 2-ft cord reach."},
  {"id":32,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What is the primary purpose of the motor overload protection device required by NEC 430 Part III?","opts":["To protect against short circuits between conductors","To protect the motor and conductors from sustained overcurrent due to motor overload","To provide instantaneous disconnection during a ground fault","To limit voltage spikes during motor starting"],"correct":1,"re":"NEC 430.32 overload devices protect the motor, motor-control apparatus, and branch-circuit conductors against excessive heating from running overcurrents (overloads), not short circuits or ground faults."},
  {"id":33,"sec":"Safety","block":1,"q":"What is the purpose of the arc-flash boundary established under NFPA 70E?","opts":["It marks where the incident energy equals 1.2 cal/cm2, the onset of a second-degree burn to bare skin","It indicates the maximum length of an extension cord allowed","It defines the minimum bending radius for conductors","It sets the distance for required emergency lighting"],"correct":0,"re":"The arc-flash boundary is the distance at which the incident energy is 1.2 cal/cm2; at this point an unprotected person could receive a second-degree burn if an arc-flash occurred."},
  {"id":34,"sec":"Planning & Estimation","block":1,"q":"Four 100 ohm resistors are connected in parallel; what is the equivalent resistance?","opts":["400 ohms","100 ohms","25 ohms","50 ohms"],"correct":2,"re":"For equal parallel resistors, R = R/n = 100/4 = 25 ohms."},
  {"id":35,"sec":"Rough Wiring","block":1,"q":"The three temperature columns in NEC Table 310.16 represent which conductor property?","opts":["Insulation temperature ratings","Ambient temperature ranges","Conduit fill percentages","Voltage class ratings"],"correct":0,"re":"The 60°C, 75°C, and 90°C columns correspond to the temperature rating of the conductor insulation. See NEC Table 310.16."},
  {"id":36,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Which device in a motor branch circuit is designed to protect against short circuits and ground faults rather than running overloads?","opts":["The thermal overload relay","The control transformer","The motor holding contact","The branch-circuit short-circuit and ground-fault protective device (fuse or breaker)"],"correct":3,"re":"NEC 430 Part IV requires a branch-circuit short-circuit and ground-fault protective device (typically a fuse or inverse-time circuit breaker) that is separate from the running-overload device in Part III."},
  {"id":37,"sec":"Planning & Estimation","block":1,"q":"In a series circuit with a 30 ohm and a 60 ohm resistor across 90 V, what is the circuit current?","opts":["3 A","0.5 A","1 A","90 A"],"correct":2,"re":"Total R = 30 + 60 = 90 ohms; I = V/R = 90/90 = 1 A."},
  {"id":38,"sec":"Rough Wiring","block":1,"q":"When a conductor with 90°C insulation terminates on equipment rated for 75°C, which column's ampacity must be used for the final termination rating?","opts":["60°C","90°C","75°C","Average of 75°C and 90°C"],"correct":2,"re":"Per NEC 110.14(C), the lowest temperature rating of any connected termination or conductor governs; here the 75°C column applies."},
  {"id":39,"sec":"Safety","block":1,"q":"When applying lockout/tagout under Cal/OSHA T8 Section 3314, who is permitted to remove a lock that an authorized employee placed on a disconnect?","opts":["Any electrician on the next shift who needs the circuit","Generally only the authorized employee who applied that lock, except under a documented procedure when that employee is unavailable","The site security guard at the end of the day","Any apprentice working in the same area"],"correct":1,"re":"Cal/OSHA T8 Section 3314 requires that each lock be removed by the employee who applied it; removal by others is allowed only through a specific documented procedure when that employee is absent and the employer verifies it is safe."},
  {"id":40,"sec":"Finish Wiring & Trim","block":1,"q":"A kitchen wall countertop space is at least how wide before a receptacle outlet is required to serve it?","opts":["12 inches","6 inches","18 inches","24 inches"],"correct":0,"re":"NEC 210.52(C)(1) requires a receptacle for each wall countertop space that is 12 in. (300 mm) or wider."},
  {"id":41,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Why is the branch-circuit short-circuit and ground-fault protective device for a motor typically rated higher than the motor's full-load current?","opts":["Because it must also serve as the overload device","Because conductors are always oversized","Because it must allow the high inrush (locked-rotor) current during motor starting without tripping","Because the nameplate current is inaccurate"],"correct":2,"re":"Motors draw a large inrush/locked-rotor current at startup, so NEC 430.52 permits the short-circuit/ground-fault device to be set well above FLC so it does not nuisance-trip while still protecting against faults."},
  {"id":42,"sec":"Rough Wiring","block":1,"q":"The 90°C column of an ampacity table is primarily used for which purpose?","opts":["The final allowable load on terminals","Determining conduit size","Applying derating/correction factors as a starting point","Selecting overcurrent device size directly"],"correct":2,"re":"The 90°C ampacity is commonly used as the starting value for adjustment and correction factors, provided terminations are not exceeded. See NEC 110.14(C) and 310.15."},
  {"id":43,"sec":"Planning & Estimation","block":1,"q":"A single-phase load draws 16 A at 240 V; what is the apparent power in volt-amperes?","opts":["3840 VA","15 VA","256 VA","1920 VA"],"correct":0,"re":"Apparent power S = V x I = 240 x 16 = 3840 VA."},
  {"id":44,"sec":"Safety","block":1,"q":"What does establishing an electrically safe work condition require after the disconnecting means is opened?","opts":["Immediately beginning work since the switch is off","Waiting 24 hours before any testing","Visually verifying the disconnect is open, applying lockout/tagout, testing for absence of voltage, and grounding where induced or stored energy may be present","Calling the utility to confirm the meter reading"],"correct":2,"re":"NFPA 70E lists the steps to establish an electrically safe work condition, including verifying the disconnect is open, applying LOTO, testing for absence of voltage with an adequately rated device, and applying grounds where stored or induced voltage could exist."},
  {"id":45,"sec":"Rough Wiring","block":1,"q":"When the ambient temperature exceeds 30°C (86°F), the conductor ampacity from Table 310.16 must be:","opts":["Multiplied by a correction factor less than 1.0","Increased by the correction factor","Left unchanged","Multiplied by 1.25"],"correct":0,"re":"Higher ambient temperatures reduce ampacity, so a correction factor below 1.0 from Table 310.15(B)(1) is applied."},
  {"id":46,"sec":"Planning & Estimation","block":1,"q":"What current does a 1500 W single-phase resistive heater draw on a 120 V circuit?","opts":["12.5 A","180000 A","0.08 A","8 A"],"correct":0,"re":"I = P/V = 1500/120 = 12.5 A (resistive, PF = 1)."},
  {"id":47,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a standard three-phase induction motor, how is the direction of rotation reversed?","opts":["By reversing all three line leads","By reversing the connection of the equipment grounding conductor","By interchanging any two of the three line leads","By increasing the supply voltage"],"correct":2,"re":"Swapping any two of the three line conductors reverses the phase sequence, which reverses the direction of the rotating magnetic field and thus the motor rotation."},
  {"id":48,"sec":"Safety","block":1,"q":"Which of the following tasks is an unqualified person permitted to perform near energized electrical equipment?","opts":["Opening an energized motor control center to troubleshoot","Work outside the limited approach boundary, where exposure to energized parts is not present","Crossing the restricted approach boundary to take measurements","Replacing energized bus connections during an outage"],"correct":1,"re":"Under NFPA 70E, an unqualified person may work outside the limited approach boundary; they are not permitted to cross it toward exposed energized parts unless continuously escorted by a qualified person and even then cannot perform the qualified work."},
  {"id":49,"sec":"Finish Wiring & Trim","block":1,"q":"A kitchen island countertop with a long dimension of 24 in. or greater and a short dimension of 12 in. or greater generally requires at least how many receptacle outlets?","opts":["Zero","Three","Two","One"],"correct":3,"re":"NEC 210.52(C) requires at least one receptacle outlet for an island countertop space meeting the minimum dimensions of 24 in. by 12 in."},
  {"id":50,"sec":"Rough Wiring","block":1,"q":"Ampacity tables such as Table 310.16 are based on an assumed ambient temperature of:","opts":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"correct":0,"re":"Table 310.16 is based on an ambient temperature of 30°C (86°F); other ambients require correction factors. See NEC 310.15(B)."},
  {"id":51,"sec":"Planning & Estimation","block":1,"q":"A resistor dissipates 600 W at a current of 5 A; what is its resistance?","opts":["120 ohms","24 ohms","3000 ohms","0.042 ohms"],"correct":1,"re":"From P = I squared x R, R = P / I squared = 600 / 25 = 24 ohms."},
  {"id":52,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A three-phase motor connected to lines L1-T1, L2-T2, L3-T3 is rotating in the wrong direction; which change will correct the rotation?","opts":["Swap L1 and L2 only","Swap all three leads simultaneously","Reconnect the neutral","Add a phase-shifting capacitor"],"correct":0,"re":"Reversing any two leads reverses rotation; swapping L1 and L2 (or any single pair) reverses the phase sequence and corrects the direction."},
  {"id":53,"sec":"Rough Wiring","block":1,"q":"If a 90°C conductor is installed in a 50°C ambient, why is starting from the 90°C column advantageous?","opts":["Its higher base ampacity better absorbs the temperature correction","It avoids any derating","It eliminates the need for correction factors","It allows a smaller overcurrent device"],"correct":0,"re":"Using the higher 90°C base ampacity gives more margin when the ambient correction factor reduces the value, as permitted by NEC 310.15(B) and 110.14(C)."},
  {"id":54,"sec":"Safety","block":1,"q":"What is the primary hazard that arc-flash PPE is designed to protect against?","opts":["Falls from elevated work platforms","Thermal burns from the radiant and convective heat of an electric arc","Hearing loss from rotating machinery","Chemical splashes from battery electrolyte"],"correct":1,"re":"Arc-rated PPE is selected based on incident energy to protect the worker from the intense thermal energy of an arc flash; it is rated in cal/cm2 to match or exceed the calculated incident energy."},
  {"id":55,"sec":"Planning & Estimation","block":1,"q":"What voltage is required to push 4 A through a 35 ohm resistor?","opts":["140 V","8.75 V","0.114 V","39 V"],"correct":0,"re":"By Ohm's law, V = I x R = 4 x 35 = 140 V."},
  {"id":56,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a magnetic motor starter, what is the function of the holding (maintaining) contact in the control circuit?","opts":["To open the circuit during an overload condition","To keep the starter coil energized after the momentary start button is released","To step down the control voltage","To reverse the motor rotation"],"correct":1,"re":"The holding contact is an auxiliary contact wired in parallel with the start button; once the coil energizes, it closes and maintains coil power so the motor keeps running after the start button is released."},
  {"id":57,"sec":"Rough Wiring","block":1,"q":"According to Table 310.15(C)(1), what adjustment factor applies when 4 to 6 current-carrying conductors are bundled in a raceway?","opts":["100%","80%","70%","50%"],"correct":1,"re":"For 4-6 current-carrying conductors, the adjustment factor is 80%. See NEC Table 310.15(C)(1)."},
  {"id":58,"sec":"Finish Wiring & Trim","block":1,"q":"Receptacles installed to serve dwelling kitchen countertop surfaces must be supplied by at least how many small-appliance branch circuits?","opts":["One 15-amp circuit","Two 20-amp circuits","One 30-amp circuit","Three 15-amp circuits"],"correct":1,"re":"NEC 210.11(C)(1) and 210.52(B) require at least two 20-amp small-appliance branch circuits to serve countertop and other receptacles in the kitchen, pantry, and dining areas."},
  {"id":59,"sec":"Safety","block":1,"q":"Under the NFPA 70E PPE category method, what determines which arc-flash PPE category applies to a task?","opts":["The color of the equipment enclosure","The specific equipment and task parameters listed in the arc-flash PPE category tables, including voltage and available fault current","The total horsepower of all connected motors","The age of the electrical panel"],"correct":1,"re":"NFPA 70E PPE category tables assign a category (1 through 4) based on the specific equipment type, available short-circuit current, and fault clearing time, which together estimate the arc-flash exposure."},
  {"id":60,"sec":"Planning & Estimation","block":1,"q":"A 2000 W appliance operates for 3 hours; how much energy does it consume?","opts":["0.67 kWh","667 Wh","6 kWh","6000 kWh"],"correct":2,"re":"Energy = power x time = 2000 W x 3 h = 6000 Wh = 6 kWh."},
  {"id":61,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a standard three-wire start/stop control circuit, how are the start and stop pushbuttons typically wired?","opts":["Start is normally closed and stop is normally open","Both buttons are normally closed and in parallel","Start (normally open) is in parallel with the holding contact, and stop (normally closed) is in series","Both buttons are normally open and in series"],"correct":2,"re":"A standard start/stop station uses a normally open start button (parallel with the holding contact to seal in) and a normally closed stop button in series, so pressing stop de-energizes the coil."},
  {"id":62,"sec":"Rough Wiring","block":1,"q":"Per Table 310.15(C)(1), what adjustment factor applies when 7 to 9 current-carrying conductors are run together in a raceway?","opts":["60%","80%","70%","50%"],"correct":2,"re":"For 7-9 current-carrying conductors, the adjustment factor is 70%. See NEC Table 310.15(C)(1)."},
  {"id":63,"sec":"Safety","block":1,"q":"When performing the live-dead-live test, why must the voltage tester be checked on a known energized source both before and after testing the de-energized circuit?","opts":["To charge the tester's internal battery","To confirm the tester is functioning properly so a false 'dead' reading is not relied upon","To calibrate the tester to the local utility frequency","To discharge stored capacitance in the conductors"],"correct":1,"re":"Re-verifying the tester on a known live source after the dead test confirms the instrument did not fail during the test, ensuring the absence-of-voltage reading was valid before touching conductors."},
  {"id":64,"sec":"Planning & Estimation","block":1,"q":"If electricity costs 0.20 dollars per kWh, what does it cost to run a 5 kW load for 8 hours?","opts":["40.00 dollars","1.60 dollars","8.00 dollars","0.20 dollars"],"correct":2,"re":"Energy = 5 kW x 8 h = 40 kWh; cost = 40 x 0.20 = 8.00 dollars."},
  {"id":65,"sec":"Rough Wiring","block":1,"q":"At what number of current-carrying conductors in a single raceway do the Table 310.15(C)(1) adjustment factors first apply?","opts":["2 or more","More than 3 (4 or more)","3 or more","More than 9"],"correct":1,"re":"Adjustment factors begin when there are more than three current-carrying conductors (i.e., 4 or more). See NEC 310.15(C)(1)."},
  {"id":66,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What is the main difference between a contactor and a magnetic motor starter?","opts":["A contactor includes built-in overload protection, but a starter does not","A contactor can only switch DC loads","A starter is essentially a contactor with integral overload protection added","A starter has no electromagnetic coil"],"correct":2,"re":"A magnetic motor starter is a contactor combined with an overload relay; a plain contactor switches the load but provides no running-overload protection."},
  {"id":67,"sec":"Finish Wiring & Trim","block":1,"q":"In a dwelling, hallways of at least what length require a minimum of one receptacle outlet?","opts":["15 feet","5 feet","12 feet","10 feet"],"correct":3,"re":"NEC 210.52(H) requires that hallways 10 ft (3.0 m) or more in length have at least one receptacle outlet."},
  {"id":68,"sec":"Planning & Estimation","block":1,"q":"A motor delivers 10 HP of mechanical output; approximately how many watts is this?","opts":["746 W","7460 W","1340 W","74.6 W"],"correct":1,"re":"Using 1 HP = 746 W, 10 HP = 10 x 746 = 7460 W."},
  {"id":69,"sec":"Safety","block":1,"q":"Per NFPA 70E, which condition justifies performing work on energized electrical conductors instead of de-energizing them?","opts":["The crew wants to finish the job faster","The supervisor verbally prefers energized work","De-energizing would introduce additional or increased hazards, or is infeasible due to equipment design or operational limitations","The equipment is rated above 600 volts"],"correct":2,"re":"NFPA 70E permits energized work only when de-energizing introduces additional or increased hazards (such as life-support shutdown) or is infeasible due to equipment design or operational limitations; convenience or saving time does not qualify."},
  {"id":70,"sec":"Rough Wiring","block":1,"q":"Six current-carrying THHN copper 12 AWG conductors (90°C value 30 A) share one conduit; after applying the bundling adjustment, the adjusted ampacity is approximately:","opts":["30 A","27 A","21 A","24 A"],"correct":3,"re":"Starting from the 90°C value of 30 A and applying the 80% factor for 4-6 conductors gives 30 × 0.80 = 24 A. See NEC Table 310.15(C)(1)."},
  {"id":71,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"When the overload relay of a magnetic motor starter trips, which circuit does it directly open to stop the motor?","opts":["The control circuit, de-energizing the starter coil","The main power (line) conductors to the motor","The equipment grounding conductor","The branch-circuit feeder"],"correct":0,"re":"Overload relay contacts are wired into the control circuit; when they trip open, the starter coil de-energizes, dropping out the main contacts and disconnecting the motor."},
  {"id":72,"sec":"Planning & Estimation","block":1,"q":"A 5 HP motor is 100 percent efficient and runs on 240 V single-phase at PF 1; what current does it draw?","opts":["3730 A","15.5 A","0.064 A","31 A"],"correct":1,"re":"P = 5 x 746 = 3730 W; I = P/V = 3730/240 = 15.5 A."},
  {"id":73,"sec":"Rough Wiring","block":1,"q":"Eight current-carrying conductors with a 90°C base ampacity of 40 A each are bundled in a raceway; the adjusted ampacity is:","opts":["40 A","36 A","28 A","32 A"],"correct":2,"re":"For 7-9 conductors the factor is 70%, so 40 × 0.70 = 28 A. See NEC Table 310.15(C)(1)."},
  {"id":74,"sec":"Safety","block":1,"q":"What is the function of the limited approach boundary under NFPA 70E?","opts":["It is the distance from an exposed energized part within which a shock hazard exists","It is the maximum reach of a bucket truck","It marks the edge of the equipment grounding electrode system","It is the boundary for fire-sprinkler coverage"],"correct":0,"re":"The limited approach boundary is the distance from an exposed energized conductor or circuit part within which a shock hazard exists; unqualified persons must not cross it without a qualified escort."},
  {"id":75,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a typical motor control circuit using a control transformer, what voltage is most commonly supplied to the control circuit?","opts":["480 volts","240 volts","24 volts","120 volts"],"correct":3,"re":"Control transformers commonly step the line voltage down to 120 volts for the control circuit, providing safer and standardized voltage for pilot devices and coils."},
  {"id":76,"sec":"Finish Wiring & Trim","block":1,"q":"A dwelling unit must have at least how many receptacle outlets installed for each bathroom, located adjacent to each basin?","opts":["None are required","At least two per bathroom","One only if the room exceeds 50 sq ft","At least one within 36 in. of the outside edge of each basin"],"correct":3,"re":"NEC 210.52(D) requires at least one receptacle outlet installed within 36 in. of the outside edge of each bathroom basin (lavatory)."},
  {"id":77,"sec":"Planning & Estimation","block":1,"q":"A motor has an input of 5000 W and an output of 4000 W; what is its efficiency?","opts":["125 percent","80 percent","20 percent","90 percent"],"correct":1,"re":"Efficiency = output/input = 4000/5000 = 0.80 = 80 percent."},
  {"id":78,"sec":"Rough Wiring","block":1,"q":"In a normally balanced 3-wire, single-phase, 120/240-volt circuit, the neutral conductor is:","opts":["Always counted as a current-carrying conductor","Counted only if the load is over 50 amps","Not counted as a current-carrying conductor","Counted as two conductors"],"correct":2,"re":"The neutral of a balanced single-phase 3-wire circuit carries only unbalanced current and is not counted as current-carrying. See NEC 310.15(E)."},
  {"id":79,"sec":"Safety","block":1,"q":"Before energizing newly installed equipment after maintenance under Cal/OSHA T8 Section 3314, what must be verified?","opts":["That the warranty paperwork is filed","That the paint on the enclosure has dried","That all employees are clear, tools removed, guards reinstalled, and each worker has removed their own lock before re-energizing","That the utility bill has been paid"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires that before re-energizing, the work area is inspected to ensure nonessential items are removed, components are intact, employees are clear, and each authorized employee removes their own lockout device."},
  {"id":80,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What does a reversing magnetic starter use to change the direction of a three-phase motor?","opts":["A single contactor with a reversing coil","Two contactors (forward and reverse) that interchange two of the line leads","A variable resistor in the rotor circuit","A capacitor bank switched into the line"],"correct":1,"re":"A reversing starter uses two mechanically and electrically interlocked contactors; the reverse contactor is wired to swap two of the three line leads, reversing rotation."},
  {"id":81,"sec":"Rough Wiring","block":1,"q":"When is the neutral conductor of a 4-wire, 3-phase wye circuit required to be counted as a current-carrying conductor?","opts":["Never","Only when it carries unbalanced current of a linear load","When the major portion of the load consists of nonlinear loads","Only on 480Y/277-volt systems"],"correct":2,"re":"Per NEC 310.15(E), the neutral is counted when the major portion of the load is nonlinear (harmonic) because it then carries significant current."},
  {"id":82,"sec":"Planning & Estimation","block":1,"q":"A motor delivers 3 HP at the shaft with an efficiency of 75 percent; what is the electrical input power?","opts":["2984 W","1678 W","2238 W","1119 W"],"correct":0,"re":"Output = 3 x 746 = 2238 W; input = output/eff = 2238/0.75 = 2984 W."},
  {"id":83,"sec":"Safety","block":1,"q":"An arc-flash hazard analysis primarily determines which two key items for a piece of equipment?","opts":["The conductor insulation color and conduit size","The breaker manufacturer and catalog number","The ambient temperature and humidity","The incident energy (or PPE category) and the arc-flash boundary"],"correct":3,"re":"An arc-flash risk assessment establishes the incident energy (or assigns a PPE category) and the arc-flash boundary so the correct arc-rated PPE can be selected and the protection distance known."},
  {"id":84,"sec":"Rough Wiring","block":1,"q":"In a 3-wire circuit taken from two phases and the neutral of a 3-phase, 4-wire wye system, the neutral is:","opts":["Not counted as current-carrying","Counted as a current-carrying conductor","Counted as half a conductor","Allowed to be smaller than the phases"],"correct":1,"re":"Per NEC 310.15(E), the neutral of such a 3-wire wye circuit carries approximately the same current as the phase conductors and is counted as current-carrying."},
  {"id":85,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Why are the forward and reverse contactors in a reversing starter mechanically and electrically interlocked?","opts":["To prevent both contactors from closing at the same time, which would cause a line-to-line short","To increase the motor torque","To reduce the control voltage","To allow simultaneous two-direction operation"],"correct":0,"re":"Interlocking ensures only one direction contactor can be energized at a time; closing both would connect two phases together through the swapped leads, creating a phase-to-phase short circuit."},
  {"id":86,"sec":"Finish Wiring & Trim","block":1,"q":"A dwelling unit foyer that is not part of a hallway and has an area greater than 60 sq ft requires receptacle outlets on any wall space how wide or wider?","opts":["3 ft","2 ft","1 ft","4 ft"],"correct":0,"re":"NEC 210.52(I) requires receptacle outlets in foyers larger than 60 sq ft for each wall space 3 ft (900 mm) or more in width that is unbroken by doorways and similar openings."},
  {"id":87,"sec":"Planning & Estimation","block":1,"q":"A single-phase motor draws 10 A at 240 V and delivers 1800 W of real power; what is its power factor?","opts":["0.90","1.33","0.50","0.75"],"correct":3,"re":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0.75."},
  {"id":88,"sec":"Rough Wiring","block":1,"q":"An equipment grounding conductor (EGC) run in the same raceway as the circuit conductors is counted as how many current-carrying conductors?","opts":["One","Two","Zero","Depends on its size"],"correct":2,"re":"Grounding and bonding conductors are not counted as current-carrying conductors for adjustment purposes. See NEC 310.15(E)."},
  {"id":89,"sec":"Safety","block":1,"q":"Which device is appropriate for verifying the absence of voltage during the test-before-touch step?","opts":["A non-contact pen-type detector used by itself as the sole means","A continuity ohmmeter set to the resistance scale","A clamp ammeter reading load current","An adequately rated contact voltage tester confirmed working before and after the test"],"correct":3,"re":"NFPA 70E requires an adequately rated voltage detector or tester to verify absence of voltage, and the device must be tested for proper operation immediately before and after the absence-of-voltage test."},
  {"id":90,"sec":"Planning & Estimation","block":1,"q":"What is the real power of a single-phase load drawing 20 A at 120 V with a power factor of 0.85?","opts":["2400 W","102 W","2823 W","2040 W"],"correct":3,"re":"Real power P = V x I x PF = 120 x 20 x 0.85 = 2040 W."},
  {"id":91,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"How does a single-phase induction motor differ from a three-phase induction motor regarding starting?","opts":["A single-phase motor requires an auxiliary starting method (such as a start winding), while a three-phase motor is self-starting","A single-phase motor is inherently self-starting with no auxiliary means","A three-phase motor cannot start under load","Both require a capacitor to start"],"correct":0,"re":"A three-phase motor produces a rotating magnetic field and is self-starting; a single-phase motor's pulsating field is not, so it needs a start winding (and often a capacitor) to develop starting torque."},
  {"id":92,"sec":"Rough Wiring","block":1,"q":"What is the minimum conductor size generally permitted for conductors installed in parallel?","opts":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"correct":1,"re":"NEC 310.10(G) (parallel conductors) permits paralleling only for sizes 1/0 AWG and larger, with limited exceptions."},
  {"id":93,"sec":"Safety","block":1,"q":"Under Cal/OSHA T8 Section 3314, what must be done with stored energy (such as charged capacitors or spring tension) during lockout?","opts":["It may be ignored if the main disconnect is locked open","It should be increased to test the equipment","It must be relieved, disconnected, restrained, or otherwise rendered safe before work begins","It must be measured but left in place"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires that stored or residual energy be dissipated or restrained so that it cannot cause injury; locking the disconnect alone does not address stored capacitive or mechanical energy."},
  {"id":94,"sec":"Planning & Estimation","block":1,"q":"A single-phase circuit carries 25 A over a one-way length where the total conductor resistance for the run is 0.4 ohms; what is the voltage drop?","opts":["10 V","62.5 V","0.016 V","100 V"],"correct":0,"re":"Voltage drop Vd = I x R = 25 x 0.4 = 10 V."},
  {"id":95,"sec":"Finish Wiring & Trim","block":1,"q":"Which dwelling location requires that 125-volt, 15- and 20-amp receptacles be GFCI-protected?","opts":["A bedroom closet","A bathroom","An attic crawl space with no equipment","A formal dining room"],"correct":1,"re":"NEC 210.8(A) lists bathrooms among the dwelling locations where 125-volt, 15- and 20-amp receptacles must have ground-fault circuit-interrupter protection."},
  {"id":96,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a capacitor-start single-phase motor, what is the purpose of the start capacitor?","opts":["To create a phase shift in the start winding so the motor develops starting torque","To improve the running power factor continuously","To limit the locked-rotor current to the run winding","To convert single-phase power to three-phase"],"correct":0,"re":"The start capacitor shifts the current in the start winding out of phase with the run winding, producing a rotating field that gives high starting torque."},
  {"id":97,"sec":"Rough Wiring","block":1,"q":"When conductors are installed in parallel, the paralleled conductors of each phase must be:","opts":["Different sizes to balance load","The same length, material, and size","Of different insulation types","Connected with different terminations"],"correct":1,"re":"Per NEC 310.10(G), paralleled conductors of each phase must be identical in length, material, size, and insulation and terminated the same way."},
  {"id":98,"sec":"Planning & Estimation","block":1,"q":"A 120 V branch circuit has a measured voltage drop of 6 V; what is the percent voltage drop?","opts":["20 percent","0.5 percent","2 percent","5 percent"],"correct":3,"re":"Percent drop = Vd/Vsource x 100 = 6/120 x 100 = 5 percent."},
  {"id":99,"sec":"Safety","block":1,"q":"When may an unqualified person cross the limited approach boundary toward an exposed energized part?","opts":["Never, under any circumstances whatsoever","Any time, as long as they wear safety glasses","Only during daylight hours","Only when continuously escorted or advised by a qualified person and properly protected"],"correct":3,"re":"NFPA 70E allows an unqualified person to cross the limited approach boundary only when continuously escorted by a qualified person who advises them of the hazards and ensures protection; they still may not perform the qualified work."},
  {"id":100,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a capacitor-start, induction-run motor, what device disconnects the start winding once the motor reaches about 75% of full speed?","opts":["A thermal overload relay","A centrifugal switch","A magnetic contactor","A control transformer"],"correct":1,"re":"A centrifugal switch (or equivalent relay) opens to remove the start winding and start capacitor from the circuit once the motor approaches running speed."},
  {"id":101,"sec":"Rough Wiring","block":2,"q":"Two 250 kcmil copper conductors per phase are run in parallel; electrically they behave as:","opts":["One 250 kcmil conductor","A conductor with half the ampacity","A single conductor of roughly doubled ampacity","Two separate branch circuits"],"correct":2,"re":"Parallel conductors share the load and are treated as a single conductor of combined (approximately doubled) ampacity. See NEC 310.10(G)."},
  {"id":102,"sec":"Planning & Estimation","block":2,"q":"On a 240 V feeder, the conductors have a total resistance of 0.15 ohms and carry 40 A; what is the percent voltage drop?","opts":["2.5 percent","6 V","0.6 percent","25 percent"],"correct":0,"re":"Vd = 40 x 0.15 = 6 V; percent = 6/240 x 100 = 2.5 percent."},
  {"id":103,"sec":"Finish Wiring & Trim","block":2,"q":"Dwelling unit receptacles installed to serve the kitchen countertop surfaces must be provided with what protection?","opts":["AFCI only","Surge protection only","GFCI protection","No special protection"],"correct":2,"re":"NEC 210.8(A) requires GFCI protection for receptacles serving dwelling kitchen countertop surfaces."},
  {"id":104,"sec":"Rough Wiring","block":2,"q":"What is the minimum size copper branch-circuit conductor generally permitted for a 15-ampere general-purpose branch circuit?","opts":["12 AWG","16 AWG","14 AWG","10 AWG"],"correct":2,"re":"14 AWG copper is the smallest standard branch-circuit conductor (15 A); 12 AWG is required for 20 A circuits. See NEC 210.19 and Table 310.16."},
  {"id":105,"sec":"Safety","block":2,"q":"What information must an energized electrical work permit typically include under NFPA 70E?","opts":["The job-site lunch schedule and parking assignments","The retail price of replacement parts","The names of all past employees who serviced the equipment","A description of the work, justification for energized work, the shock and arc-flash risk assessment results, and required PPE"],"correct":3,"re":"NFPA 70E specifies the energized work permit include the circuit/equipment description, justification for working energized, results of the shock and arc-flash risk assessments, required PPE, and management approval signatures."},
  {"id":106,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A capacitor-start single-phase motor hums but will not start and does not turn; which fault is the most likely cause?","opts":["The run winding is open","The start capacitor or start winding circuit is open (e.g., failed capacitor or centrifugal switch)","The supply voltage is too high","The motor bearings are over-greased"],"correct":1,"re":"Humming without starting typically indicates the run winding is energized but the start circuit (capacitor, start winding, or centrifugal switch) is open, so no starting torque is produced."},
  {"id":107,"sec":"Planning & Estimation","block":2,"q":"Using the single-phase voltage-drop formula Vd = 2 x K x I x L / CM, with K = 12.9, I = 20 A, L = 100 ft, and CM = 10380, what is the approximate voltage drop?","opts":["2.48 V","4.97 V","9.94 V","0.50 V"],"correct":1,"re":"Vd = (2 x 12.9 x 20 x 100)/10380 = 51600/10380 = 4.97 V."},
  {"id":108,"sec":"Rough Wiring","block":2,"q":"What is the smallest copper conductor size permitted for a 20-ampere branch circuit?","opts":["16 AWG","12 AWG","14 AWG","10 AWG"],"correct":1,"re":"A 20-ampere branch circuit requires a minimum 12 AWG copper conductor per NEC 240.4(D) and Table 310.16."},
  {"id":109,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"What is the primary function of a variable frequency drive (VFD) connected to an AC induction motor?","opts":["To control motor speed by varying the frequency (and voltage) supplied to the motor","To convert AC to DC for the motor","To provide overload protection only","To correct power factor on the utility side"],"correct":0,"re":"A VFD adjusts the output frequency, and proportionally the voltage, to the motor; since synchronous speed is proportional to frequency, this controls the motor speed."},
  {"id":110,"sec":"Safety","block":2,"q":"Why does NFPA 70E emphasize de-energizing equipment rather than relying solely on PPE?","opts":["PPE is more expensive than de-energizing","Eliminating the hazard by de-energizing is more effective than PPE, which only mitigates the consequences if an incident occurs","PPE cannot be cleaned after use","De-energizing is required only for cosmetic reasons"],"correct":1,"re":"NFPA 70E follows the hierarchy of risk controls, where elimination (de-energizing) is the most effective control and PPE is the last line of defense that only reduces the severity of injury if an arc or shock occurs."},
  {"id":111,"sec":"Planning & Estimation","block":2,"q":"A 240 V single-phase resistive load consumes 4800 W; what is its resistance?","opts":["12 ohms","20 ohms","0.05 ohms","50 ohms"],"correct":0,"re":"From P = V squared / R, R = V squared / P = 57600 / 4800 = 12 ohms."},
  {"id":112,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), what is the maximum overcurrent protection generally permitted for 14 AWG copper conductors?","opts":["10 A","20 A","15 A","25 A"],"correct":2,"re":"NEC 240.4(D) limits 14 AWG copper to a maximum 15-ampere overcurrent device regardless of its higher tabulated ampacity."},
  {"id":113,"sec":"Finish Wiring & Trim","block":2,"q":"Which of the following dwelling receptacle locations is generally required to be GFCI-protected?","opts":["A living room wall","Outdoors","A bedroom wall","A central hallway"],"correct":1,"re":"NEC 210.8(A) requires GFCI protection for outdoor 125-volt, 15- and 20-amp receptacles at dwellings."},
  {"id":114,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A VFD generally controls the speed of an AC induction motor by maintaining what relationship between voltage and frequency?","opts":["Zero voltage at low frequency","A constant current regardless of frequency","Maximum voltage at all frequencies","A constant volts-per-hertz (V/Hz) ratio"],"correct":3,"re":"To maintain constant magnetic flux and torque capability across the speed range, a VFD typically holds a constant volts-per-hertz ratio as it varies the output frequency."},
  {"id":115,"sec":"Safety","block":2,"q":"Which of the following best describes the restricted approach boundary compared with the limited approach boundary?","opts":["The restricted approach boundary is closer to the energized part and accounts for increased risk due to electrical arc-over plus inadvertent movement","The restricted approach boundary is farther from the energized part than the limited approach boundary","The two boundaries are always at the same distance","The restricted approach boundary applies only to mechanical hazards"],"correct":0,"re":"The restricted approach boundary is closer to the exposed energized part than the limited approach boundary; crossing it requires a qualified person with appropriate PPE because of the increased likelihood of arc-over combined with inadvertent movement."},
  {"id":116,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), the maximum overcurrent device for 12 AWG copper conductors is generally:","opts":["30 A","25 A","15 A","20 A"],"correct":3,"re":"NEC 240.4(D) limits 12 AWG copper to a maximum 20-ampere overcurrent device."},
  {"id":117,"sec":"Planning & Estimation","block":2,"q":"Three lamps rated 60 W each at 120 V are connected in parallel; what is the total current drawn?","opts":["0.5 A","180 A","4.5 A","1.5 A"],"correct":3,"re":"Total P = 3 x 60 = 180 W; I = P/V = 180/120 = 1.5 A."},
  {"id":118,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which is a common benefit of starting an AC motor with a VFD instead of across-the-line starting?","opts":["It increases the locked-rotor inrush current","It provides a soft start with reduced inrush current and mechanical stress","It eliminates the need for any overload protection","It requires the motor to be a synchronous type"],"correct":1,"re":"A VFD ramps frequency and voltage up gradually, providing a soft start that greatly reduces inrush current and mechanical/electrical stress compared to across-the-line starting."},
  {"id":119,"sec":"Safety","block":2,"q":"Under Cal/OSHA T8 Section 3314, when is a tagout device alone (without a lock) considered acceptable?","opts":["Whenever the worker prefers tags over locks","Anytime the equipment is over 480 volts","Only when the energy-isolating device is not capable of being locked out, and additional safety measures provide protection equivalent to lockout","Only on weekends"],"correct":2,"re":"Cal/OSHA T8 Section 3314 permits tagout alone only when the energy-isolating device cannot accept a lock, and then the employer must provide full employee protection equivalent to that of a lockout program."},
  {"id":120,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), the maximum overcurrent device for 10 AWG copper conductors is generally:","opts":["20 A","30 A","25 A","40 A"],"correct":1,"re":"NEC 240.4(D) limits 10 AWG copper to a maximum 30-ampere overcurrent device."},
  {"id":121,"sec":"Planning & Estimation","block":2,"q":"A water heater element has a resistance of 12.8 ohms on a 240 V circuit; what is its power consumption?","opts":["3072 W","18.75 W","4500 W","737280 W"],"correct":2,"re":"P = V squared / R = 57600 / 12.8 = 4500 W."},
  {"id":122,"sec":"Finish Wiring & Trim","block":2,"q":"A 125-volt receptacle in an unfinished basement of a dwelling generally requires what protection?","opts":["No protection","AFCI only","GFCI protection","Isolated ground only"],"correct":2,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in unfinished basements of dwellings."},
  {"id":123,"sec":"Rough Wiring","block":2,"q":"For aluminum conductors under NEC 240.4(D), what is the maximum overcurrent protection for 12 AWG aluminum?","opts":["20 A","10 A","15 A","25 A"],"correct":2,"re":"NEC 240.4(D) limits 12 AWG aluminum/copper-clad aluminum to a maximum 15-ampere overcurrent device."},
  {"id":124,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"When reading a motor nameplate, what does the listed RPM value represent?","opts":["The synchronous speed of the magnetic field","The speed only at no load","The maximum permissible overspeed","The approximate full-load operating speed of the motor shaft"],"correct":3,"re":"The nameplate RPM is the full-load (rated) speed of the motor, which for an induction motor is slightly less than synchronous speed due to slip."},
  {"id":125,"sec":"Safety","block":2,"q":"What is the correct sequence of the live-dead-live verification procedure?","opts":["Test a known live source, test the circuit to be worked on for absence of voltage, then re-test the known live source","Test the dead circuit, then touch it, then test a live source","Touch the circuit first, then test a live source twice","Test resistance, test continuity, then test current"],"correct":0,"re":"The live-dead-live method verifies the tester on a known energized source, then confirms the target circuit is dead, then re-verifies the tester on a known live source to prove it still functions, confirming a valid absence-of-voltage result."},
  {"id":126,"sec":"Planning & Estimation","block":2,"q":"In a series circuit, a 5 ohm and a 5 ohm resistor are followed by a 10 ohm resistor; what is the total resistance?","opts":["2 ohms","250 ohms","20 ohms","10 ohms"],"correct":2,"re":"Series adds: 5 + 5 + 10 = 20 ohms."},
  {"id":127,"sec":"Rough Wiring","block":2,"q":"Why does aluminum wiring typically require a larger conductor size than copper for the same ampacity?","opts":["Aluminum melts at a lower temperature","Aluminum cannot be insulated as well","Aluminum is heavier than copper","Aluminum has higher electrical resistivity"],"correct":3,"re":"Aluminum's higher resistivity means a larger cross-section is needed to carry the same current. See NEC Table 310.16 ampacity comparisons."},
  {"id":128,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"On a motor nameplate, what does the code letter (NEMA code letter) primarily indicate?","opts":["The locked-rotor kVA per horsepower (starting inrush characteristic)","The full-load efficiency","The maximum ambient temperature","The insulation class"],"correct":0,"re":"The NEMA code letter on the nameplate indicates the locked-rotor kVA per horsepower, which is used to determine the motor's starting (inrush) current."},
  {"id":129,"sec":"Planning & Estimation","block":2,"q":"What is the equivalent resistance of a 10 ohm, 20 ohm, and 30 ohm resistor connected in parallel?","opts":["60 ohms","0.183 ohms","20 ohms","5.45 ohms"],"correct":3,"re":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5.45 ohms."},
  {"id":130,"sec":"Safety","block":2,"q":"Which statement about arc-rated clothing under NFPA 70E is correct?","opts":["Ordinary cotton T-shirts provide adequate arc protection","Any flame-retardant clothing is automatically arc-rated","Arc-rated garments must have an arc rating equal to or greater than the estimated incident energy at the working distance","Arc-rated clothing only needs to cover the hands"],"correct":2,"re":"NFPA 70E requires that arc-rated PPE have an arc rating (in cal/cm2) at least equal to the available incident energy; non-rated clothing, even cotton, can ignite or melt and does not provide certified protection."},
  {"id":131,"sec":"Finish Wiring & Trim","block":2,"q":"A receptacle installed in a dwelling garage must be provided with which of the following?","opts":["A locking-type configuration","GFCI protection","AFCI protection only","An isolated neutral"],"correct":1,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in dwelling garages."},
  {"id":132,"sec":"Rough Wiring","block":2,"q":"Terminals listed and marked 'CU-AL' or 'AL-CU' are required when connecting:","opts":["Conductors larger than 1/0 only","Copper conductors only","Grounding conductors only","Aluminum or copper conductors at that termination"],"correct":3,"re":"Terminations marked CU-AL/AL-CU are tested and listed for use with aluminum and copper conductors. See NEC 110.14(A)."},
  {"id":133,"sec":"Planning & Estimation","block":2,"q":"A single-phase 240 V motor circuit delivers 7200 W of real power at a power factor of 0.80; what is the line current?","opts":["37.5 A","30 A","24 A","60 A"],"correct":0,"re":"I = P / (V x PF) = 7200 / (240 x 0.80) = 7200/192 = 37.5 A."},
  {"id":134,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"On a motor nameplate, what does a service factor (SF) of 1.15 indicate?","opts":["The motor must always run at 115% of rated voltage","The motor can be operated continuously at up to 115% of its rated horsepower without immediate damage","The starting current is 115% of full-load current","The insulation is rated for 115°C"],"correct":1,"re":"A service factor of 1.15 means the motor can carry a continuous overload of 15% above its rated horsepower under specified conditions; it also affects the allowable overload sizing per NEC 430.32."},
  {"id":135,"sec":"Safety","block":2,"q":"What is the role of an electrically safe work condition in eliminating electrical hazards?","opts":["It removes the shock and arc-flash hazards because the equipment is verified de-energized, isolated, and incapable of being re-energized","It reduces the hazard by half but still requires full PPE","It only protects against arc flash, not shock","It applies only to low-voltage control circuits"],"correct":0,"re":"Once an electrically safe work condition is established and verified, the source of electrical energy is removed, eliminating both shock and arc-flash hazards so the work is no longer considered energized work."},
  {"id":136,"sec":"Rough Wiring","block":2,"q":"When both ambient correction and bundling adjustment factors apply to a conductor, they must be:","opts":["Multiplied together with the base ampacity","Added together","Ignored if conductors are 90°C rated","Used separately, choosing the smaller"],"correct":0,"re":"Correction and adjustment factors are multiplied together and applied to the base ampacity. See NEC 310.15(B) and (C)."},
  {"id":137,"sec":"Planning & Estimation","block":2,"q":"A 3 kW load runs continuously for one full day; how much energy is consumed?","opts":["24 kWh","3 kWh","72 kWh","125 kWh"],"correct":2,"re":"Energy = 3 kW x 24 h = 72 kWh."},
  {"id":138,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A motor nameplate shows a dual voltage rating of 230/460 V; what generally happens to the full-load current when the motor is wired for the higher voltage (460 V)?","opts":["It approximately doubles","It stays exactly the same","It becomes zero","It is approximately one-half of the 230 V value"],"correct":3,"re":"For a given horsepower, current is inversely proportional to voltage, so wiring for 460 V draws about half the full-load current required at 230 V."},
  {"id":139,"sec":"Rough Wiring","block":2,"q":"A conductor rated USE-2 carries which temperature rating?","opts":["60°C","75°C","105°C","90°C"],"correct":3,"re":"The '-2' suffix indicates a 90°C wet and dry rating, so USE-2 is rated 90°C. See NEC Table 310.4(A)."},
  {"id":140,"sec":"Safety","block":2,"q":"Who is authorized to determine that energized work is justified and to approve an energized electrical work permit?","opts":["Any worker on the crew by majority vote","The first person to arrive on site","The equipment manufacturer's sales representative","Authorized management personnel, after the justification and risk assessment are documented"],"correct":3,"re":"NFPA 70E requires that the energized electrical work permit be reviewed and signed by authorized management, confirming the justification for energized work and the completed risk assessments."},
  {"id":141,"sec":"Finish Wiring & Trim","block":2,"q":"Receptacles installed within what distance of the outside edge of a sink generally require GFCI protection in a dwelling?","opts":["3 feet","4 feet","10 feet","6 feet"],"correct":3,"re":"NEC 210.8(A) requires GFCI protection for receptacles located within 6 ft of the outside edge of a sink."},
  {"id":142,"sec":"Planning & Estimation","block":2,"q":"A pump motor draws 4 kW input and produces 5 HP of useful output; what is its efficiency?","opts":["125 percent","80 percent","93 percent","75 percent"],"correct":2,"re":"Output = 5 x 746 = 3730 W; eff = 3730/4000 = 0.93 = 93 percent."},
  {"id":143,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A 5 hp single-phase 230 V motor and a 5 hp three-phase 230 V motor are compared; which statement about their full-load currents is generally true?","opts":["The single-phase motor draws less current than the three-phase motor","Both draw exactly the same current","The single-phase motor draws more current than the three-phase motor for the same horsepower and voltage","The three-phase motor cannot operate at 230 V"],"correct":2,"re":"For the same horsepower and voltage, a single-phase motor draws substantially more current than a three-phase motor because three-phase power is delivered more efficiently across three conductors."},
  {"id":144,"sec":"Rough Wiring","block":2,"q":"Plain USE conductor without an outer covering rated for the purpose is generally NOT permitted to be used as:","opts":["Underground feeder","Direct-burial service entrance","Underground service lateral","Interior branch-circuit wiring inside premises"],"correct":3,"re":"USE is intended for underground/service use; it is not listed for general interior wiring within buildings. See NEC Table 310.4(A) notes."},
  {"id":145,"sec":"Safety","block":2,"q":"During lockout/tagout, where must each authorized employee place their lockout device?","opts":["On the equipment nameplate","On the door of the electrical room only","On the energy-isolating device, so each worker controls the isolation with their own lock","In their personal toolbox for safekeeping"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires the lockout device be applied to the energy-isolating means; when multiple workers are involved, each applies their own lock (often via a group lockout hasp) so isolation cannot be removed until every worker is done."},
  {"id":146,"sec":"Planning & Estimation","block":2,"q":"A single-phase load of 8 kVA operates at a power factor of 0.90; what is the real power in kW?","opts":["7.2 kW","8.89 kW","8 kW","0.9 kW"],"correct":0,"re":"Real power = kVA x PF = 8 x 0.90 = 7.2 kW."},
  {"id":147,"sec":"Rough Wiring","block":2,"q":"A dual-rated conductor marked 'THHN/THWN-2' may be used in a wet location at what temperature rating?","opts":["60°C","90°C","75°C","It cannot be used in wet locations"],"correct":1,"re":"The THWN-2 rating provides 90°C in both wet and dry locations for the dual-rated conductor. See NEC Table 310.4(A)."},
  {"id":148,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A three-phase motor running on a 480 V system suddenly draws high current, runs hot, and hums loudly; which condition should be checked first?","opts":["Excessive control-circuit voltage","An open phase (single-phasing) on the supply","A reversed grounding conductor","Too large a branch-circuit conductor"],"correct":1,"re":"Loss of one phase (single-phasing) causes a three-phase motor to overheat and draw high current on the remaining phases; checking for an open phase or blown fuse is the first step."},
  {"id":149,"sec":"Finish Wiring & Trim","block":2,"q":"A dwelling laundry area receptacle that serves the laundry equipment generally requires what protection?","opts":["GFCI protection","Tamper-resistant only","AFCI only","No protection"],"correct":0,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in dwelling laundry areas."},
  {"id":150,"sec":"Safety","block":2,"q":"Which factor increases the available incident energy at a given piece of equipment during an arc flash?","opts":["A shorter fault clearing time of the upstream protective device","A longer arc duration before the protective device clears the fault","A larger working distance from the arc source","A lower available short-circuit current"],"correct":1,"re":"Incident energy increases with longer arc duration; the longer the upstream protective device takes to clear the fault, the more thermal energy is delivered, which is why fast-clearing protection lowers the arc-flash hazard."},
  {"id":151,"sec":"Planning & Estimation","block":2,"q":"If a 277 V circuit has a 3 percent maximum allowable voltage drop, what is the maximum permitted drop in volts?","opts":["0.83 V","8.31 V","83.1 V","9.23 V"],"correct":1,"re":"Max drop = 0.03 x 277 = 8.31 V."},
  {"id":152,"sec":"Rough Wiring","block":2,"q":"Ten current-carrying conductors are installed in a single raceway; which Table 310.15(C)(1) adjustment factor applies?","opts":["50%","70%","80%","45%"],"correct":0,"re":"For 10 to 20 current-carrying conductors the adjustment factor is 50%. See NEC Table 310.15(C)(1)."},
  {"id":153,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"If a magnetic motor starter's coil will not energize when the start button is pressed, which is a logical first item to check in the control circuit?","opts":["The motor bearings","The direction of motor rotation","The horsepower rating on the nameplate","Continuity of the control circuit, including the stop button, overload contacts, and control fuse"],"correct":3,"re":"A coil that will not pick up points to an open control circuit; check the stop button (NC), overload (NC) contacts, control fuse, and coil continuity before suspecting mechanical issues."},
  {"id":154,"sec":"Rough Wiring","block":2,"q":"Which statement about counting current-carrying conductors for derating is correct?","opts":["The grounded neutral is always counted","Equipment grounding conductors are counted","Only ungrounded (hot) conductors and qualifying neutrals are counted","All conductors in the raceway are counted"],"correct":2,"re":"Only ungrounded conductors plus neutrals that actually carry current count; EGCs and non-current-carrying neutrals are excluded. See NEC 310.15(E)."},
  {"id":155,"sec":"Safety","block":2,"q":"What must a qualified person do before crossing the arc-flash boundary to perform a task?","opts":["Wait until the incident energy drops on its own","Remove all metal jewelry and proceed in street clothes","Wear arc-rated PPE rated equal to or greater than the incident energy at the working distance","Notify the local fire department in writing"],"correct":2,"re":"NFPA 70E requires that anyone crossing the arc-flash boundary wear arc-rated PPE with an arc rating at least equal to the estimated incident energy at the working distance to prevent a second-degree burn."},
  {"id":156,"sec":"Planning & Estimation","block":2,"q":"A conductor run drops 7.2 V on a 120 V circuit supplying a load; what is the voltage delivered at the load?","opts":["112.8 V","127.2 V","6 V","120 V"],"correct":0,"re":"Load voltage = source minus drop = 120 - 7.2 = 112.8 V."},
  {"id":157,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A continuous-duty motor's branch-circuit conductors are sized at 125% of full-load current; the overload device for the same motor (SF 1.15) is sized at 125% of nameplate FLA. Why can these two percentages reference different current values?","opts":["Conductors use the NEC table FLC, while the overload device uses the actual nameplate full-load amperes","Both must always use the exact same current value","The overload device uses locked-rotor current","Conductors use nameplate amperes and overloads use table values"],"correct":0,"re":"Per NEC 430.6(A), conductor and short-circuit device sizing use the table FLC values, while overload protection per 430.32 is based on the motor's actual nameplate full-load current."},
  {"id":158,"sec":"Finish Wiring & Trim","block":2,"q":"When a single GFCI receptacle is wired to protect downstream receptacles, the protected outlets must be connected to which set of terminals on the GFCI device?","opts":["The LINE terminals","The grounding terminal only","The LOAD terminals","Either set works the same"],"correct":2,"re":"Downstream (protected) receptacles must connect to the LOAD terminals of the GFCI; the incoming supply connects to the LINE terminals."},
  {"id":159,"sec":"Rough Wiring","block":2,"q":"For a continuous load, branch-circuit conductors must have an allowable ampacity of not less than what percentage of the continuous load?","opts":["100%","125%","150%","115%"],"correct":1,"re":"Per NEC 210.19(A) and 215.2, conductors supplying continuous loads must be sized at not less than 125% of the continuous load."},
  {"id":160,"sec":"Planning & Estimation","block":2,"q":"A current of 0.25 A flows through a 480 ohm resistor; how much power is dissipated?","opts":["30 W","120 W","7680 W","1920 W"],"correct":0,"re":"P = I squared x R = 0.0625 x 480 = 30 W."},
  {"id":161,"sec":"Safety","block":2,"q":"Under Cal/OSHA T8 Section 3314, how often must lockout/tagout procedures be inspected or reviewed?","opts":["Only once when the employee is first hired","Every ten years","Periodically, at least annually, to ensure the procedures and employee performance remain effective","Never, once the written program is created"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires a periodic inspection, at least annually, of the energy-control procedures to correct deficiencies and verify that authorized employees follow them correctly."},
  {"id":162,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A single-phase 240 V continuous-duty motor has a table full-load current of 20 amps; what minimum branch-circuit conductor ampacity is required by NEC 430.22?","opts":["20 amps","25 amps","23 amps","30 amps"],"correct":1,"re":"NEC 430.22 requires 125% of the FLC for a single motor: 20 A x 1.25 = 25 A minimum conductor ampacity."},
  {"id":163,"sec":"Rough Wiring","block":2,"q":"Six current-carrying conductors are in one conduit and the ambient is 40°C; both the 0.91 ambient correction and the 80% adjustment apply to a 90°C base ampacity of 40 A, giving approximately:","opts":["40 A","36 A","32 A","29 A"],"correct":3,"re":"40 A × 0.91 × 0.80 ≈ 29 A; correction and adjustment factors are multiplied per NEC 310.15(B) and (C)."},
  {"id":164,"sec":"Planning & Estimation","block":2,"q":"Two resistors in series carry the same 2 A; if one is 15 ohms and the other 25 ohms, what is the total voltage across the pair?","opts":["20 V","8 V","40 V","80 V"],"correct":3,"re":"Total R = 15 + 25 = 40 ohms; V = I x R = 2 x 40 = 80 V."},
  {"id":165,"sec":"Safety","block":2,"q":"What distinguishes a qualified person from an unqualified person when it comes to shock approach boundaries?","opts":["Unqualified persons may freely cross any boundary if they wear gloves","Only a qualified person may cross the restricted approach boundary toward exposed energized parts using appropriate PPE and a plan","Both may cross all boundaries equally","Only the unqualified person may cross the restricted approach boundary"],"correct":1,"re":"NFPA 70E permits only a qualified person, using appropriate shock PPE and a documented approach plan, to cross the restricted approach boundary; unqualified persons are kept outside the limited approach boundary except under qualified escort."},
  {"id":166,"sec":"Rough Wiring","block":2,"q":"Which conductor material is lighter in weight and lower in cost, making it common for large service-entrance and feeder runs despite needing upsizing?","opts":["Silver-coated copper","Copper","Tinned copper","Aluminum"],"correct":3,"re":"Aluminum is lighter and cheaper than copper, which is why it is widely used for larger feeders and services even though it must be upsized for equal ampacity. See NEC Table 310.16."},
  {"id":167,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"If the initial overload protection sized at 125% of nameplate FLA trips during the motor's normal starting cycle, what does NEC 430.32 permit as a remedy?","opts":["Removing the overload protection entirely","Replacing the motor with a larger horsepower unit","Reducing the branch-circuit conductor size","Increasing the overload trip setting up to a higher permitted maximum (such as 140% of FLA)"],"correct":3,"re":"NEC 430.32(C) allows the overload size to be increased to a higher maximum (e.g., up to 140% for SF 1.15+ motors) when the initial value is not sufficient to allow the motor to start."},
  {"id":168,"sec":"Finish Wiring & Trim","block":2,"q":"A GFCI device is designed to open the circuit when it detects a current imbalance of approximately what value between the hot and neutral conductors?","opts":["0.5 ampere","20 milliamperes","4 to 6 milliamperes","5 amperes"],"correct":2,"re":"A Class A GFCI is designed to trip when the difference between the hot and grounded conductor currents reaches approximately 4 to 6 milliamperes, protecting against shock."},
  {"id":169,"sec":"Planning & Estimation","block":2,"q":"A 7.5 HP single-phase motor at 90 percent efficiency operates on 240 V; what is the approximate input power?","opts":["6217 W","5036 W","5595 W","4500 W"],"correct":0,"re":"Output = 7.5 x 746 = 5595 W; input = 5595/0.90 = 6217 W."},
  {"id":170,"sec":"Safety","block":2,"q":"After an electrical incident or whenever a circuit's status is uncertain, what is the safest assumption a worker should make?","opts":["Assume the circuit is de-energized to save time on testing","Assume the breaker tripped and cleared the fault","Treat all conductors and parts as energized until verified de-energized by an electrically safe work condition","Assume another worker already locked it out"],"correct":2,"re":"Cal/OSHA and NFPA 70E require conductors and circuit parts to be treated as energized until an electrically safe work condition is established and verified, because unverified assumptions about de-energization cause many electrical injuries."},
  {"id":171,"sec":"Rough Wiring","block":2,"q":"Four current-carrying conductors with a 90°C base ampacity of 55 A each are bundled in a raceway; what is the adjusted ampacity?","opts":["55 A","49.5 A","44 A","38.5 A"],"correct":2,"re":"For 4-6 conductors the adjustment factor is 80%, so 55 × 0.80 = 44 A. See NEC Table 310.15(C)(1)."},
  {"id":172,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A single-phase transformer has a primary voltage of 480 V and a secondary voltage of 120 V, so what is its turns ratio?","opts":["1:4","1:2","2:1","4:1"],"correct":3,"re":"Turns ratio equals primary voltage divided by secondary voltage, so 480 V divided by 120 V equals a 4:1 ratio."},
  {"id":173,"sec":"Planning & Estimation","block":2,"q":"A 120 V circuit feeds a load 150 ft away; if the two-way voltage drop is 3.6 V, what percent of the source voltage is lost?","opts":["0.3 percent","1 percent","6 percent","3 percent"],"correct":3,"re":"Percent drop = 3.6/120 x 100 = 3 percent."},
  {"id":174,"sec":"Rough Wiring","block":2,"q":"When installing electrical metallic tubing (EMT) on a wall, what is the maximum distance the raceway must be securely fastened from each outlet box, junction box, or other conduit termination?","opts":["18 inches","10 feet","3 feet","5 feet"],"correct":2,"re":"Per NEC 358.30, EMT must be securely fastened within 3 ft of each outlet box, junction box, cabinet, or fitting."},
  {"id":175,"sec":"Safety","block":2,"q":"At what approximate level of 60 Hz alternating current passing through the human body does a person typically lose the ability to release a conductor due to muscular contraction?","opts":["About 1 mA","About 500 mA","About 100 mA","About 10 to 16 mA"],"correct":3,"re":"The let-go threshold for most adults is roughly 10 to 16 mA; above this the muscles contract and the victim cannot release the energized conductor."},
  {"id":176,"sec":"Planning & Estimation","block":2,"q":"In a balanced three-phase wye-connected system, what is the relationship between the line voltage and the phase voltage?","opts":["Line voltage equals phase voltage","Line voltage equals phase voltage times 3","Line voltage equals phase voltage divided by 1.732","Line voltage equals phase voltage times 1.732"],"correct":3,"re":"In a wye configuration, line voltage = phase voltage × √3 (1.732), while line current equals phase current."},
  {"id":177,"sec":"Finish Wiring & Trim","block":2,"q":"Which device is designed to detect dangerous arcing conditions in branch-circuit wiring and is required for dwelling unit bedrooms?","opts":["GFCI","Surge protective device","Isolated ground receptacle","AFCI"],"correct":3,"re":"NEC 210.12 requires arc-fault circuit-interrupter (AFCI) protection for branch circuits supplying outlets in dwelling bedrooms, which detect arcing faults."},
  {"id":178,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which test instrument measures the insulation resistance of a conductor by applying a high DC voltage?","opts":["Clamp-on ammeter","Phase-rotation meter","Megohmmeter (megger)","Non-contact voltage tester"],"correct":2,"re":"A megohmmeter, or megger, applies a high DC test voltage (such as 500 V or 1000 V) to measure insulation resistance in megohms."},
  {"id":179,"sec":"Rough Wiring","block":2,"q":"What is the maximum total degrees of bends permitted in a run of conduit between pull points such as boxes or conduit bodies?","opts":["180 degrees","540 degrees","270 degrees","360 degrees"],"correct":3,"re":"NEC limits the total bends between pull points to a maximum of 360 degrees (the equivalent of four quarter bends) for raceways such as EMT, RMC, IMC, and PVC."},
  {"id":180,"sec":"Safety","block":2,"q":"Approximately what level of current through the body is generally considered the threshold of perception, where a person can just barely feel a tingle?","opts":["About 1 mA","About 50 mA","About 200 mA","About 1,000 mA"],"correct":0,"re":"The threshold of perception for most people is around 1 mA, producing a faint tingling sensation."},
  {"id":181,"sec":"Planning & Estimation","block":2,"q":"What is the total apparent power of a three-phase load operating at 480 V line-to-line drawing 50 A per line?","opts":["72,000 VA","24,000 VA","41,569 VA","13,856 VA"],"correct":2,"re":"Three-phase apparent power S = √3 × VL × IL = 1.732 × 480 × 50 = 41,569 VA."},
  {"id":182,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which instrument allows you to read the current in a conductor without breaking the circuit or disconnecting any wires?","opts":["Megohmmeter","Clamp-on ammeter","Insulation tester","Continuity tester"],"correct":1,"re":"A clamp-on ammeter measures current by sensing the magnetic field around a conductor, so the circuit does not need to be opened."},
  {"id":183,"sec":"Rough Wiring","block":2,"q":"Nonmetallic-sheathed cable (Type NM) run on the surface of framing members must be secured at intervals not exceeding which distance?","opts":["4 1/2 feet","3 feet","6 feet","10 feet"],"correct":0,"re":"Per NEC 334.30, Type NM cable must be secured at intervals not exceeding 4 1/2 ft."},
  {"id":184,"sec":"Safety","block":2,"q":"Currents in the range of roughly 100 to 200 mA through the chest are especially dangerous primarily because they can cause which life-threatening condition?","opts":["Minor skin burns only","Muscle cramps that resolve quickly","Temporary loss of hearing","Ventricular fibrillation of the heart"],"correct":3,"re":"Currents of about 100 to 200 mA across the chest can throw the heart into ventricular fibrillation, which is frequently fatal without immediate intervention."},
  {"id":185,"sec":"Planning & Estimation","block":2,"q":"A 240 V three-phase motor delivers 30 kW of real power at a power factor of 0.85; approximately what line current does it draw?","opts":["72 A","85 A","104 A","60 A"],"correct":1,"re":"IL = P / (√3 × VL × PF) = 30,000 / (1.732 × 240 × 0.85) = 84.9 A ≈ 85 A."},
  {"id":186,"sec":"Rough Wiring","block":2,"q":"Type NM cable must be secured within what maximum distance of each outlet box, junction box, or cabinet where the cable enters?","opts":["12 inches","24 inches","18 inches","8 inches"],"correct":0,"re":"Per NEC 334.30, NM cable must be secured within 12 in. of every outlet box, junction box, cabinet, or fitting."},
  {"id":187,"sec":"Finish Wiring & Trim","block":2,"q":"AFCI protection is generally required for branch circuits supplying outlets in which of the following dwelling areas?","opts":["Bathrooms","Outdoor patios","Detached unheated garages","Bedrooms and living rooms"],"correct":3,"re":"NEC 210.12(A) requires AFCI protection for branch circuits supplying outlets in dwelling living areas such as bedrooms, living rooms, family rooms, and similar rooms."},
  {"id":188,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"An ideal step-down transformer with a 10:1 turns ratio carries 5 A in its primary winding, so what is the approximate secondary current?","opts":["0.5 A","50 A","5 A","15 A"],"correct":1,"re":"In an ideal transformer the current ratio is the inverse of the turns ratio, so a 10:1 step-down draws 5 A primary and delivers about 50 A secondary."},
  {"id":189,"sec":"Rough Wiring","block":2,"q":"When more than two conductors are installed in a conduit or tubing, the maximum allowable conductor fill is what percentage of the raceway cross-sectional area?","opts":["31 percent","40 percent","53 percent","60 percent"],"correct":1,"re":"Per NEC Chapter 9, Table 1, where over 2 conductors are installed in a raceway, the maximum fill is 40 percent of the cross-sectional area."},
  {"id":190,"sec":"Planning & Estimation","block":2,"q":"In a balanced three-phase delta-connected system, what is the relationship between line current and phase (winding) current?","opts":["Line current equals phase current","Line current equals phase current divided by 1.732","Line current equals phase current times 3","Line current equals phase current times 1.732"],"correct":3,"re":"In a delta configuration, line current = phase current × √3 (1.732), while line voltage equals phase voltage."},
  {"id":191,"sec":"Safety","block":2,"q":"A Class A ground-fault circuit interrupter (GFCI) is designed to trip when the difference in current between the hot and neutral conductors reaches approximately what value?","opts":["500 mA","30 mA","100 mA","5 mA"],"correct":3,"re":"A Class A GFCI trips at a ground-fault current of about 5 mA (nominally 4 to 6 mA), the level chosen to protect people from lethal shock."},
  {"id":192,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"In a balanced three-phase wye (star) connected transformer, how does the line voltage compare to the phase (winding) voltage?","opts":["Line voltage is the square root of 3 times the phase voltage","Line voltage is half the phase voltage","Line voltage is 3 times the phase voltage","Line voltage equals phase voltage"],"correct":0,"re":"In a wye connection the line voltage equals the phase voltage multiplied by the square root of 3 (about 1.732), while line and phase currents are equal."},
  {"id":193,"sec":"Rough Wiring","block":2,"q":"A single insulated conductor installed alone in a conduit is permitted to fill a maximum of what percentage of the raceway's cross-sectional area?","opts":["31 percent","40 percent","53 percent","60 percent"],"correct":2,"re":"Per NEC Chapter 9, Table 1, one conductor in a raceway is permitted a maximum fill of 53 percent."},
  {"id":194,"sec":"Planning & Estimation","block":2,"q":"A three-phase wye system has a phase voltage of 277 V; what is the approximate line-to-line voltage?","opts":["277 V","480 V","831 V","160 V"],"correct":1,"re":"Wye line voltage = phase voltage × √3 = 277 × 1.732 = 480 V."},
  {"id":195,"sec":"Finish Wiring & Trim","block":2,"q":"What is the primary hazard that AFCI protection is intended to reduce?","opts":["Fires caused by arcing faults","Electric shock to a person","Voltage drop on long runs","Overloaded neutral conductors"],"correct":0,"re":"AFCI devices are intended to de-energize a circuit when an arcing fault is detected, reducing the risk of fires ignited by arcing in wiring, per NEC 210.12."},
  {"id":196,"sec":"Safety","block":2,"q":"Under OSHA 1926.404, which of the following best describes the GFCI requirement for 125-volt, single-phase, 15- and 20-ampere receptacle outlets used by employees on a construction site?","opts":["GFCI protection is required only when it rains","GFCI protection is never required outdoors","GFCI protection is required for all such receptacles not part of the permanent wiring","GFCI protection applies only to 240-volt circuits"],"correct":2,"re":"OSHA requires GFCI protection for all 125-V, single-phase, 15-, 20-, and 30-A receptacle outlets that are not part of the permanent wiring and are used by employees."},
  {"id":197,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"What is the primary purpose of using a phase-rotation meter before connecting a three-phase motor?","opts":["To measure insulation resistance","To verify the phase sequence so the motor turns in the correct direction","To measure the ground-electrode resistance","To check conductor continuity"],"correct":1,"re":"A phase-rotation meter confirms the A-B-C phase sequence so a three-phase motor rotates in the intended direction when energized."},
  {"id":198,"sec":"Rough Wiring","block":2,"q":"When exactly two conductors are installed in a conduit, the maximum conductor fill permitted is what percentage of the raceway cross-sectional area?","opts":["60 percent","40 percent","53 percent","31 percent"],"correct":3,"re":"Per NEC Chapter 9, Table 1, two conductors in a raceway are limited to a maximum fill of 31 percent."},
  {"id":199,"sec":"Planning & Estimation","block":2,"q":"What is the real power consumed by a three-phase load at 208 V drawing 40 A per line with a power factor of 0.9?","opts":["14,400 W","8,320 W","16,000 W","12,973 W"],"correct":3,"re":"P = √3 × VL × IL × PF = 1.732 × 208 × 40 × 0.9 = 12,973 W."},
  {"id":200,"sec":"Safety","block":2,"q":"On a construction site, OSHA 1926.404 allows an employer to use an assured equipment grounding conductor program as an alternative to which protective measure?","opts":["Lockout/tagout procedures","Hard-hat requirements","Personal fall arrest systems","GFCI protection on temporary receptacles"],"correct":3,"re":"The assured equipment grounding conductor program is the permitted alternative to GFCI protection for receptacles not part of the permanent wiring."},
  {"id":201,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When using a digital multimeter set to the resistance (ohms) function, on what condition must the circuit be tested?","opts":["Energized at full load","Under reduced voltage","Energized at no load","De-energized with no voltage present"],"correct":3,"re":"Resistance and continuity measurements must be made on a de-energized circuit, because applied voltage will give false readings and can damage the meter."},
  {"id":202,"sec":"Rough Wiring","block":3,"q":"Where a cable or raceway-type wiring method passes through a wood stud and the edge of the bored hole is less than 1 1/4 inches from the nearest edge of the stud, what protection is required?","opts":["A steel plate or bushing at least 1/16 inch thick","No additional protection is required","Wrapping the cable with electrical tape","Doubling the staple spacing"],"correct":0,"re":"Per NEC 300.4(A), where the hole is less than 1 1/4 in. from the nearest edge, a steel plate or bushing at least 1/16 in. thick must protect the wiring from screws and nails."},
  {"id":203,"sec":"Planning & Estimation","block":3,"q":"A 480 V line-to-line three-phase system is connected in wye; what is the voltage from any one line to the neutral?","opts":["480 V","277 V","240 V","831 V"],"correct":1,"re":"Line-to-neutral (phase) voltage = line voltage ÷ √3 = 480 ÷ 1.732 = 277 V."},
  {"id":204,"sec":"Finish Wiring & Trim","block":3,"q":"In a new dwelling unit, 125-volt, 15- and 20-amp receptacles installed in areas specified by the Code must be of what type to resist insertion of foreign objects by children?","opts":["Weather-resistant","Tamper-resistant","Isolated ground","Hospital grade"],"correct":1,"re":"NEC 406.12 requires listed tamper-resistant (TR) receptacles for 125-volt, 15- and 20-amp receptacles in dwelling units, which have internal shutters preventing object insertion."},
  {"id":205,"sec":"Rough Wiring","block":3,"q":"Which raceway type is most subject to corrosion and is NOT suitable for severe corrosive environments unless provided with supplementary corrosion protection?","opts":["Electrical metallic tubing (EMT)","PVC Schedule 40","Rigid metal conduit (RMC)","Intermediate metal conduit (IMC)"],"correct":0,"re":"Per NEC 358.10, EMT and its fittings are subject to corrosion and require supplementary protection in severe corrosive conditions, unlike PVC."},
  {"id":206,"sec":"Safety","block":3,"q":"Under an assured equipment grounding conductor program, each cord set and receptacle that is not part of the permanent wiring must, at a minimum, be tested for continuity and proper terminal connection of the equipment grounding conductor at what frequency?","opts":["Before first use, after repair, and at least every 3 months","Once per year","Only when a tool fails","Once every 5 years"],"correct":0,"re":"OSHA requires testing before first use, after any repairs, after suspected damage, and at intervals not exceeding 3 months (6 months for fixed receptacles not exposed to damage)."},
  {"id":207,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A buck-boost transformer is most commonly used to do which of the following?","opts":["Make a small voltage correction, such as raising 208 V to about 230 V","Convert single-phase to three-phase power","Provide complete isolation between two large systems","Step a primary down to a separately derived 120/240 V service"],"correct":0,"re":"A buck-boost transformer is connected as an autotransformer to make a small percentage adjustment in voltage, such as bucking down or boosting up a supply by roughly 5 to 20 percent."},
  {"id":208,"sec":"Planning & Estimation","block":3,"q":"A single-phase transformer has a primary voltage of 480 V and a secondary voltage of 120 V; what is the turns ratio?","opts":["4:1","1:4","2:1","6:1"],"correct":0,"re":"Turns ratio = primary voltage ÷ secondary voltage = 480 ÷ 120 = 4, expressed as 4:1."},
  {"id":209,"sec":"Rough Wiring","block":3,"q":"Rigid PVC conduit (Schedule 40) installed on a wall must be securely fastened within what distance of each box, cabinet, or other conduit termination?","opts":["18 inches","8 feet","3 feet","5 feet"],"correct":2,"re":"Per NEC 352.30, rigid PVC conduit must be securely fastened within 3 ft of each box, cabinet, conduit body, or other termination."},
  {"id":210,"sec":"Safety","block":3,"q":"In an assured equipment grounding conductor program, which of the following tests must be performed on each cord set and receptacle?","opts":["A measurement of the conductor's color fade","A test that all equipment grounding conductors are electrically continuous","A test of the cord's tensile strength only","A check of the manufacturer's warranty date"],"correct":1,"re":"Each cord set and receptacle must be tested to verify that the equipment grounding conductor is electrically continuous and correctly connected to its proper terminal."},
  {"id":211,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Before energizing a newly installed panelboard, which commissioning check should be performed on all terminations?","opts":["Apply full load current and watch for heat","Energize and read voltage at each breaker","Verify each lug is tightened to the manufacturer's specified torque","Spray contact cleaner on each lug"],"correct":2,"re":"A key pre-energization commissioning step is to torque all terminations to the manufacturer's specified values using a calibrated torque tool to prevent loose, high-resistance connections."},
  {"id":212,"sec":"Planning & Estimation","block":3,"q":"A transformer with a 10:1 turns ratio has 240 V applied to its primary; what is the secondary voltage (ignoring losses)?","opts":["24 V","120 V","10 V","2,400 V"],"correct":0,"re":"Secondary voltage = primary voltage ÷ turns ratio = 240 ÷ 10 = 24 V."},
  {"id":213,"sec":"Rough Wiring","block":3,"q":"An expansion fitting is required to be installed on a rigid PVC conduit run to compensate for which condition?","opts":["Electromagnetic interference","Voltage drop over long distances","Excessive conductor fill","Thermal expansion and contraction of the conduit"],"correct":3,"re":"Per NEC 352.44, expansion fittings shall be provided to compensate for thermal expansion and contraction where the length change is expected to be 1/4 in. or greater."},
  {"id":214,"sec":"Finish Wiring & Trim","block":3,"q":"What feature distinguishes a tamper-resistant receptacle from a standard receptacle?","opts":["Internal spring-loaded shutters over the slots","A higher amperage rating","A weatherproof gasket","An integral surge suppressor"],"correct":0,"re":"Tamper-resistant receptacles (NEC 406.12) use internal spring-loaded shutters that open only when both blades of a plug are inserted simultaneously, blocking single-object insertion."},
  {"id":215,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which method is used to measure the resistance of a driven ground rod to earth?","opts":["Continuity test with a multimeter on the ohms range","Three-point fall-of-potential ground-resistance test","Insulation-resistance test with a megger","Clamp-on current measurement of the service conductor"],"correct":1,"re":"Ground-electrode resistance is commonly measured with a three-point fall-of-potential test using auxiliary probes, or with a clamp-on ground-resistance tester."},
  {"id":216,"sec":"Safety","block":3,"q":"A portable electric drill marked with the symbol of a square within a square is described as double-insulated; what does this designation indicate about the tool?","opts":["It relies on two independent layers of insulation and does not require an equipment grounding conductor","It must always be connected to a GFCI to be safe","It is rated for use only in wet locations","It contains two internal batteries"],"correct":0,"re":"The square-within-a-square symbol identifies a double-insulated tool, which provides two independent insulation systems and therefore does not need a grounding conductor."},
  {"id":217,"sec":"Planning & Estimation","block":3,"q":"What is the full-load current on the secondary of a 25 kVA single-phase transformer with a 240 V secondary?","opts":["60 A","104 A","208 A","10 A"],"correct":1,"re":"Single-phase secondary current = kVA × 1000 ÷ V = 25,000 ÷ 240 = 104 A."},
  {"id":218,"sec":"Rough Wiring","block":3,"q":"In a standard outlet box, what volume in cubic inches must be allowed for each 14 AWG conductor when performing a box-fill calculation?","opts":["1.5 cubic inches","2.5 cubic inches","2.25 cubic inches","2.0 cubic inches"],"correct":3,"re":"Per NEC Table 314.16(B), each 14 AWG conductor requires a volume allowance of 2.0 cubic inches."},
  {"id":219,"sec":"Planning & Estimation","block":3,"q":"A three-phase transformer is rated 75 kVA with a 208 V secondary; what is the approximate secondary full-load line current?","opts":["208 A","625 A","360 A","104 A"],"correct":0,"re":"Three-phase current = kVA × 1000 ÷ (√3 × V) = 75,000 ÷ (1.732 × 208) = 75,000 ÷ 360.3 = 208 A."},
  {"id":220,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A non-contact voltage tester is best suited for which task?","opts":["Measuring exact line-to-line voltage","Measuring the turns ratio of a transformer","Measuring current draw on a feeder","Quickly indicating the presence of voltage without touching a conductor"],"correct":3,"re":"A non-contact voltage tester senses the electric field and indicates whether voltage is present, but it does not display an exact value."},
  {"id":221,"sec":"Safety","block":3,"q":"A grounded portable power tool with a three-prong plug is plugged into a two-wire receptacle using an adapter whose grounding pigtail is left unconnected; what is the principal hazard?","opts":["The tool's metal housing has no path to ground if an internal fault occurs","The tool will run in reverse","The tool will draw excessive current and trip the breaker","The tool will overheat the receptacle"],"correct":0,"re":"Without the grounding pigtail connected, a fault to the tool's metal frame leaves the housing energized with no low-resistance path to ground, exposing the user to shock."},
  {"id":222,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, what volume in cubic inches must be allowed for each 12 AWG conductor?","opts":["2.25 cubic inches","2.0 cubic inches","2.5 cubic inches","3.0 cubic inches"],"correct":0,"re":"Per NEC Table 314.16(B), each 12 AWG conductor requires a volume allowance of 2.25 cubic inches."},
  {"id":223,"sec":"Finish Wiring & Trim","block":3,"q":"A 15- or 20-amp, 125-volt receptacle installed outdoors in a damp or wet location must be listed as which type?","opts":["Tamper-resistant only","Self-grounding","Hospital grade","Weather-resistant (WR)"],"correct":3,"re":"NEC 406.9(A) and (B) require receptacles in damp or wet locations to be of the weather-resistant (WR) type, listed for those conditions."},
  {"id":224,"sec":"Planning & Estimation","block":3,"q":"If a step-down transformer has a secondary current of 100 A and a turns ratio of 5:1, what is the approximate primary current (ignoring losses)?","opts":["500 A","20 A","100 A","25 A"],"correct":1,"re":"Primary current = secondary current ÷ turns ratio = 100 ÷ 5 = 20 A (current is inversely proportional to the voltage ratio)."},
  {"id":225,"sec":"Rough Wiring","block":3,"q":"When calculating box fill, how are all of the equipment grounding conductors that enter a box counted, regardless of how many there are?","opts":["Each grounding conductor counts as one separate conductor","They are not counted at all","All grounding conductors together count as a single conductor volume allowance based on the largest one","They count double because of the bonding requirement"],"correct":2,"re":"Per NEC 314.16(B)(5), all equipment grounding conductors count collectively as a single conductor volume allowance, based on the largest grounding conductor present."},
  {"id":226,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"For a 25 kVA single-phase transformer with a 240 V secondary, what is the approximate full-load secondary current?","opts":["About 60 A","About 208 A","About 104 A","About 25 A"],"correct":2,"re":"Secondary current equals VA divided by voltage, so 25,000 VA divided by 240 V is about 104 A."},
  {"id":227,"sec":"Safety","block":3,"q":"When working on or near exposed energized electrical parts, which type of portable ladder is recommended to reduce the risk of electric shock?","opts":["Aluminum ladder","Steel ladder","Magnesium ladder","Fiberglass (nonconductive) ladder"],"correct":3,"re":"A fiberglass ladder has nonconductive side rails, making it the proper choice near energized parts where a metal ladder could become an electrical path."},
  {"id":228,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, how many conductor volume allowances are counted for a single device such as a receptacle or switch mounted on a yoke or strap?","opts":["One based on the largest conductor connected to the device","Two based on the largest conductor connected to the device","Three regardless of conductor size","Zero because devices are not counted"],"correct":1,"re":"Per NEC 314.16(B)(4), each yoke or strap containing one or more devices is counted as two conductor volume allowances based on the largest conductor connected to it."},
  {"id":229,"sec":"Planning & Estimation","block":3,"q":"What size transformer, in kVA, is minimally required to supply a single-phase 240 V load drawing 80 A?","opts":["10 kVA","19.2 kVA","33.3 kVA","15 kVA"],"correct":1,"re":"kVA = V × A ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 kVA."},
  {"id":230,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When commissioning a separately derived system from a dry-type transformer, where must the system grounding (bonding) connection be made?","opts":["At the load end of every branch circuit","Only at the utility transformer","At the source, bonding the secondary neutral to a grounding electrode","At each individual receptacle"],"correct":2,"re":"A separately derived system must have its grounded (neutral) conductor bonded to a grounding electrode at or near the source, typically with a system bonding jumper at the transformer."},
  {"id":231,"sec":"Safety","block":3,"q":"An electrician must change a light fixture located near energized overhead conductors and chooses a ladder; which of the following is the least appropriate choice?","opts":["A dry wood ladder","An aluminum extension ladder","A fiberglass ladder","A nonconductive step ladder"],"correct":1,"re":"An aluminum ladder is conductive and the least appropriate near energized conductors; fiberglass or other nonconductive ladders should be used instead."},
  {"id":232,"sec":"Finish Wiring & Trim","block":3,"q":"A 15- or 20-amp, 125-volt receptacle in a wet location must have an enclosure that is weatherproof under what condition?","opts":["Only when the cover is closed","Whether or not an attachment plug cap is inserted","Only when no plug is inserted","Only during dry weather"],"correct":1,"re":"NEC 406.9(B)(1) requires receptacles in wet locations to have a weatherproof enclosure (an in-use/while-in-use cover) that remains weatherproof whether or not an attachment plug is inserted."},
  {"id":233,"sec":"Rough Wiring","block":3,"q":"Which of the following wiring methods is flexible and commonly used for the final connection to a motor to reduce the transmission of vibration and noise?","opts":["Rigid metal conduit (RMC)","PVC Schedule 80","Electrical metallic tubing (EMT)","Flexible metal conduit (FMC)"],"correct":3,"re":"Per NEC Article 348, flexible metal conduit (FMC) is used where flexibility is needed, such as motor connections, to dampen vibration."},
  {"id":234,"sec":"Planning & Estimation","block":3,"q":"A single-phase transformer steps 7,200 V down to 240 V; if the primary draws 5 A, what is the approximate secondary current (ignoring losses)?","opts":["0.17 A","30 A","150 A","300 A"],"correct":2,"re":"Secondary current = primary current × (primary V ÷ secondary V) = 5 × (7200 ÷ 240) = 5 × 30 = 150 A."},
  {"id":235,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"If a megohmmeter reads a very low or near-zero insulation resistance between a conductor and ground, what does this most likely indicate?","opts":["Excellent insulation","A correctly grounded system that needs no further action","An open circuit","Insulation breakdown or a fault to ground"],"correct":3,"re":"A very low insulation-resistance reading indicates deteriorated or damaged insulation or a fault path to ground, which must be corrected before energizing."},
  {"id":236,"sec":"Safety","block":3,"q":"If you discover a coworker who is still in contact with an energized conductor and cannot let go, what is the correct first action?","opts":["Immediately grab the victim and pull them away with your bare hands","Pour water on the victim to cool the burns","De-energize the circuit or use a nonconductive object to separate the victim from the source","Begin chest compressions while the victim is still energized"],"correct":2,"re":"You must first remove the source of electricity, either by shutting off the power or using a nonconductive means to free the victim, before touching them or starting CPR."},
  {"id":237,"sec":"Rough Wiring","block":3,"q":"Which flexible raceway is specifically listed and suitable for use in wet locations and damp environments where liquids may be present?","opts":["Flexible metal conduit (FMC)","Liquidtight flexible metal conduit (LFMC)","Electrical nonmetallic tubing (ENT) without fittings","Standard EMT without weatherproof fittings"],"correct":1,"re":"Per NEC Article 350, liquidtight flexible metal conduit (LFMC) has a liquidtight outer jacket making it suitable for wet locations; standard FMC is not."},
  {"id":238,"sec":"Planning & Estimation","block":3,"q":"Per NEC Table 430.248, the full-load current of a single-phase 240 V, 5 HP motor is approximately:","opts":["28 A","15 A","56 A","8 A"],"correct":0,"re":"NEC Table 430.248 lists a 5 HP single-phase 230 V (used for 240 V) motor at 28 A full-load current."},
  {"id":239,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"In a delta-connected three-phase transformer winding, how does the line current relate to the phase (winding) current?","opts":["Line current equals 3 times the phase current","Line current equals phase current","Line current is one-third of the phase current","Line current equals the square root of 3 times the phase current"],"correct":3,"re":"In a delta connection the line current equals the phase current multiplied by the square root of 3, while line and phase voltages are equal."},
  {"id":240,"sec":"Rough Wiring","block":3,"q":"Electrical nonmetallic tubing (ENT) is generally NOT permitted to be installed in which of the following locations?","opts":["Exposed where subject to physical damage","Concealed within walls, floors, and ceilings","Above a suspended ceiling in a one-story building","Encased in a concrete slab"],"correct":0,"re":"Per NEC 362.12, ENT is not permitted where subject to physical damage because its nonmetallic material offers limited mechanical protection."},
  {"id":241,"sec":"Finish Wiring & Trim","block":3,"q":"The cover that keeps an outdoor receptacle weatherproof even while a cord is plugged in is commonly called what?","opts":["A flush cover plate","A blank cover","A faceplate gasket","An in-use (while-in-use) cover"],"correct":3,"re":"An in-use or while-in-use cover (NEC 406.9(B)(1)) is a bubble-type enclosure that maintains weatherproof integrity while a plug and cord remain inserted in a wet location."},
  {"id":242,"sec":"Safety","block":3,"q":"After a shock victim has been safely separated from the electrical source and is found to have no pulse and is not breathing, what is the appropriate next step?","opts":["Wait for the burns to heal before acting","Begin CPR and have someone call emergency services","Give the victim water to drink","Move the victim to a vehicle and drive to the hospital without further aid"],"correct":1,"re":"Once the victim is clear of the source and shows no pulse or breathing, begin CPR immediately and ensure emergency medical services are summoned."},
  {"id":243,"sec":"Planning & Estimation","block":3,"q":"When sizing branch-circuit conductors for a single continuously-running motor, which current value does the NEC require you to use?","opts":["The motor's actual measured current","The locked-rotor current","The full-load current value from the NEC motor tables","The nameplate current divided by 1.25"],"correct":2,"re":"NEC 430.6(A) requires using the full-load current values from Tables 430.247 through 430.250 rather than the nameplate current for conductor sizing."},
  {"id":244,"sec":"Rough Wiring","block":3,"q":"Type AC (armored) cable must be secured at intervals not exceeding what distance when installed along framing members?","opts":["3 feet","8 feet","4 1/2 feet","6 feet"],"correct":2,"re":"Per NEC 320.30, Type AC cable must be secured at intervals not exceeding 4 1/2 ft."},
  {"id":245,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which instrument function is the correct choice to verify that a fuse is good without removing it from a de-energized holder?","opts":["AC voltage","Clamp-on current","Continuity (ohms)","Insulation resistance"],"correct":2,"re":"On a de-energized circuit, the continuity (ohms) function shows a low resistance through a good fuse and an open (no continuity) through a blown fuse."},
  {"id":246,"sec":"Safety","block":3,"q":"Why is it dangerous to touch an electric-shock victim who is still in contact with the energized source before the power is removed?","opts":["The victim may be carrying a contagious disease","The victim's clothing may be flammable","The current can pass through the victim and into the rescuer, creating a second casualty","The rescuer might damage the electrical equipment"],"correct":2,"re":"If the source is still energized, current can flow through the victim into the rescuer, making the rescuer a second shock victim."},
  {"id":247,"sec":"Planning & Estimation","block":3,"q":"A 230 V single-phase motor is rated at 1 HP and operates at roughly 80% efficiency with unity power factor; approximately what current does it draw?","opts":["3.2 A","4.1 A","2.0 A","6.5 A"],"correct":1,"re":"Input watts = 746 ÷ 0.80 = 932.5 W; I = 932.5 ÷ 230 = 4.1 A (1 HP = 746 W)."},
  {"id":248,"sec":"Rough Wiring","block":3,"q":"Which cable type is specifically listed for direct burial in the earth without requiring a protective raceway?","opts":["Type NM cable","Type AC cable","Type MC cable not marked for direct burial","Type UF cable"],"correct":3,"re":"Per NEC Article 340, Type UF (underground feeder) cable is listed and suitable for direct burial in the earth."},
  {"id":249,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"What is the main reason a torque screwdriver or torque wrench is preferred over hand-tight tightening for electrical terminations?","opts":["It applies the manufacturer's specified torque to ensure a reliable, low-resistance connection","It increases the conductor ampacity","It eliminates the need for a wire stripper","It is faster than a regular tool"],"correct":0,"re":"A calibrated torque tool applies the exact manufacturer-specified value, preventing connections that are too loose (overheating) or too tight (damage), which is required for many listed terminations."},
  {"id":250,"sec":"Finish Wiring & Trim","block":3,"q":"An insulated grounded (neutral) conductor of 6 AWG or smaller must be identified by which color?","opts":["Green","Blue","Red","White or gray"],"correct":3,"re":"NEC 200.6(A) requires that grounded (neutral) conductors 6 AWG or smaller be identified by a continuous white or gray outer finish, or three continuous white/gray stripes."},
  {"id":251,"sec":"Planning & Estimation","block":3,"q":"How many watts are equal to one horsepower for electrical motor calculations?","opts":["550 W","1,000 W","746 W","1,200 W"],"correct":2,"re":"One horsepower equals 746 watts, the standard conversion used in motor load calculations."},
  {"id":252,"sec":"Safety","block":3,"q":"Under OSHA temporary wiring rules for construction, flexible cords and cables used for temporary power must be protected from damage; which condition would make a cord unacceptable for continued use?","opts":["The outer jacket is cut or split, exposing the inner conductors","The cord is rated for hard or extra-hard usage","The cord is colored orange","The cord is longer than 25 feet"],"correct":0,"re":"A cord with a damaged outer jacket that exposes the conductors must be removed from service; length or color alone does not make a cord unacceptable."},
  {"id":253,"sec":"Rough Wiring","block":3,"q":"Type NM (nonmetallic-sheathed) cable is permitted to be used in which of the following locations?","opts":["Wet locations such as direct burial","Embedded in poured concrete","Exposed to oils and other deteriorating agents","Dry locations of normally dry, non-corrosive interiors"],"correct":3,"re":"Per NEC 334.10 and 334.12, Type NM cable is permitted in normally dry locations and is not permitted in wet locations, embedded in concrete, or where exposed to corrosive conditions."},
  {"id":254,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A transformer enclosure and core must be connected to which conductor for safety?","opts":["The ungrounded (hot) conductor","The equipment grounding conductor","The secondary neutral only on the load side","No connection is required"],"correct":1,"re":"The non-current-carrying metal parts of a transformer, such as its enclosure and core, must be bonded to the equipment grounding conductor to provide a safe fault-clearing path."},
  {"id":255,"sec":"Planning & Estimation","block":3,"q":"Per NEC Table 430.250, a three-phase 460 V, 10 HP motor has a full-load current of approximately:","opts":["28 A","14 A","21 A","9 A"],"correct":1,"re":"NEC Table 430.250 lists a 10 HP, 460 V three-phase motor at 14 A full-load current."},
  {"id":256,"sec":"Rough Wiring","block":3,"q":"When fittings are installed on a conduit entering an enclosure in a wet location, which type of fitting must be used?","opts":["A standard indoor connector","A reducing washer","A raintight or wet-location-rated fitting","A set-screw fitting"],"correct":2,"re":"Per NEC 314.15 and 300.5, fittings and enclosures used in wet locations must be listed for wet locations to prevent moisture entry."},
  {"id":257,"sec":"Safety","block":3,"q":"For temporary wiring on a construction site, flexible cords are generally required to be of which type to withstand job-site conditions?","opts":["Light-duty lamp cord","Untwisted bare conductors","Single-conductor bell wire","Listed for hard usage or extra-hard usage"],"correct":3,"re":"Job-site temporary cords must be listed for hard or extra-hard usage so the jacket can resist the abuse found on construction sites."},
  {"id":258,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"During startup, an electrician uses a clamp-on ammeter on each phase of a three-phase motor feeder; what does a large imbalance between the phase currents most likely suggest?","opts":["The motor is operating normally","The clamp meter is reading insulation resistance","A possible winding fault, loose connection, or voltage imbalance","The phase rotation is reversed"],"correct":2,"re":"Significant current imbalance between phases often indicates a developing winding fault, a high-resistance (loose) connection, or a supply voltage imbalance that should be investigated."},
  {"id":259,"sec":"Finish Wiring & Trim","block":3,"q":"An equipment grounding conductor (EGC), when insulated, is identified by which of the following?","opts":["White or gray","Solid black","Green, or green with one or more yellow stripes","Solid red"],"correct":2,"re":"NEC 250.119 permits an insulated EGC to be green, or green with one or more yellow stripes; it may also be bare."},
  {"id":260,"sec":"Planning & Estimation","block":3,"q":"When sizing the branch-circuit conductors for a single continuous-duty motor, the conductor ampacity must be at least what percent of the motor full-load current?","opts":["100%","115%","125%","150%"],"correct":2,"re":"NEC 430.22 requires motor branch-circuit conductors to have an ampacity of at least 125% of the motor full-load current."},
  {"id":261,"sec":"Rough Wiring","block":3,"q":"Cables or raceways installed parallel to framing members must be set back from the nearest edge of the framing member by at least what distance to avoid the need for a protective plate?","opts":["3/4 inch","1 1/4 inches","1 inch","1 1/2 inches"],"correct":1,"re":"Per NEC 300.4(D), cables run parallel to framing members must be at least 1 1/4 in. from the nearest edge, or be protected by a steel plate."},
  {"id":262,"sec":"Safety","block":3,"q":"Which practice involving an extension cord on a job site is a recognized safety hazard?","opts":["Removing the grounding prong from the cord's plug to fit a two-slot receptacle","Using a cord listed for outdoor use","Using a cord with an intact molded plug","Coiling unused cord neatly out of walkways"],"correct":0,"re":"Cutting or removing the grounding prong defeats the equipment grounding path and is a serious hazard; the other practices are acceptable."},
  {"id":263,"sec":"Planning & Estimation","block":3,"q":"A demand factor is best described as:","opts":["The ratio of the maximum demand to the total connected load","The sum of all connected loads","The ratio of nameplate voltage to operating voltage","The product of voltage and current"],"correct":0,"re":"Per NEC Article 100, the demand factor is the ratio of the maximum demand of a system to the total connected load, allowing realistic sizing below 100% of connected load."},
  {"id":264,"sec":"Rough Wiring","block":3,"q":"Which raceway has the thickest, heaviest wall and provides the greatest physical protection for conductors?","opts":["Electrical nonmetallic tubing (ENT)","Electrical metallic tubing (EMT)","Rigid metal conduit (RMC)","Flexible metal conduit (FMC)"],"correct":2,"re":"Per NEC Article 344, rigid metal conduit (RMC) is the heaviest-wall steel raceway and offers the greatest physical protection compared to IMC and EMT."},
  {"id":265,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Before applying a high-voltage megohmmeter test to a circuit, what must be confirmed first?","opts":["The circuit is fully energized","The circuit is de-energized and isolated, and sensitive electronics are disconnected","A load is connected to the far end","The phase rotation is correct"],"correct":1,"re":"Insulation-resistance testing applies high DC voltage, so the circuit must be de-energized, isolated, and any sensitive electronic equipment disconnected to avoid damage and ensure safety."},
  {"id":266,"sec":"Safety","block":3,"q":"An extension cord used to supply a portable tool runs across a doorway where it could be pinched by the door; what does OSHA generally require regarding flexible cords?","opts":["Flexible cords must not be run through doorways, windows, or similar openings where they can be damaged","Cords may be run through doorways if the door is kept open with the cord","Cords through doorways are fine if taped to the floor","Only metal-jacketed cords may pass through doorways"],"correct":0,"re":"OSHA prohibits running flexible cords through doorways, windows, holes in walls, or similar openings where they are subject to damage."},
  {"id":267,"sec":"Rough Wiring","block":3,"q":"PVC Schedule 80 conduit is preferred over PVC Schedule 40 in which application?","opts":["Underground in non-traffic areas","Inside dry interior walls","Inside a finished attic with no access","Where exposed to physical damage"],"correct":3,"re":"Per NEC 352.10, PVC Schedule 80 has a thicker wall and is permitted where the conduit is exposed to physical damage, whereas Schedule 40 is not."},
  {"id":268,"sec":"Planning & Estimation","block":3,"q":"A panel has 60 kVA of connected load with an applicable demand factor of 70%; what is the calculated demand load?","opts":["60 kVA","86 kVA","18 kVA","42 kVA"],"correct":3,"re":"Demand load = connected load × demand factor = 60 × 0.70 = 42 kVA."},
  {"id":269,"sec":"Finish Wiring & Trim","block":3,"q":"An equipment grounding conductor may also be installed as which of the following?","opts":["A white insulated conductor","A gray insulated conductor","A bare conductor","A blue insulated conductor"],"correct":2,"re":"NEC 250.118 and 250.119 permit an equipment grounding conductor to be a bare conductor, in addition to the green/green-yellow insulated identification."},
  {"id":270,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Two 120 V buck-boost transformer windings are connected to boost a 208 V supply; what is the main advantage of using a buck-boost connection instead of an isolation transformer for this small correction?","opts":["It provides complete isolation from the source","It is smaller and less costly because it only handles the boosted portion of the load","It converts the supply to three-phase","It eliminates the need for overcurrent protection"],"correct":1,"re":"Because a buck-boost is wired as an autotransformer that only processes the small voltage difference, it is physically smaller and less expensive than a full isolation transformer of the same load."},
  {"id":271,"sec":"Safety","block":3,"q":"Why should flexible cords used as temporary wiring on a construction site not be used as a substitute for the fixed (permanent) wiring of a structure?","opts":["Flexible cords are more expensive than permanent wiring","Flexible cords are not intended for permanent installation and are more prone to damage and overheating in that role","Flexible cords carry too little current for any tool","Flexible cords are illegal to manufacture"],"correct":1,"re":"Flexible cords are not a substitute for fixed wiring because they are subject to mechanical damage, are not protected within the building structure, and can overheat when used permanently."},
  {"id":272,"sec":"Rough Wiring","block":3,"q":"A conductor or cable installed through a metal framing member must be protected by a bushing or grommet where required because the metal edge can cause what type of damage?","opts":["Voltage drop","Electromagnetic interference","Excessive heat buildup","Abrasion or cutting of the conductor insulation"],"correct":3,"re":"Per NEC 300.4(B), where cables pass through factory or field punched holes in metal framing, listed bushings or grommets protect the cable from abrasion against sharp metal edges."},
  {"id":273,"sec":"Planning & Estimation","block":3,"q":"Under the standard method of NEC Article 220, what is the general lighting load value assigned per square foot of a dwelling unit?","opts":["1 VA per square foot","2 VA per square foot","3 VA per square foot","5 VA per square foot"],"correct":2,"re":"NEC Table 220.12 assigns 3 VA per square foot for general lighting in dwelling units."},
  {"id":274,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"What does a continuity test of an equipment grounding conductor verify during commissioning?","opts":["That there is a complete, low-resistance metallic path back to the source","The exact resistance to earth in ohms","The insulation quality of the conductor","The phase sequence of the supply"],"correct":0,"re":"A continuity test on the equipment grounding conductor verifies an unbroken low-resistance path for fault current to return to the source and operate the overcurrent device."},
  {"id":275,"sec":"Rough Wiring","block":3,"q":"When Type NM cable is run through bored holes in wood studs or joists, additional securing along that portion of the run is considered satisfied because the holes provide what?","opts":["Grounding continuity","Support and protection at each penetration","Required derating","Expansion compensation"],"correct":1,"re":"Per NEC 334.30, NM cable installed through bored holes in framing members is considered supported and secured by the framing where intervals do not exceed code limits."},
  {"id":276,"sec":"Safety","block":3,"q":"Live parts of electrical equipment operating at 50 volts or more must generally be guarded against accidental contact; which of the following is an acceptable method of guarding?","opts":["Placing the equipment in a room or enclosure accessible only to qualified persons","Painting the live parts a bright color","Posting a warning sign with no physical barrier","Coating the parts with a thin layer of oil"],"correct":0,"re":"Guarding live parts by location in a controlled room, vault, or enclosure accessible only to qualified persons is an accepted method; a sign or paint alone is not sufficient."},
  {"id":277,"sec":"Planning & Estimation","block":3,"q":"What is the general lighting load for a dwelling with 2,000 square feet of habitable space using the standard calculation?","opts":["6,000 VA","4,000 VA","2,000 VA","10,000 VA"],"correct":0,"re":"General lighting = area × 3 VA/ft² = 2,000 × 3 = 6,000 VA."},
  {"id":278,"sec":"Finish Wiring & Trim","block":3,"q":"Which color is NOT permitted to be used to identify an ungrounded (hot) conductor?","opts":["White","Red","Black","Blue"],"correct":0,"re":"Ungrounded conductors may be any color other than white, gray, or green (which are reserved for grounded and grounding conductors); white is reserved for the grounded conductor per NEC 200.6/200.7."},
  {"id":279,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"An ideal transformer steps 240 V up to 480 V; if the load on the 480 V side draws 10 A, what is the approximate primary current (neglecting losses)?","opts":["20 A","10 A","5 A","40 A"],"correct":0,"re":"Power in equals power out for an ideal transformer, so primary current equals secondary VA divided by primary voltage: (480 V x 10 A) / 240 V equals 20 A."},
  {"id":280,"sec":"Rough Wiring","block":3,"q":"What is the maximum spacing for supports of rigid metal conduit (RMC) trade size 1/2 through 3/4 installed exposed in a straight horizontal run?","opts":["6 feet","16 feet","10 feet","12 feet"],"correct":2,"re":"Per NEC Table 344.30(B)(2), RMC of trade size 1/2 and 3/4 requires support spacing not exceeding 10 ft."},
  {"id":281,"sec":"Planning & Estimation","block":3,"q":"How many volt-amperes does the NEC require for each of the two minimum small-appliance branch circuits in a dwelling load calculation?","opts":["1,000 VA each","1,500 VA each","2,000 VA each","3,000 VA each"],"correct":1,"re":"NEC 220.52(A) requires each small-appliance branch circuit to be calculated at 1,500 VA."},
  {"id":282,"sec":"Safety","block":3,"q":"The primary purpose of guarding live parts in electrical equipment is to do which of the following?","opts":["Improve the appearance of the installation","Increase the voltage rating of the conductors","Reduce the cost of the equipment","Prevent accidental contact by persons and protect against electric shock"],"correct":3,"re":"Guarding live parts is intended to prevent inadvertent contact by people, thereby protecting against electric shock and burns."},
  {"id":283,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When troubleshooting with a multimeter, you read 0 volts across a closed switch that should be passing current to a working load; what does this reading indicate about the switch?","opts":["The switch is good, since a closed switch should have little or no voltage drop across it","The switch is open and faulty","The load is short-circuited","The supply voltage is too high"],"correct":0,"re":"A properly closed switch has nearly zero voltage drop across it, so reading 0 V across it while the load operates indicates the switch contacts are good."},
  {"id":284,"sec":"Rough Wiring","block":3,"q":"A junction box must have its volume marked or be of sufficient size so that the total box fill does not exceed which of the following?","opts":["Half the number of cable clamps","Exactly 75 percent of the box volume","Twice the smallest conductor area","The marked or calculated volume of the box"],"correct":3,"re":"Per NEC 314.16(A) and (B), the total calculated volume of all contents must not exceed the marked or calculated volume of the box."},
  {"id":285,"sec":"Planning & Estimation","block":3,"q":"In a dwelling unit standard load calculation, the laundry branch circuit is computed at what value?","opts":["1,000 VA","1,500 VA","2,000 VA","1,200 VA"],"correct":1,"re":"NEC 220.52(B) requires the laundry branch circuit to be calculated at 1,500 VA."},
  {"id":286,"sec":"Safety","block":3,"q":"A GFCI provides protection against which specific hazard?","opts":["Overcurrent from a short circuit between hot conductors","Line-to-ground fault current flowing through a person to ground","Overvoltage from a lightning strike","Voltage drop on a long feeder"],"correct":1,"re":"A GFCI senses small imbalances caused by current leaking to ground (such as through a person) and trips to prevent fatal shock; it is not primarily an overcurrent or surge device."},
  {"id":287,"sec":"Finish Wiring & Trim","block":3,"q":"When a white conductor in a cable is used as an ungrounded conductor in a switch loop, what must the electrician do at terminations?","opts":["Leave it white since it is in a cable","Connect it only to the neutral bar","Reidentify it with a color other than white, gray, or green","Cut and cap it"],"correct":2,"re":"NEC 200.7(C) permits a white conductor in a cable to serve as an ungrounded conductor only if it is permanently reidentified to indicate its use, by marking it with a color other than white, gray, or green."},
  {"id":288,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, conductors that originate outside the box and pass through without splice or termination are counted how?","opts":["Each is counted once based on its size","Each is counted as two conductors","They are not counted","Only the largest one is counted"],"correct":0,"re":"Per NEC 314.16(B)(1), each conductor that runs through the box without splice or termination is counted once as a single conductor volume allowance."},
  {"id":289,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which of the following is a correct safety practice when using a multimeter to measure voltage in a live panel?","opts":["Select a CAT rating and meter rated for the circuit, and inspect the leads before use","Set the meter to the ohms function first","Hold both probes in one hand for stability","Use a meter and leads rated below the system voltage"],"correct":0,"re":"Measuring live voltage safely requires a properly CAT-rated meter and leads suited to the circuit and inspecting the leads for damage before use."},
  {"id":290,"sec":"Planning & Estimation","block":3,"q":"Using the standard method, the combined general lighting, small-appliance, and laundry load of a dwelling totals 12,000 VA; what is the demand after applying NEC Table 220.42 (first 3,000 VA at 100%, remainder at 35%)?","opts":["12,000 VA","4,200 VA","6,150 VA","9,000 VA"],"correct":2,"re":"First 3,000 VA at 100% = 3,000; remaining 9,000 VA at 35% = 3,150; total = 6,150 VA per Table 220.42."},
  {"id":291,"sec":"Rough Wiring","block":3,"q":"When one or more internal cable clamps are present in a box, how many conductor volume allowances are added for all the clamps?","opts":["None, clamps are not counted","Two regardless of conductor size","One for each clamp present","A single volume allowance based on the largest conductor in the box"],"correct":3,"re":"Per NEC 314.16(B)(2), one or more internal cable clamps count collectively as a single conductor volume allowance based on the largest conductor entering the box."},
  {"id":292,"sec":"Safety","block":3,"q":"Does a standard GFCI protect a person against a shock received by contacting both the hot and neutral (line-to-line) conductors simultaneously?","opts":["Yes, it always prevents all shocks","Yes, but only on 240-volt circuits","No, because the current is balanced and no imbalance to ground is detected","No, because GFCIs only work on direct current"],"correct":2,"re":"If a person contacts both hot and neutral, the current returns through the neutral and remains balanced, so the GFCI sees no ground-fault imbalance and will not trip."},
  {"id":293,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A three-phase delta primary, wye secondary transformer is energized; on the wye secondary the phase voltage measures 277 V, so what is the expected line-to-line voltage?","opts":["About 480 V","About 831 V","About 160 V","277 V"],"correct":0,"re":"On a wye secondary the line-to-line voltage equals phase voltage times the square root of 3, so 277 V times 1.732 is about 480 V."},
  {"id":294,"sec":"Planning & Estimation","block":3,"q":"A dwelling has two small-appliance circuits and one laundry circuit; what total VA do these three circuits contribute before applying the demand factor?","opts":["3,000 VA","1,500 VA","6,000 VA","4,500 VA"],"correct":3,"re":"Two small-appliance circuits (2 × 1,500) + one laundry circuit (1,500) = 3,000 + 1,500 = 4,500 VA."},
  {"id":295,"sec":"Rough Wiring","block":3,"q":"Which raceway is a corrugated, pliable nonmetallic tubing, often colored, that is intended for concealed installation in residential and light commercial work?","opts":["Intermediate metal conduit (IMC)","Liquidtight flexible nonmetallic conduit (LFNC)","Rigid PVC conduit","Electrical nonmetallic tubing (ENT)"],"correct":3,"re":"Per NEC Article 362, electrical nonmetallic tubing (ENT) is a pliable corrugated raceway, often colored, used in concealed locations."},
  {"id":296,"sec":"Finish Wiring & Trim","block":3,"q":"Which conductor in a standard duplex receptacle must be connected to the terminal identified by the silver or light-colored screws?","opts":["The grounded (neutral) conductor","The ungrounded (hot) conductor","The equipment grounding conductor","The traveler conductor"],"correct":0,"re":"On a receptacle, the silver/light-colored screws are the grounded (neutral) terminals; the brass screws are the ungrounded terminals and the green screw is for the EGC, per NEC 200.10 and 250.126."},
  {"id":297,"sec":"Safety","block":3,"q":"After installing a GFCI receptacle on a job site, what should the electrician do to verify it is functioning correctly?","opts":["Measure the cord length","Leave it untested until an inspector arrives","Check the color of the faceplate","Press the TEST button and confirm the device trips, then press RESET"],"correct":3,"re":"Pressing the TEST button should trip the GFCI, confirming the protective mechanism works; RESET then restores power."},
  {"id":298,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"During a pre-energization inspection, what is the purpose of verifying that the main bonding jumper is installed at the service?","opts":["To connect the grounded conductor to the equipment grounding system so fault current can clear","To isolate the neutral from ground","To increase voltage to the loads","To balance the phase currents"],"correct":0,"re":"The main bonding jumper connects the grounded (neutral) conductor to the equipment grounding system at the service, establishing the path that lets fault current operate the overcurrent device."},
  {"id":299,"sec":"Planning & Estimation","block":3,"q":"Using NEC Table 220.55 Column C, what is the demand load for a single household electric range rated at 12 kW?","opts":["12 kW","6 kW","10 kW","8 kW"],"correct":3,"re":"NEC Table 220.55 Column C gives 8 kW for one range not over 12 kW."},
  {"id":300,"sec":"Rough Wiring","block":3,"q":"Flexible metal conduit (FMC) used as a fixture whip for connection to a luminaire is generally permitted to be unsupported for a length not exceeding which distance?","opts":["3 feet","6 feet","4 1/2 feet","8 feet"],"correct":1,"re":"Per NEC 348.30(A), FMC is permitted to be unsupported up to 6 ft from a luminaire terminal for tap connections (fixture whips)."},
  {"id":301,"sec":"Safety","block":4,"q":"A worker is using a corded portable power tool outdoors in a damp area; which combination provides the best protection against electric shock?","opts":["An ungrounded tool with no GFCI","A properly grounded or double-insulated tool supplied through a GFCI","A tool with the grounding prong removed","A tool plugged into a frayed extension cord"],"correct":1,"re":"The safest combination is a tool that is either properly grounded or double-insulated and fed through GFCI protection, especially in damp locations."},
  {"id":302,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"Which instrument is specifically designed to measure how many ohms of resistance exist between a grounding electrode and the surrounding earth?","opts":["Ground-resistance tester (earth ground tester)","Standard multimeter on the ohms range","Megohmmeter","Non-contact voltage tester"],"correct":0,"re":"A ground-resistance (earth ground) tester is designed to measure electrode-to-earth resistance, using fall-of-potential or clamp-on methods that a standard ohmmeter cannot perform accurately."},
  {"id":303,"sec":"Rough Wiring","block":4,"q":"Securing of NM cable is NOT required in which of the following situations?","opts":["Where the cable is fished between access points through concealed spaces of finished buildings and supporting is impracticable","Where the cable enters a surface-mounted box","Where the cable runs exposed across the face of a finished wall","Where the cable is run across the bottom of floor joists"],"correct":0,"re":"Per NEC 334.30(B), securing is not required where cable is fished between access points through concealed spaces of finished buildings and supporting is impracticable."},
  {"id":304,"sec":"Planning & Estimation","block":4,"q":"Per NEC 220.54, what minimum value must a single household electric clothes dryer be calculated at, even if its nameplate rating is lower?","opts":["3,000 VA","5,000 VA","4,500 VA","1,500 VA"],"correct":1,"re":"NEC 220.54 requires a household electric dryer to be calculated at 5,000 VA or the nameplate rating, whichever is larger."},
  {"id":305,"sec":"Finish Wiring & Trim","block":4,"q":"To control a single luminaire from two different locations, which switching arrangement is used?","opts":["Two single-pole switches","One 4-way switch","Two 3-way switches","Two double-pole switches"],"correct":2,"re":"Control of one load from two locations is accomplished with a pair of 3-way switches connected by traveler conductors."},
  {"id":306,"sec":"Rough Wiring","block":4,"q":"An outlet box mounted in a finished wall of noncombustible material such as drywall must be installed so that the front edge is set back no more than what distance from the finished surface?","opts":["Flush, with no setback permitted","Not more than 1/4 inch back from the surface","Not more than 1 inch back from the surface","Not more than 1 1/4 inches back from the surface"],"correct":1,"re":"Per NEC 314.20, in walls of noncombustible material the box may be set back not more than 1/4 in. from the finished surface."},
  {"id":307,"sec":"Safety","block":4,"q":"Electrical burns from contact with energized parts can be deceptively serious because the most severe tissue damage often occurs where?","opts":["Only on the surface of the skin","Only in the victim's clothing","Only in the hair and fingernails","Deep inside the body along the path the current takes between entry and exit points"],"correct":3,"re":"Current passing through the body generates heat deep within tissues, so internal damage along the current path is frequently far worse than the visible surface wounds."},
  {"id":308,"sec":"Planning & Estimation","block":4,"q":"What is the minimum service size, in amperes, required for a single one-family dwelling under NEC 230.79(C)?","opts":["100 A","60 A","125 A","150 A"],"correct":0,"re":"NEC 230.79(C) requires a minimum 100 A service disconnect rating for a one-family dwelling."},
  {"id":309,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the most reliable way to verify a circuit is de-energized before beginning work, sometimes called the live-dead-live test?","opts":["Test the meter on a known live source, test the circuit, then re-test the known live source","Use a non-contact tester one time","Look at the breaker handle position only","Assume it is dead if the lights are off"],"correct":0,"re":"The live-dead-live (test-before-touch) method confirms the tester works on a known live source, shows the circuit is dead, then re-confirms the tester still works, proving the absence of voltage."},
  {"id":310,"sec":"Rough Wiring","block":4,"q":"An outlet box installed in a combustible wall surface such as wood paneling must be installed so that the front edge is positioned how relative to the finished surface?","opts":["Flush with or projecting from the finished surface","Set back 1/4 inch","Set back 1/2 inch","Set back 1 inch"],"correct":0,"re":"Per NEC 314.20, in walls of combustible material the box must be flush with or project from the finished surface."},
  {"id":311,"sec":"Planning & Estimation","block":4,"q":"A 120/240 V single-phase dwelling has a calculated total demand load of 24,000 VA; what is the minimum service ampacity required?","opts":["200 A","150 A","125 A","100 A"],"correct":3,"re":"Service amperes = VA ÷ V = 24,000 ÷ 240 = 100 A."},
  {"id":312,"sec":"Safety","block":4,"q":"Which factor most directly determines the magnitude of current that will flow through a person who contacts an energized conductor at a fixed voltage?","opts":["The person's height","The color of the conductor insulation","The resistance of the body and contact points in the current path","The time of day"],"correct":2,"re":"By Ohm's law, for a given voltage the current equals voltage divided by resistance, so lower body and contact resistance (for example, wet skin) results in higher, more dangerous current."},
  {"id":313,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A clamp-on ammeter is placed around all three phase conductors of a balanced three-phase circuit at the same time; what should it ideally read?","opts":["The line-to-line voltage","The sum of all three phase currents","The current of one phase only","Approximately zero, because the balanced currents cancel"],"correct":3,"re":"When all conductors of a balanced set pass through the clamp together, their magnetic fields cancel, so the meter reads near zero; this principle is the basis of ground-fault detection."},
  {"id":314,"sec":"Finish Wiring & Trim","block":4,"q":"To control a single luminaire from three or more locations, what combination of switches is required?","opts":["Three 3-way switches","Three single-pole switches","Three 4-way switches","Two 3-way switches and one or more 4-way switches"],"correct":3,"re":"Three-or-more-location control uses two 3-way switches at the ends and one or more 4-way switches in between, wired through traveler conductors."},
  {"id":315,"sec":"Rough Wiring","block":4,"q":"Type MC (metal-clad) cable installed exposed and run on framing members must be secured at intervals not exceeding what distance?","opts":["3 feet","6 feet","4 feet","8 feet"],"correct":1,"re":"Per NEC 330.30, Type MC cable must be secured at intervals not exceeding 6 ft."},
  {"id":316,"sec":"Planning & Estimation","block":4,"q":"When calculating a feeder or service load for a dwelling, fixed appliances such as a water heater and dishwasher are classified under which NEC term?","opts":["Fastened-in-place appliance loads","Continuous loads","Motor loads","General lighting loads"],"correct":0,"re":"NEC 220.53 covers fastened-in-place (fixed) appliances, allowing a 75% demand factor when four or more are present on a dwelling feeder."},
  {"id":317,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When verifying transformer connections at startup, why is correct polarity (additive vs subtractive) important when paralleling or banking transformers?","opts":["Incorrect polarity can cause a short circuit or improper voltage when windings are interconnected","It only affects the color of the bushings","It determines the insulation class","It changes the kVA rating"],"correct":0,"re":"Transformer polarity must be verified so that interconnected or paralleled windings add correctly; reversed polarity can create a dead short or wrong output voltage."},
  {"id":318,"sec":"Safety","block":4,"q":"On a construction site, a 30-ampere, 125-volt single-phase receptacle that is not part of the permanent wiring and is used by employees must have what protection under OSHA 1926.404?","opts":["No special protection is required","Only a locking-type cover","Only a surge protector","GFCI protection or coverage under an assured equipment grounding conductor program"],"correct":3,"re":"OSHA extends the GFCI requirement to 15-, 20-, and 30-A single-phase 125-V receptacles not part of permanent wiring, with the assured grounding program as the alternative."},
  {"id":319,"sec":"Rough Wiring","block":4,"q":"Which statement best describes the permitted use of intermediate metal conduit (IMC)?","opts":["It is permitted only in dry indoor locations","It is permitted only underground","It may never be threaded","It may be used in all the same atmospheric conditions and occupancies as RMC"],"correct":3,"re":"Per NEC Article 342, IMC is a lighter-wall steel raceway permitted in all the same locations and conditions as rigid metal conduit (RMC)."},
  {"id":320,"sec":"Planning & Estimation","block":4,"q":"Per NEC 220.53, when four or more fastened-in-place appliances are on the same dwelling feeder, what demand factor may be applied to their total nameplate load?","opts":["50%","75%","65%","100%"],"correct":1,"re":"NEC 220.53 permits a 75% demand factor for four or more fastened-in-place appliances (excluding ranges, dryers, space heating, and air conditioning)."},
  {"id":321,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"During commissioning, a megger insulation-resistance reading is taken immediately and again after one minute to compute which useful diagnostic value?","opts":["Turns ratio","Phase rotation","Polarization index (PI)","Ground-electrode resistance"],"correct":2,"re":"The polarization index is the ratio of the 10-minute (or 1-minute) reading to the earlier reading, indicating insulation condition; a higher ratio generally indicates better, drier insulation."},
  {"id":322,"sec":"Safety","block":4,"q":"Before beginning CPR on an electric-shock victim, the single most important condition that must be satisfied is which of the following?","opts":["The victim's burns have been bandaged","The circuit breaker has been replaced with a new one","The victim has been given fluids","The victim is no longer in contact with any energized source"],"correct":3,"re":"CPR must not begin until the victim is completely clear of the energized source; otherwise the rescuer risks being shocked as well."},
  {"id":323,"sec":"Rough Wiring","block":4,"q":"When determining the minimum size of a box containing several conductors of different sizes, what is the correct total volume requirement?","opts":["The volume of the largest conductor times the number of conductors","The sum of the individual volume allowances for each conductor and component","Always a minimum of 18 cubic inches","The volume of the smallest conductor only"],"correct":1,"re":"Per NEC 314.16(B), the total box-fill is the sum of the individual volume allowances for all conductors, devices, clamps, and grounding conductors."},
  {"id":324,"sec":"Finish Wiring & Trim","block":4,"q":"A 3-way switch has how many terminals not counting the grounding screw?","opts":["Two","Three","Four","Five"],"correct":1,"re":"A 3-way switch has three current-carrying terminals: one common (often darker) terminal and two traveler terminals."},
  {"id":325,"sec":"Planning & Estimation","block":4,"q":"Using NEC 220.12, the minimum number of 15 A, 120 V general lighting branch circuits required for 6,000 VA of dwelling lighting load is:","opts":["4 circuits","2 circuits","5 circuits","8 circuits"],"correct":0,"re":"Each 15 A, 120 V circuit carries 1,800 VA; 6,000 ÷ 1,800 = 3.33, rounded up to 4 circuits."},
  {"id":326,"sec":"Rough Wiring","block":4,"q":"Liquidtight flexible nonmetallic conduit (LFNC) and liquidtight flexible metal conduit (LFMC) require listed fittings primarily to maintain which characteristic of the installation?","opts":["The liquidtight integrity at terminations","Maximum bend radius","Color coding","Grounding continuity only"],"correct":0,"re":"Per NEC 350.42 and 356.42, only fittings listed and identified for the conduit may be used to preserve the liquidtight seal at connections."},
  {"id":327,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the correct first step to reverse the rotation of a running three-phase motor found to be turning the wrong way at startup?","opts":["De-energize and swap any two of the three line conductors","Increase the supply voltage","Add a buck-boost transformer","Reverse only the equipment grounding conductor"],"correct":0,"re":"Three-phase motor rotation is reversed by de-energizing the circuit and interchanging any two of the three line (phase) conductors at the motor terminals."},
  {"id":328,"sec":"Safety","block":4,"q":"Why is human skin resistance an important factor in electrical shock severity, and how does moisture affect it?","opts":["Moisture increases skin resistance, reducing current flow","Dry skin always allows more current than wet skin","Moisture has no effect on skin resistance","Moisture lowers skin resistance, allowing more current to flow and increasing danger"],"correct":3,"re":"Wet or sweaty skin has much lower resistance than dry skin, so for the same voltage more current flows through the body, making the shock more dangerous."},
  {"id":329,"sec":"Planning & Estimation","block":4,"q":"In the standard dwelling calculation, the range and dryer demand loads are added to the lighting/appliance demand at what percentage of their NEC-calculated demand values?","opts":["35%","100%","75%","40%"],"correct":1,"re":"After applying Tables 220.55 and 220.54 demand factors, the range and dryer demand values are added at 100% to the service/feeder calculation."},
  {"id":330,"sec":"Rough Wiring","block":4,"q":"A run of EMT contains three 90-degree bends and one 45-degree bend between two pull boxes; what is the total bend in degrees, and is it acceptable?","opts":["315 degrees, acceptable","315 degrees, not acceptable","405 degrees, not acceptable","270 degrees, acceptable"],"correct":0,"re":"Three 90-degree bends (270) plus one 45-degree bend equals 315 degrees, which is within the 360-degree maximum permitted between pull points per NEC 358.26."},
  {"id":331,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A lower ground-electrode resistance value is generally considered better; which condition tends to reduce the measured resistance of a ground rod?","opts":["Moist soil and a longer or multiple bonded electrodes","Dry, sandy, high-resistivity soil","A loose, corroded ground clamp","A shorter rod driven only a few inches deep"],"correct":0,"re":"Moist soil and increased electrode surface area, such as a longer rod or multiple bonded rods, lower the contact resistance to earth and improve the grounding system."},
  {"id":332,"sec":"Safety","block":4,"q":"When a portable power tool is dropped into water while still plugged in, what is the correct first response?","opts":["Reach into the water and pull the tool out by its cord","De-energize the circuit at the breaker or unplug it without contacting the water, then retrieve the tool","Continue using the tool once it dries","Pour more water on it to rinse it"],"correct":1,"re":"The energized tool can make the water hazardous; first remove power safely without touching the water, then retrieve and inspect the tool before any further use."},
  {"id":333,"sec":"Finish Wiring & Trim","block":4,"q":"A 4-way switch has how many current-carrying terminals not counting the grounding screw?","opts":["Two","Four","Three","Six"],"correct":1,"re":"A 4-way switch has four terminals, arranged as two pairs of travelers, and is installed between two 3-way switches."},
  {"id":334,"sec":"Planning & Estimation","block":4,"q":"A three-phase, 208 V panel supplies a balanced load of 36 kVA; what is the approximate line current on each phase?","opts":["173 A","100 A","115 A","60 A"],"correct":1,"re":"IL = kVA × 1000 ÷ (√3 × VL) = 36,000 ÷ (1.732 × 208) = 36,000 ÷ 360.3 = 100 A."},
  {"id":335,"sec":"Rough Wiring","block":4,"q":"Where a cable is installed in a notch cut into the face of a wood stud, what is required to protect the cable from screws and nails?","opts":["Nothing, a notch is always acceptable","Filling the notch with caulk","Painting the cable a bright color","A steel plate at least 1/16 inch thick installed across the face of the notch"],"correct":3,"re":"Per NEC 300.4(A)(2), cables installed in notches in wood must be protected by a steel plate at least 1/16 in. thick across the face of the notch."},
  {"id":336,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"Which sequence best describes proper commissioning order before placing a new feeder into service?","opts":["Energize first, then check torque and grounding","Verify terminations torque and grounding/bonding, perform insulation-resistance testing, then energize and measure voltages","Measure phase rotation only after full load is applied","Apply load, then verify the equipment grounding conductor"],"correct":1,"re":"Proper commissioning is done de-energized first: verify torque and grounding/bonding, perform insulation-resistance tests, and only then energize to measure operating voltages."},
  {"id":337,"sec":"Safety","block":4,"q":"What is the chief safety advantage of a double-insulated portable tool when the equipment grounding conductor of the supply might be unreliable?","opts":["It can be used on any voltage without limit","Its two independent insulation layers protect the user even without a grounding conductor","It never requires maintenance","It automatically increases its own current rating"],"correct":1,"re":"Double insulation provides a second, independent barrier between live parts and the user, giving shock protection that does not depend on an external grounding conductor."},
  {"id":338,"sec":"Planning & Estimation","block":4,"q":"A dwelling's net calculated load is 27,600 VA on a 240 V single-phase service; what is the required minimum service rating from standard sizes?","opts":["100 A","150 A","125 A","200 A"],"correct":2,"re":"27,600 ÷ 240 = 115 A; the next standard service/overcurrent size up is 125 A."},
  {"id":339,"sec":"Rough Wiring","block":4,"q":"What is the maximum support spacing generally required for electrical metallic tubing (EMT) along an exposed straight run?","opts":["6 feet","8 feet","12 feet","10 feet"],"correct":3,"re":"Per NEC 358.30(A), EMT must be supported at intervals not exceeding 10 ft along the run."},
  {"id":340,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When testing a de-energized branch circuit with an ohmmeter, a reading of infinite (OL) resistance between the two ends of a single conductor indicates which condition?","opts":["An open circuit","A short circuit","A ground fault","Normal continuity"],"correct":0,"re":"Infinite resistance through one conductor means current cannot pass, which is the definition of an open. Good continuity would read near zero ohms."},
  {"id":341,"sec":"Finish Wiring & Trim","block":4,"q":"On a 3-way switch, the single terminal that connects to either the line or the load is commonly called the what?","opts":["Common terminal","Grounding terminal","Traveler terminal","Neutral terminal"],"correct":0,"re":"The common terminal of a 3-way switch (usually a dark or black-colored screw) connects to the line (source) at one switch and to the load at the other."},
  {"id":342,"sec":"Rough Wiring","block":4,"q":"What is the minimum length of a single ground rod that must be in contact with the soil to serve as a grounding electrode?","opts":["6 ft","10 ft","8 ft","4 ft"],"correct":2,"re":"NEC 250.52(A)(5) requires a rod electrode to be at least 8 ft in length in contact with the soil."},
  {"id":343,"sec":"Planning & Estimation","block":4,"q":"Two 12 kW household ranges on the same feeder have a Table 220.55 Column C demand of 11 kW; this demonstrates that the demand factor for ranges:","opts":["Increases the calculated load above nameplate","Reduces the combined load below the sum of nameplate ratings","Has no effect on multiple ranges","Applies only to commercial kitchens"],"correct":1,"re":"Two 12 kW ranges total 24 kW nameplate, but Table 220.55 Column C allows only 11 kW, showing the demand factor reduces the load below the connected total."},
  {"id":344,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(1), what is the minimum depth of working space required in front of electrical equipment operating at 0-150 volts to ground where there are exposed live parts on one side and no live or grounded parts on the other side?","opts":["2 feet","3 feet","3.5 feet","4 feet"],"correct":1,"re":"NEC 110.26(A)(1) Condition 1 requires a minimum working clearance depth of 3 feet for equipment at 0-150 V to ground."},
  {"id":345,"sec":"Rough Wiring","block":4,"q":"A single rod electrode that does not have a resistance to earth of 25 ohms or less must be supplemented by at least how many additional electrodes?","opts":["Two additional electrodes","One additional electrode","Three additional electrodes","No additional electrode is required"],"correct":1,"re":"NEC 250.53(A)(2) requires a single rod electrode exceeding 25 ohms to be supplemented by one additional electrode."},
  {"id":346,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A standard Class A GFCI device is designed to trip when the difference between the hot and neutral currents reaches approximately what value?","opts":["20 A","5 A","30 mA","5 mA"],"correct":3,"re":"A Class A GFCI trips at a ground-fault current of about 4 to 6 mA, nominally 5 mA, to protect people from shock."},
  {"id":347,"sec":"Planning & Estimation","block":4,"q":"What is the approximate full-load current of a three-phase 480 V load delivering 100 kW at a power factor of 1.0?","opts":["100 A","208 A","120 A","150 A"],"correct":2,"re":"IL = P ÷ (√3 × VL × PF) = 100,000 ÷ (1.732 × 480 × 1.0) = 100,000 ÷ 831.4 = 120 A."},
  {"id":348,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(3), what is the minimum required headroom (height) of the working space about service equipment, panelboards, or motor control centers rated 1200 amperes or less?","opts":["7 feet 6 inches","6 feet","7 feet","6 feet 6 inches"],"correct":3,"re":"NEC 110.26(A)(3) requires minimum headroom of 6.5 feet (6 ft 6 in) for the working space about electrical equipment."},
  {"id":349,"sec":"Rough Wiring","block":4,"q":"When two ground rods are used to form the grounding electrode, what is the minimum spacing required between them?","opts":["3 ft apart","6 ft apart","8 ft apart","10 ft apart"],"correct":1,"re":"NEC 250.53(A)(3) requires rod electrodes that are part of an array to be spaced at least 6 ft apart."},
  {"id":350,"sec":"Planning & Estimation","block":4,"q":"Using NEC Table 310.16 at the 60°C column, what is the allowable ampacity of a 12 AWG copper conductor?","opts":["15 A","20 A","25 A","30 A"],"correct":1,"re":"Per NEC Table 310.16, 12 AWG copper at the 60°C termination column has an allowable ampacity of 20 A."},
  {"id":351,"sec":"Finish Wiring & Trim","block":4,"q":"A switch controlling lighting in a dwelling generally must not switch which conductor?","opts":["The ungrounded (hot) conductor","The traveler conductor","The grounded (neutral) conductor","The switch leg"],"correct":2,"re":"NEC 404.2(B) requires switches to control the ungrounded conductor; the grounded (neutral) conductor is generally not to be switched (with limited exceptions)."},
  {"id":352,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An electrician notices that incandescent lights dim noticeably whenever a large motor starts on the same circuit; this symptom most directly points to which problem?","opts":["Excessive voltage drop from an undersized or overloaded conductor","A ground fault on the lighting circuit","A failed GFCI device","Reversed polarity at the receptacle"],"correct":0,"re":"Dimming during high-current draw indicates voltage drop, commonly caused by undersized conductors, long runs, or loose connections that cannot supply the inrush current."},
  {"id":353,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(2), the minimum width of the working space in front of electrical equipment must be the width of the equipment or what minimum dimension, whichever is greater?","opts":["24 inches","30 inches","42 inches","36 inches"],"correct":1,"re":"NEC 110.26(A)(2) requires the working space width to be a minimum of 30 inches or the width of the equipment, whichever is greater."},
  {"id":354,"sec":"Rough Wiring","block":4,"q":"A concrete-encased electrode (Ufer) must consist of at least 20 ft of bare copper conductor not smaller than which size?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"correct":0,"re":"NEC 250.52(A)(3) permits a concrete-encased electrode using at least 20 ft of bare copper conductor not smaller than 4 AWG."},
  {"id":355,"sec":"Planning & Estimation","block":4,"q":"What is the allowable ampacity of a 10 AWG copper conductor in the 60°C column of NEC Table 310.16?","opts":["30 A","25 A","20 A","40 A"],"correct":0,"re":"NEC Table 310.16 lists 10 AWG copper at 30 A in the 60°C column."},
  {"id":356,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An AFCI device is specifically designed to detect and respond to which hazardous condition?","opts":["Overvoltage from utility surges","Small ground-fault currents to earth","Arcing faults in wiring and connections","Phase imbalance between legs"],"correct":2,"re":"An AFCI senses the high-frequency current signature of an arc fault, such as from damaged or loose wiring, and interrupts the circuit to prevent fires."},
  {"id":357,"sec":"Rough Wiring","block":4,"q":"When a concrete-encased electrode uses electrically conductive coated steel reinforcing bars, the bars must be at least which diameter?","opts":["1/4 in","1/2 in","3/8 in","5/8 in"],"correct":1,"re":"NEC 250.52(A)(3) requires reinforcing bars used as a concrete-encased electrode to be at least 1/2 in in diameter."},
  {"id":358,"sec":"Safety","block":4,"q":"According to NEC 110.26(A)(2), the 30-inch-wide working space in front of a panelboard is permitted to be measured in which manner?","opts":["Only centered on the panelboard","Only from the left edge of the equipment","Measured diagonally across the equipment face","Either centered on the equipment or offset, as long as a 30-inch width is achieved"],"correct":3,"re":"NEC 110.26(A)(2) permits the 30-inch width to be measured either centered on the equipment or offset, provided the full 30-inch width is maintained."},
  {"id":359,"sec":"Planning & Estimation","block":4,"q":"According to NEC 240.6(A), which of the following is NOT a standard ampere rating for a fuse or inverse-time circuit breaker?","opts":["35 A","45 A","70 A","55 A"],"correct":3,"re":"Per NEC 240.6(A), 55 A is not a standard rating; the standard ratings skip from 50 A to 60 A."},
  {"id":360,"sec":"Finish Wiring & Trim","block":4,"q":"A general-use snap switch installed in a metal box must generally be provided with what connection for safety?","opts":["A connection to the grounded (neutral) conductor","An equipment grounding connection to the switch yoke","A surge protective device","An isolated ground conductor"],"correct":1,"re":"NEC 404.9(B) requires snap switches, including metal faceplate types, to be effectively grounded by connecting the equipment grounding conductor to the switch metal yoke or strap."},
  {"id":361,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A circuit breaker trips immediately and violently the instant it is reset, with no load connected; this behavior most strongly suggests which fault?","opts":["A gradual overload","Normal thermal trip from heat","A high-resistance loose connection","A direct short circuit (hot-to-neutral or hot-to-ground)"],"correct":3,"re":"Instantaneous tripping with no load points to a short circuit, where very high fault current activates the breaker's magnetic instantaneous trip. An overload trips slowly under load."},
  {"id":362,"sec":"Rough Wiring","block":4,"q":"A metal underground water pipe used as a grounding electrode must be in direct contact with the earth for at least how many feet?","opts":["5 ft","20 ft","8 ft","10 ft"],"correct":3,"re":"NEC 250.52(A)(1) requires a metal underground water pipe to be in direct contact with the earth for 10 ft or more to qualify as an electrode."},
  {"id":363,"sec":"Safety","block":4,"q":"Per NEC 110.26(E)(1), the dedicated equipment space above a panelboard or switchboard must extend from the top of the equipment to a height of how many feet above the equipment, or to the structural ceiling, whichever is lower?","opts":["3 feet","6.5 feet","6 feet","10 feet"],"correct":2,"re":"NEC 110.26(E)(1)(a) requires the dedicated electrical space to extend 6 feet above the equipment or to the structural ceiling, whichever is lower."},
  {"id":364,"sec":"Planning & Estimation","block":4,"q":"A continuous load draws 16 A; what minimum branch-circuit OCPD ampacity is required before applying any temperature or bundling adjustments?","opts":["20 A","18 A","16 A","25 A"],"correct":0,"re":"Per NEC 210.20(A), the OCPD must be at least 125% of the continuous load: 16 A × 1.25 = 20 A."},
  {"id":365,"sec":"Rough Wiring","block":4,"q":"A metal underground water pipe used as a grounding electrode must always be supplemented by which of the following?","opts":["An additional grounding electrode","A surge arrester","A second water meter","A larger service conductor"],"correct":0,"re":"NEC 250.53(D)(2) requires the metal underground water pipe electrode to be supplemented by an additional electrode of a type specified in 250.52."},
  {"id":366,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"In a multiwire branch circuit, what is the primary danger if the shared neutral becomes loose or open while the circuit is energized?","opts":["The breakers will trip immediately on overload","The GFCI will fail to test","Connected loads can be exposed to abnormally high or low voltages","The grounding conductor carries the full load current"],"correct":2,"re":"With an open shared neutral, the line-to-neutral loads become series-connected across the two legs, so voltage divides unevenly and can damage equipment."},
  {"id":367,"sec":"Safety","block":4,"q":"Within the dedicated equipment space above a panelboard required by NEC 110.26(E), which of the following is specifically permitted by the Code?","opts":["Foreign piping such as a water line","An HVAC duct passing through the space","A drain pan from equipment above","Sprinkler protection piping for the area"],"correct":3,"re":"NEC 110.26(E)(1)(b) prohibits foreign systems (piping, ducts, etc.) in the dedicated space but specifically permits sprinkler protection piping for the area."},
  {"id":368,"sec":"Planning & Estimation","block":4,"q":"Per NEC Chapter 9, Table 1, what is the maximum percent of conduit cross-sectional area that may be filled when more than two conductors are installed in a raceway?","opts":["31%","60%","53%","40%"],"correct":3,"re":"NEC Chapter 9, Table 1 limits fill to 40% for more than two conductors in a conduit or tubing."},
  {"id":369,"sec":"Rough Wiring","block":4,"q":"When a water meter is installed in a metal underground water pipe used as an electrode, what must be provided to maintain electrical continuity?","opts":["A dielectric union","A plastic spacer","A second ground rod only","A bonding jumper around the meter"],"correct":3,"re":"NEC 250.53(D)(1) requires a bonding jumper around insulating components such as a water meter to ensure continuity of the electrode."},
  {"id":370,"sec":"Finish Wiring & Trim","block":4,"q":"A standard 15-amp, 125-volt duplex receptacle on a 20-amp branch circuit serving multiple outlets is permitted because of what reason?","opts":["A 15-amp receptacle is never allowed on a 20-amp circuit","NEC Table 210.21(B)(3) permits 15-amp receptacles on a 20-amp circuit with two or more outlets","Only single receptacles are allowed","Only if the receptacle is GFCI"],"correct":1,"re":"NEC Table 210.21(B)(3) permits 15-amp rated receptacles to be used on 20-amp branch circuits where two or more receptacles are supplied."},
  {"id":371,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the correct way to verify that a GFCI receptacle is functioning properly?","opts":["Press the TEST button and confirm the device trips and removes power","Read line voltage with the device energized","Measure resistance across the line terminals","Apply a 30 mA load and confirm it holds"],"correct":0,"re":"Pressing the TEST button creates a small simulated imbalance; a working GFCI must trip and de-energize the outlet, after which RESET restores power."},
  {"id":372,"sec":"Planning & Estimation","block":4,"q":"What is the maximum conduit fill percentage permitted for a single conductor per NEC Chapter 9, Table 1?","opts":["31%","53%","40%","60%"],"correct":1,"re":"NEC Chapter 9, Table 1 permits 53% fill for one conductor in a raceway."},
  {"id":373,"sec":"Safety","block":4,"q":"Per NEC 110.27(A), live parts of electrical equipment operating at 50 volts or more must be guarded against accidental contact by which of the following methods?","opts":["Painting the live parts with insulating paint","Location in a room accessible only to qualified persons","Posting a warning sign within 10 feet","Applying dielectric grease to the conductors"],"correct":1,"re":"NEC 110.27(A) permits guarding live parts by location in a room, vault, or enclosure accessible only to qualified persons, among other listed methods."},
  {"id":374,"sec":"Rough Wiring","block":4,"q":"Where the upper end of a ground rod is exposed and subject to physical damage, how must it be installed to avoid additional protection requirements?","opts":["At least 6 in above grade","Flush with or below ground level","Painted with red paint","Wrapped in tape"],"correct":1,"re":"NEC 250.53(G) requires the rod to be installed flush with or below the ground unless the above-ground end and connection are protected."},
  {"id":375,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A motor runs sluggishly and stalls under load, and measurements show terminal voltage well below the nameplate rating during operation; the most likely cause is:","opts":["A failed AFCI breaker","Excessive voltage drop in the supply conductors","An oversized overcurrent device","Reversed line and neutral"],"correct":1,"re":"Low terminal voltage under load reduces motor torque, causing sluggish operation and stalling; this is a classic symptom of voltage drop from undersized or overloaded conductors."},
  {"id":376,"sec":"Rough Wiring","block":4,"q":"All grounding electrodes that are present at a building, such as a ground rod and a concrete-encased electrode, must be:","opts":["Connected only to the neutral bus","Kept electrically isolated from each other","Bonded together to form a grounding electrode system","Used one at a time on alternating days"],"correct":2,"re":"NEC 250.50 requires all electrodes present to be bonded together to form the grounding electrode system."},
  {"id":377,"sec":"Planning & Estimation","block":4,"q":"Per NEC Chapter 9, Table 1, what is the maximum conduit fill percentage when exactly two conductors are installed in a raceway?","opts":["26%","31%","40%","53%"],"correct":1,"re":"NEC Chapter 9, Table 1 limits two conductors in a raceway to 31% fill."},
  {"id":378,"sec":"Safety","block":4,"q":"Per NEC 110.27(A), at what voltage level do live parts of electrical equipment generally require guarding against accidental contact?","opts":["50 volts or more","30 volts or more","24 volts or more","120 volts or more"],"correct":0,"re":"NEC 110.27(A) requires that live parts operating at 50 volts or more be guarded against accidental contact."},
  {"id":379,"sec":"Finish Wiring & Trim","block":4,"q":"A single receptacle installed on an individual branch circuit must have an ampere rating that is at least what value relative to the branch circuit?","opts":["Half the rating of the branch circuit","One-third the rating of the branch circuit","Exactly 15 amps regardless of circuit","Equal to or greater than the rating of the branch circuit"],"correct":3,"re":"NEC 210.21(B)(1) requires a single receptacle on an individual branch circuit to have an ampere rating not less than that of the branch circuit."},
  {"id":380,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An ohmmeter reading of nearly zero ohms between an ungrounded (hot) conductor and the equipment grounding conductor on a de-energized circuit indicates what?","opts":["A ground fault or short to ground","An open neutral","Normal insulation resistance","An overloaded conductor"],"correct":0,"re":"Near-zero resistance between the hot and the grounding conductor means they are unintentionally connected, which is a ground fault. Healthy insulation reads very high resistance."},
  {"id":381,"sec":"Rough Wiring","block":4,"q":"What is the maximum size copper grounding electrode conductor required where the only electrode is a single ground rod?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"correct":2,"re":"NEC 250.66(A) states the GEC to a rod electrode is not required to be larger than 6 AWG copper."},
  {"id":382,"sec":"Planning & Estimation","block":4,"q":"For box-fill calculations under NEC 314.16(B), what volume allowance is assigned to each 14 AWG conductor?","opts":["2.00 in³","1.50 in³","2.25 in³","2.50 in³"],"correct":0,"re":"NEC Table 314.16(B) assigns 2.00 cubic inches per 14 AWG conductor."},
  {"id":383,"sec":"Safety","block":4,"q":"An electrician must work on the face of a 480-volt panelboard with exposed live parts on one side and a grounded concrete block wall directly behind; which working-space condition and depth of NEC 110.26(A)(1) applies?","opts":["Condition 1, 3 feet","Condition 3, 4 feet","Condition 2, 3.5 feet","Condition 2, 3 feet"],"correct":2,"re":"For 151-600 V to ground with exposed live parts on one side and grounded parts (concrete) on the other, this is Condition 2, requiring 3.5 feet per NEC Table 110.26(A)(1)."},
  {"id":384,"sec":"Rough Wiring","block":4,"q":"What is the maximum size copper grounding electrode conductor required where the connection is to a concrete-encased electrode?","opts":["4 AWG","6 AWG","8 AWG","3 AWG"],"correct":0,"re":"NEC 250.66(B) states the GEC to a concrete-encased electrode is not required to be larger than 4 AWG copper."},
  {"id":385,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A 15-amp breaker trips after roughly 10 to 15 minutes of running several appliances, but resets and holds fine when fewer loads are used; this pattern indicates:","opts":["A bolted short circuit","A ground fault","A sustained overload","A defective AFCI sensor"],"correct":2,"re":"Delayed tripping that correlates with the number of loads is the signature of a thermal overload, where current modestly exceeds the rating and heats the bimetal element over time."},
  {"id":386,"sec":"Planning & Estimation","block":4,"q":"What single-conductor volume allowance does NEC Table 314.16(B) assign to a 12 AWG conductor?","opts":["2.25 in³","2.00 in³","2.50 in³","3.00 in³"],"correct":0,"re":"NEC Table 314.16(B) assigns 2.25 cubic inches for each 12 AWG conductor."},
  {"id":387,"sec":"Finish Wiring & Trim","block":4,"q":"Which receptacle grade is built to a higher standard for impact, retention force, and durability for demanding applications?","opts":["Residential grade","Standard grade","Decorator grade","Hospital grade"],"correct":3,"re":"Hospital-grade receptacles are constructed to higher standards (identified by a green dot) for greater durability, contact retention, and reliability than residential or standard grades."},
  {"id":388,"sec":"Safety","block":4,"q":"Per NEC 110.26(C), at least one entrance giving access to and egress from the working space about electrical equipment is required primarily to protect against what hazard?","opts":["Equipment overheating","Unauthorized access by the public","Workers being trapped near energized equipment during an emergency","Moisture intrusion into the panel"],"correct":2,"re":"NEC 110.26(C) entrance/egress requirements ensure a worker can escape quickly from the working space in the event of an arc-flash or other emergency."},
  {"id":389,"sec":"Rough Wiring","block":4,"q":"A grounding electrode conductor that is the sole connection to a single ground rod and is run in free air must be protected if it is smaller than which size?","opts":["8 AWG","10 AWG","4 AWG","6 AWG"],"correct":3,"re":"NEC 250.64(B) permits a 6 AWG or larger copper GEC to be run along the surface without metal protection where not subject to severe physical damage."},
  {"id":390,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"During a thermal imaging survey of an energized panel, one breaker terminal appears significantly hotter than identical adjacent terminals carrying similar current; this hot spot most likely indicates:","opts":["A loose or high-resistance connection","An oversized conductor","A tripped GFCI","A perfectly torqued connection"],"correct":0,"re":"A localized hot spot at a termination usually means a loose or corroded connection creating extra resistance, which generates heat under load and can lead to failure or fire."},
  {"id":391,"sec":"Planning & Estimation","block":4,"q":"A device box contains six 12 AWG current-carrying conductors with no other fill items; what total box volume is required by NEC 314.16(B)?","opts":["12.0 in³","15.0 in³","13.5 in³","18.0 in³"],"correct":2,"re":"Six 12 AWG conductors at 2.25 in³ each equal 13.5 cubic inches per NEC Table 314.16(B)."},
  {"id":392,"sec":"Rough Wiring","block":4,"q":"For a service with 2 AWG copper ungrounded service-entrance conductors, what is the minimum size copper grounding electrode conductor per Table 250.66?","opts":["10 AWG","4 AWG","6 AWG","8 AWG"],"correct":3,"re":"Table 250.66 requires an 8 AWG copper GEC for service conductors of 2 AWG copper."},
  {"id":393,"sec":"Safety","block":4,"q":"Per NEC 110.26(C)(2), for equipment rated 1200 amperes or more and over 6 feet wide, how many entrances to the working space (one at each end) are generally required unless specific exceptions are met?","opts":["No entrance is required","One entrance only","Three entrances","Two entrances"],"correct":3,"re":"NEC 110.26(C)(2) requires two entrances/egress points, one at each end, for large equipment rated 1200 A or more and over 6 feet wide."},
  {"id":394,"sec":"Planning & Estimation","block":4,"q":"Under NEC 314.16(B), how many volume allowances do all the equipment grounding conductors entering a box collectively count as?","opts":["One per grounding conductor","Zero","One, based on the largest grounding conductor","Two total"],"correct":2,"re":"NEC 314.16(B)(5) counts all equipment grounding conductors as a single volume allowance based on the largest such conductor."},
  {"id":395,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When beginning to troubleshoot a dead receptacle, which step should logically be performed FIRST?","opts":["Replace the receptacle","Replace the service panel","Pull new wire to the outlet","Verify the problem and check for a tripped breaker or GFCI"],"correct":3,"re":"Good diagnostic sequence starts by confirming the symptom and checking the simplest, most likely causes first, such as a tripped breaker or upstream GFCI, before invasive work."},
  {"id":396,"sec":"Rough Wiring","block":4,"q":"For a service with 1/0 AWG copper ungrounded service-entrance conductors, what is the minimum size copper grounding electrode conductor per Table 250.66?","opts":["8 AWG","6 AWG","4 AWG","2 AWG"],"correct":1,"re":"Table 250.66 requires a 6 AWG copper GEC for service conductors over 2 AWG through 1/0 AWG copper."},
  {"id":397,"sec":"Finish Wiring & Trim","block":4,"q":"For storage-type clothes closets, a surface-mounted incandescent or LED luminaire with a completely enclosed lamp must maintain a minimum clearance of how much from the nearest storage space?","opts":["6 inches","18 inches","12 inches","24 inches"],"correct":2,"re":"NEC 410.16(C) requires a minimum 12-in. clearance between a surface-mounted, completely enclosed incandescent/LED luminaire and the nearest point of a closet storage space."},
  {"id":398,"sec":"Safety","block":4,"q":"Per NEC 110.26(D), what must be provided at the working space about service equipment, switchboards, panelboards, and motor control centers installed indoors?","opts":["A fire extinguisher","A grounding mat","Illumination","A telephone"],"correct":2,"re":"NEC 110.26(D) requires that illumination be provided for all working spaces about service equipment, switchboards, panelboards, and motor control centers located indoors."},
  {"id":399,"sec":"Planning & Estimation","block":4,"q":"When sizing branch-circuit conductors, the NEC recommends that voltage drop generally not exceed what percentage for the branch circuit alone?","opts":["1%","3%","5%","8%"],"correct":1,"re":"NEC 210.19 Informational Note recommends a maximum 3% voltage drop on a branch circuit, with 5% total for feeder plus branch circuit."},
  {"id":400,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"On a 120-volt circuit, a voltmeter reads 120 V from hot to ground but 0 V from hot to neutral; this reading most likely indicates:","opts":["A short between hot and neutral","A solid ground fault","A normal, properly working circuit","An open neutral"],"correct":3,"re":"Full voltage to ground but no voltage to neutral means the neutral path is broken; the meter completes the circuit through ground, confirming an open neutral."},
  {"id":401,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 15-ampere branch circuit per Table 250.122?","opts":["12 AWG","10 AWG","14 AWG","16 AWG"],"correct":2,"re":"Table 250.122 requires a 14 AWG copper EGC for an overcurrent device rated 15 amperes."},
  {"id":402,"sec":"Planning & Estimation","block":5,"q":"The NEC recommends that the combined voltage drop of the feeder and branch circuit to the farthest outlet not exceed what total percentage?","opts":["3%","5%","8%","10%"],"correct":1,"re":"NEC Informational Notes recommend total voltage drop of feeder plus branch circuit not exceed 5%."},
  {"id":403,"sec":"Safety","block":5,"q":"Per NEC 110.26(B), the working space required in front of electrical equipment must be kept clear and may NOT be used for which purpose?","opts":["Temporary access during installation","Passage of qualified persons","Storage of materials and equipment","Mounting of the required illumination fixture"],"correct":2,"re":"NEC 110.26(B) requires the working space to be clear and prohibits its use for storage; when normally enclosed live parts are exposed, the space must be suitably guarded."},
  {"id":404,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"In a properly balanced 120/240-volt multiwire branch circuit, the current carried by the shared neutral equals:","opts":["The sum of the two line currents","Twice the larger line current","The difference between the two line currents","Always zero regardless of load"],"correct":2,"re":"When the two ungrounded legs are on opposite phases, the neutral carries only the unbalanced (difference) current, which is why the neutral is shared safely when correctly connected."},
  {"id":405,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 20-ampere branch circuit per Table 250.122?","opts":["14 AWG","12 AWG","10 AWG","8 AWG"],"correct":1,"re":"Table 250.122 requires a 12 AWG copper EGC for an overcurrent device rated 20 amperes."},
  {"id":406,"sec":"Finish Wiring & Trim","block":5,"q":"A surface-mounted fluorescent luminaire on the wall or ceiling of a clothes closet must maintain a minimum clearance of how much from the nearest storage space?","opts":["6 inches","3 inches","12 inches","18 inches"],"correct":0,"re":"NEC 410.16(C) permits surface-mounted fluorescent luminaires in clothes closets with a minimum clearance of 6 in. from the nearest point of a storage space."},
  {"id":407,"sec":"Planning & Estimation","block":5,"q":"Conductor terminations on equipment rated 100 A or less are generally based on which temperature column unless the equipment is listed and marked otherwise?","opts":["75°C","60°C","90°C","105°C"],"correct":1,"re":"Per NEC 110.14(C)(1)(a), terminations for circuits 100 A or less default to the 60°C column unless marked for higher."},
  {"id":408,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 60-ampere circuit per Table 250.122?","opts":["8 AWG","10 AWG","12 AWG","6 AWG"],"correct":1,"re":"Table 250.122 requires a 10 AWG copper EGC for an overcurrent device rated 60 amperes."},
  {"id":409,"sec":"Safety","block":5,"q":"For an overhead service drop of 120/240-volt conductors crossing over a residential driveway not subject to truck traffic, what is the minimum vertical clearance above the driveway required by the NEC?","opts":["10 feet","15 feet","12 feet","18 feet"],"correct":2,"re":"Per NEC 230.24(B), service-drop conductors not exceeding 300 V to ground require 12 feet of clearance over residential property and driveways not subject to truck traffic."},
  {"id":410,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"If pressing the TEST button on a GFCI receptacle does NOT cause it to trip, the correct conclusion is:","opts":["The GFCI is working perfectly","The downstream load is too small","The circuit voltage is too high","The GFCI is defective and should be replaced"],"correct":3,"re":"A GFCI that fails to trip on its TEST button has lost its protective function and must be replaced, since it can no longer interrupt a real ground fault."},
  {"id":411,"sec":"Planning & Estimation","block":5,"q":"Even when 90°C-rated conductors are installed, what is the primary permitted use of the 90°C ampacity column in NEC Table 310.16?","opts":["For final termination ampacity","For load calculations only","As the starting ampacity for applying adjustment and correction factors","It cannot be used at all"],"correct":2,"re":"Per NEC 110.14(C), the 90°C column is used as the starting point for derating, but the final ampacity must not exceed the termination temperature rating."},
  {"id":412,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 100-ampere circuit per Table 250.122?","opts":["10 AWG","8 AWG","6 AWG","4 AWG"],"correct":1,"re":"Table 250.122 requires an 8 AWG copper EGC for an overcurrent device rated 100 amperes."},
  {"id":413,"sec":"Safety","block":5,"q":"Per NEC 230.24(B), what is the minimum vertical clearance for overhead service-drop conductors above a public street, alley, or road subject to truck traffic?","opts":["12 feet","15 feet","22 feet","18 feet"],"correct":3,"re":"NEC 230.24(B)(4) requires 18 feet of clearance over public streets, alleys, roads, and other areas subject to truck traffic."},
  {"id":414,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Which maintenance practice best helps prevent loose-connection heating at panel and device terminations over time?","opts":["Periodically retorquing connections to manufacturer specifications","Leaving terminals slightly loose for thermal expansion","Painting all terminals to prevent corrosion","Increasing the breaker size to reduce heat"],"correct":0,"re":"Connections can loosen from thermal cycling and vibration; periodic inspection and retorquing to the specified value keeps resistance low and prevents heat buildup."},
  {"id":415,"sec":"Finish Wiring & Trim","block":5,"q":"Which type of luminaire is NOT permitted to be installed in a clothes closet?","opts":["An incandescent luminaire with an open or exposed lamp","Recessed fluorescent fixture","Surface-mounted LED fixture","A completely enclosed surface-mounted incandescent fixture"],"correct":0,"re":"NEC 410.16(B) prohibits incandescent luminaires with open or partially enclosed lamps and pendant luminaires in clothes closets due to fire risk."},
  {"id":416,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 40-ampere branch circuit per Table 250.122?","opts":["12 AWG","14 AWG","8 AWG","10 AWG"],"correct":3,"re":"Table 250.122 requires a 10 AWG copper EGC for an overcurrent device rated 40 amperes."},
  {"id":417,"sec":"Planning & Estimation","block":5,"q":"What is the allowable ampacity of a 14 AWG copper conductor at the 60°C column of NEC Table 310.16?","opts":["10 A","15 A","20 A","25 A"],"correct":1,"re":"NEC Table 310.16 lists 14 AWG copper at 15 A in the 60°C column."},
  {"id":418,"sec":"Safety","block":5,"q":"Per NEC 230.24(A), overhead service-drop conductors must maintain a minimum clearance of how many feet above the roof surface in the general case before any reduced-clearance exceptions apply?","opts":["3 feet","8 feet","6 feet","10 feet"],"correct":1,"re":"NEC 230.24(A) generally requires conductors to have a clearance of not less than 8 feet above the roof surface, with several reduced-clearance exceptions."},
  {"id":419,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Two 120-volt receptacle circuits fed from the SAME phase are wired to share one neutral; the most serious consequence is:","opts":["The neutral carries only the difference of the two currents","The grounding conductor becomes energized","The circuits will not energize at all","The shared neutral can be overloaded because the currents add instead of subtract"],"correct":3,"re":"When both hots are on the same phase, neutral currents add rather than cancel, so the single neutral can be forced to carry more than its rated current and overheat."},
  {"id":420,"sec":"Rough Wiring","block":5,"q":"When an equipment grounding conductor is increased in size because the ungrounded conductors were upsized, the EGC must be increased in what manner?","opts":["It does not need to be increased","By exactly one AWG size","Doubled in size","Proportionally to the increase in circular mil area of the ungrounded conductors"],"correct":3,"re":"NEC 250.122(B) requires the EGC to be increased proportionally to the circular mil area increase of the ungrounded conductors."},
  {"id":421,"sec":"Planning & Estimation","block":5,"q":"A noncontinuous load of 24 A is supplied; selecting the next standard OCPD per NEC 240.6(A), what size overcurrent device is appropriate?","opts":["20 A","35 A","30 A","25 A"],"correct":3,"re":"Per NEC 240.6(A), 25 A is a standard rating and accommodates the 24 A noncontinuous load."},
  {"id":422,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"An AFCI breaker keeps tripping on a circuit, but a plug-in tester and visual inspection show no ground fault or obvious short; which is a reasonable next troubleshooting step?","opts":["Immediately replace the entire panel","Inspect for damaged cable, loose terminations, or arcing-prone connections on that circuit","Increase the breaker amperage rating","Disconnect the equipment grounding conductor"],"correct":1,"re":"Because AFCIs respond to arcing, repeated trips warrant inspecting for damaged insulation, staples through cable, or loose connections that produce arc signatures."},
  {"id":423,"sec":"Safety","block":5,"q":"Per NEC 230.24(B)(1), service-drop conductors limited to 150 volts to ground require a minimum vertical clearance of how many feet above finished grade, sidewalks, or platforms accessible only to pedestrians?","opts":["10 feet","8 feet","12 feet","15 feet"],"correct":0,"re":"NEC 230.24(B)(1) requires 10 feet of clearance above finished grade, sidewalks, or accessible surfaces from which they might be reached, for conductors limited to 150 V to ground."},
  {"id":424,"sec":"Rough Wiring","block":5,"q":"When a single equipment grounding conductor is run with multiple circuits in the same raceway, it must be sized based on which overcurrent device?","opts":["The largest overcurrent device protecting conductors in the raceway","The smallest in the group","The average of all devices","The first circuit installed"],"correct":0,"re":"NEC 250.122(C) requires a single EGC for multiple circuits to be sized for the largest overcurrent device in the raceway."},
  {"id":425,"sec":"Finish Wiring & Trim","block":5,"q":"A luminaire used as a raceway for circuit conductors is permitted only when it is what?","opts":["Painted to match the ceiling","Installed below 8 ft","Listed and marked for use as a raceway","Rated for wet locations"],"correct":2,"re":"NEC 410.64 permits luminaires to be used as a raceway for circuit conductors only where listed and marked for use as a raceway (or where designed for end-to-end assembly)."},
  {"id":426,"sec":"Planning & Estimation","block":5,"q":"A continuous load requires conductors sized at 22 A minimum after the 125% factor; using the 75°C column of Table 310.16, what minimum copper conductor satisfies this 22 A requirement?","opts":["14 AWG","10 AWG","12 AWG","8 AWG"],"correct":1,"re":"In the 75°C column, 12 AWG is 25 A but is limited to 20 A by NEC 240.4(D); 10 AWG at 35 A is the smallest conductor providing at least 22 A."},
  {"id":427,"sec":"Rough Wiring","block":5,"q":"The main bonding jumper, which connects the grounded (neutral) conductor to the equipment grounding system, is installed at which location?","opts":["At every subpanel","Only at the service disconnecting means","At the farthest receptacle","At each grounding electrode"],"correct":1,"re":"NEC 250.24(B) and 250.28 require the main bonding jumper to be installed at the service disconnecting means."},
  {"id":428,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"When using a voltmeter to locate an open in a series string of three loads that are all dead, where will the full source voltage appear?","opts":["Across each load equally","Across the open (break) point","Across the grounding conductor","Nowhere, the meter reads zero everywhere"],"correct":1,"re":"In a series circuit with an open, the entire source voltage drops across the break because no current flows, so measuring full voltage across a component reveals the open."},
  {"id":429,"sec":"Safety","block":5,"q":"Treating cover as a safety issue, what is the minimum burial depth required by NEC Table 300.5 for direct-buried UF cable supplying a residential branch circuit of 120 volts or less protected by a 20-ampere GFCI, in a trench with no other protection?","opts":["6 inches","12 inches","18 inches","24 inches"],"correct":1,"re":"NEC Table 300.5 permits 12 inches of cover for residential branch circuits rated 120 V or less and protected by a GFCI at 20 amperes or less."},
  {"id":430,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.4(D), what is the maximum overcurrent protection generally permitted for a 14 AWG copper conductor regardless of its 90°C ampacity?","opts":["15 A","20 A","25 A","30 A"],"correct":0,"re":"NEC 240.4(D) limits 14 AWG copper to a maximum 15 A overcurrent device."},
  {"id":431,"sec":"Rough Wiring","block":5,"q":"At a subpanel located in a separate enclosure downstream of the service, the neutral (grounded) conductor must be:","opts":["Bonded to the enclosure with a bonding screw","Isolated from the equipment grounding bus and enclosure","Connected to a local ground rod only","Connected to the equipment grounding bus only"],"correct":1,"re":"NEC 250.24(A)(5) prohibits the neutral-to-ground connection on the load side of the service; the neutral must be isolated at a subpanel."},
  {"id":432,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Conductors and terminations that feel hot and show discoloration at a receptacle under normal load most commonly result from:","opts":["An open neutral elsewhere","A correctly sized conductor","An undersized or loosely connected conductor","A properly tripped GFCI"],"correct":2,"re":"Heat and discoloration indicate excessive resistance, typically from an undersized conductor or a loose, poorly made connection that dissipates power as heat."},
  {"id":433,"sec":"Finish Wiring & Trim","block":5,"q":"A standard incandescent dimmer is generally suitable for controlling which type of load?","opts":["A resistive (incandescent) lighting load","A receptacle outlet load","A standard motor load","A fluorescent ballast not rated for dimming"],"correct":0,"re":"A standard dimmer is designed for resistive incandescent (and listed compatible) lighting loads; it must not be used on motors or non-dimmable ballasts unless specifically rated."},
  {"id":434,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.4(D), what is the maximum standard overcurrent device permitted to protect a 12 AWG copper conductor?","opts":["15 A","25 A","20 A","30 A"],"correct":2,"re":"NEC 240.4(D) limits 12 AWG copper to a maximum 20 A overcurrent device."},
  {"id":435,"sec":"Safety","block":5,"q":"Per NEC Table 300.5, what is the general minimum burial depth (cover) for direct-buried cables or conductors rated 0-1000 volts where no special permitted reduction applies?","opts":["12 inches","24 inches","18 inches","30 inches"],"correct":1,"re":"NEC Table 300.5 Column 1 specifies 24 inches of cover as the general minimum for direct-buried conductors rated 0-1000 volts."},
  {"id":436,"sec":"Rough Wiring","block":5,"q":"The connection between the grounded (neutral) conductor and the equipment grounding conductors is permitted at which single point in a typical service?","opts":["At the meter socket only","At each branch-circuit panelboard","At the main service equipment","At every junction box"],"correct":2,"re":"NEC 250.24(A)(5) limits the neutral-to-ground bond to the service equipment; downstream connections are not permitted."},
  {"id":437,"sec":"Planning & Estimation","block":5,"q":"A panelboard supplies a continuous load of 40 A; what minimum OCPD rating is required to satisfy the 125% continuous-load rule?","opts":["50 A","45 A","40 A","60 A"],"correct":0,"re":"40 A × 1.25 = 50 A, and 50 A is a standard rating under NEC 240.6(A)."},
  {"id":438,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A GFCI protects against shock by comparing the current in which two conductors?","opts":["The hot and the equipment grounding conductor","The two ungrounded legs of a 240-volt circuit","The ungrounded (hot) and the grounded (neutral) conductors","The neutral and the grounding conductor"],"correct":2,"re":"A GFCI continuously compares hot and neutral current; any difference means current is leaking by another path (a ground fault), and it trips at about 5 mA."},
  {"id":439,"sec":"Safety","block":5,"q":"Per NEC Table 300.5, what is the minimum cover for conductors installed in rigid metal conduit (RMC) or intermediate metal conduit (IMC) rated 0-1000 volts buried in a location not subject to vehicular traffic?","opts":["18 inches","12 inches","6 inches","24 inches"],"correct":2,"re":"NEC Table 300.5 Column 3 permits 6 inches of cover for conductors in RMC or IMC, since these raceways provide robust physical protection."},
  {"id":440,"sec":"Rough Wiring","block":5,"q":"Metal raceways, cable trays, and enclosures used as equipment grounding conductors must be effectively bonded primarily to ensure what?","opts":["Reduced installation cost","A decorative appearance","A low-impedance fault-current path","Increased conductor ampacity"],"correct":2,"re":"NEC 250.4(A)(5) and 250.96 require bonding to provide an effective low-impedance path to clear ground faults."},
  {"id":441,"sec":"Planning & Estimation","block":5,"q":"When a single equipment grounding conductor and conductors of different sizes occupy a box, which conductor size determines the volume allowance for that grounding conductor under NEC 314.16(B)(5)?","opts":["The smallest grounding conductor","An average of all conductors","The largest equipment grounding conductor","Always 14 AWG"],"correct":2,"re":"NEC 314.16(B)(5) bases the single grounding-conductor allowance on the largest equipment grounding conductor present."},
  {"id":442,"sec":"Finish Wiring & Trim","block":5,"q":"An occupancy sensor switch used to control lighting based on detected movement most commonly operates on which principle?","opts":["Measuring conductor temperature","Detecting ground faults","Sensing line voltage drop","Passive infrared or ultrasonic motion detection"],"correct":3,"re":"Occupancy sensors typically use passive infrared (PIR), ultrasonic, or dual-technology motion detection to turn lighting on when a space is occupied and off after it is vacant."},
  {"id":443,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Which instrument is most appropriate for measuring insulation resistance to confirm a suspected high-resistance short between conductors?","opts":["A clamp-on ammeter","A non-contact voltage detector","A receptacle plug-in tester","An insulation resistance tester (megohmmeter)"],"correct":3,"re":"A megohmmeter applies a high DC test voltage to reveal insulation breakdown and leakage that an ordinary ohmmeter may miss, making it ideal for insulation faults."},
  {"id":444,"sec":"Rough Wiring","block":5,"q":"Where a metal raceway containing service conductors enters an enclosure with concentric or eccentric knockouts, the connection must be made with:","opts":["A standard locknut only","A plastic bushing only","Tape over the knockout","Bonding-type fittings such as bonding bushings or bonding locknuts"],"correct":3,"re":"NEC 250.92(B) requires bonding-type fittings for service raceways at enclosures with concentric or eccentric knockouts."},
  {"id":445,"sec":"Safety","block":5,"q":"Per NEC 110.16(A), electrical equipment such as switchboards and panelboards in other than dwelling units that are likely to require examination while energized must be field- or factory-marked to warn of which hazard?","opts":["Electromagnetic interference","Carbon monoxide","Arc flash","Radiation exposure"],"correct":2,"re":"NEC 110.16(A) requires a field- or factory-applied marking warning qualified persons of potential electric arc-flash hazards."},
  {"id":446,"sec":"Planning & Estimation","block":5,"q":"In a box-fill calculation, how many volume allowances does each yoke or strap holding a device (such as a switch or receptacle) count as per NEC 314.16(B)(4)?","opts":["One, based on the largest conductor connected to it","Two, based on the largest conductor connected to it","One per terminal","None"],"correct":1,"re":"NEC 314.16(B)(4) counts each yoke or strap as two volume allowances based on the largest conductor connected to the device."},
  {"id":447,"sec":"Rough Wiring","block":5,"q":"A bonding jumper used on the supply side of the service (a supply-side bonding jumper) is sized based on which table?","opts":["Table 250.122","Table 310.16","Table 250.66","Table 300.5"],"correct":2,"re":"NEC 250.102(C) sizes supply-side bonding jumpers using Table 250.66 based on the service conductor size."},
  {"id":448,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Before taking resistance measurements with an ohmmeter to find an open or short, the circuit must be:","opts":["Fully energized at rated voltage","Loaded to full nameplate current","Connected to a running generator","De-energized and verified dead"],"correct":3,"re":"Ohmmeters supply their own test current and can be damaged or give false readings if applied to a live circuit, so the circuit must be de-energized and confirmed dead first."},
  {"id":449,"sec":"Safety","block":5,"q":"Per NEC 110.24(A), service equipment in other than dwelling units must be legibly field-marked with which of the following pieces of information?","opts":["The installer's contractor license number","The total connected load in kVA","The date of the next inspection","The maximum available fault current"],"correct":3,"re":"NEC 110.24(A) requires service equipment to be field-marked with the maximum available fault current, including the date the calculation was performed."},
  {"id":450,"sec":"Rough Wiring","block":5,"q":"Which condition allows a reducing washer to be relied upon as the sole bonding means for a service raceway?","opts":["None; reducing washers are not permitted as the sole bonding means for service raceways","When the conductor is copper","When it is painted","When the raceway is PVC"],"correct":0,"re":"NEC 250.92(B) does not permit standard reducing washers as the bonding means for service raceways; listed bonding devices are required."},
  {"id":451,"sec":"Planning & Estimation","block":5,"q":"All internal cable clamps present in a box collectively count as how many volume allowances under NEC 314.16(B)(2)?","opts":["One per clamp","Two total","One, based on the largest conductor in the box","Zero"],"correct":2,"re":"NEC 314.16(B)(2) counts all cable clamps together as a single volume allowance based on the largest conductor present."},
  {"id":452,"sec":"Finish Wiring & Trim","block":5,"q":"Many modern electronic dimmers and occupancy sensors require which conductor to be present in the switch box to power their internal electronics?","opts":["A second ungrounded conductor","A bonding jumper only","An isolated ground conductor","A grounded (neutral) conductor"],"correct":3,"re":"Many electronic dimmers and sensors require a grounded (neutral) conductor at the device to power their electronics; NEC 404.2(C) generally requires a neutral at switch locations to support such devices."},
  {"id":453,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A homeowner reports that a GFCI breaker trips only when it rains and an outdoor cord is plugged in; the most probable cause is:","opts":["A simple thermal overload","Moisture causing current leakage to ground","A reversed line and load connection only","An undersized service panel"],"correct":1,"re":"Weather-correlated GFCI tripping typically results from water intrusion creating a small leakage current to ground that exceeds the 5 mA trip threshold."},
  {"id":454,"sec":"Safety","block":5,"q":"Per NEC 110.22(A), each disconnecting means must be legibly marked to indicate its purpose unless what condition is true?","opts":["It is rated less than 100 amperes","It is installed by a licensed electrician","It is located within sight of the equipment it controls and the purpose is evident","It is a molded-case circuit breaker"],"correct":2,"re":"NEC 110.22(A) requires each disconnecting means to be legibly marked to identify its purpose unless located and arranged so the purpose is evident."},
  {"id":455,"sec":"Rough Wiring","block":5,"q":"What is the minimum burial depth for direct-buried UF cable or conductors rated 0 to 1000 volts under a residential lawn, per Table 300.5?","opts":["12 in","18 in","24 in","6 in"],"correct":2,"re":"Table 300.5 Column 1 requires 24 in of cover for direct-buried cables and conductors not in raceway."},
  {"id":456,"sec":"Planning & Estimation","block":5,"q":"Which estimating term refers to the itemized list of all materials, devices, and fittings counted from the plans needed to complete a job?","opts":["Material takeoff","Labor unit","Overhead allocation","Change order"],"correct":0,"re":"A material takeoff is the itemized count of materials and devices derived from the construction documents."},
  {"id":457,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Excessive voltage drop on a long branch-circuit run is best reduced by:","opts":["Increasing the conductor size (larger wire gauge)","Installing a larger overcurrent device","Adding more loads to the circuit","Lowering the supply voltage"],"correct":0,"re":"Voltage drop is proportional to conductor resistance and length; increasing wire size lowers resistance and reduces the drop for a given current."},
  {"id":458,"sec":"Rough Wiring","block":5,"q":"What is the minimum burial depth for conductors installed in rigid nonmetallic conduit (PVC) approved for direct burial, 0 to 1000 volts, per Table 300.5?","opts":["18 in","24 in","6 in","12 in"],"correct":0,"re":"Table 300.5 Column 4 requires 18 in of cover for conductors in nonmetallic raceways listed for direct burial."},
  {"id":459,"sec":"Safety","block":5,"q":"Per NEC 408.4(A), each circuit and circuit modification in a panelboard must be legibly identified as to its clear, evident, and specific purpose by which means?","opts":["A diagram taped to the nearest wall","A circuit directory located on the face or inside of the panel door","A verbal explanation to the building owner","A label on the main service conductors only"],"correct":1,"re":"NEC 408.4(A) requires a circuit directory or circuit identification located on the face or inside of the panel door, supporting safe identification of disconnects."},
  {"id":460,"sec":"Planning & Estimation","block":5,"q":"In electrical estimating, a 'labor unit' most directly represents which of the following?","opts":["The price of a material item","The total project overhead","The estimated time to install a specific item","The markup percentage on materials"],"correct":2,"re":"A labor unit is the standardized estimated installation time (often in hours) assigned to installing a particular item."},
  {"id":461,"sec":"Finish Wiring & Trim","block":5,"q":"When terminating a 12 AWG conductor under a device screw, the connection should be tightened to what guideline?","opts":["As tight as possible with maximum force","Until the screw head strips","Hand-tight only with no tool","To the manufacturer's specified torque value"],"correct":3,"re":"NEC 110.14(D) requires that terminations be tightened to the torque value specified by the manufacturer, typically using a calibrated torque tool, to ensure a reliable connection."},
  {"id":462,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"While the breaker handle stays in the ON position but no power reaches the circuit, the most appropriate first measurement is:","opts":["Resistance of the load with power on","The torque on the neutral bar screws","Insulation resistance of the panel enclosure","Voltage at the breaker's load terminal to neutral"],"correct":3,"re":"Measuring voltage at the breaker output tells you whether the breaker is actually delivering power, which logically separates a faulty breaker from a downstream wiring problem."},
  {"id":463,"sec":"Rough Wiring","block":5,"q":"What is the minimum cover for a residential branch circuit rated 120 volts or less and 20 amperes or less, GFCI-protected, per Table 300.5?","opts":["24 in","18 in","6 in","12 in"],"correct":2,"re":"Table 300.5 Column 5 permits 6 in of cover for residential 120-volt, 20-ampere or less GFCI-protected circuits."},
  {"id":464,"sec":"Planning & Estimation","block":5,"q":"Voltage drop in a single-phase circuit is directly proportional to which combination of factors?","opts":["Conductor cross-sectional area only","Conduit fill percentage","Voltage and conductor insulation rating","Current and one-way circuit length"],"correct":3,"re":"Single-phase voltage drop increases with both the load current and the circuit length (VD = 2 × K × I × L / CM)."},
  {"id":465,"sec":"Safety","block":5,"q":"When taking voltage measurements on a 480-volt three-phase distribution panel inside a commercial building, which measurement category (CAT) rating should the digital multimeter and its leads have at minimum?","opts":["CAT I","CAT II","CAT III","CAT 0"],"correct":2,"re":"CAT III is the minimum rating for measurements on fixed installations such as distribution panels and branch circuits in commercial buildings; CAT IV is used at the service entrance."},
  {"id":466,"sec":"Rough Wiring","block":5,"q":"What is the minimum cover required for conductors in rigid metal conduit (RMC) buried directly in the earth, 0 to 1000 volts, per Table 300.5?","opts":["18 in","12 in","24 in","6 in"],"correct":3,"re":"Table 300.5 Column 2 requires 6 in of cover for rigid metal conduit and intermediate metal conduit."},
  {"id":467,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A key advantage of thermal imaging during electrical maintenance is that it allows the technician to:","opts":["De-energize equipment before inspection","Detect overheating connections without contact while the system is under load","Measure exact circuit resistance values","Replace the need for torque specifications"],"correct":1,"re":"Infrared thermography finds abnormal heat from loose or failing connections on energized, loaded equipment without physical contact, enabling early intervention."},
  {"id":468,"sec":"Planning & Estimation","block":5,"q":"To reduce voltage drop on a long branch circuit without changing the load or length, what is the most direct method?","opts":["Increase the OCPD rating","Decrease the conductor size","Increase the conductor size","Use a smaller conduit"],"correct":2,"re":"Increasing conductor size (larger circular-mil area) lowers resistance and therefore reduces voltage drop."},
  {"id":469,"sec":"Safety","block":5,"q":"An electrician needs to measure voltage at the line side of the main service disconnect of a commercial building; which CAT rating is most appropriate for the meter at this location?","opts":["CAT I","CAT II","CAT IV","CAT III"],"correct":2,"re":"CAT IV is intended for measurements at the origin of the installation, such as the service entrance and line side of the main disconnect, where available fault energy is highest."},
  {"id":470,"sec":"Finish Wiring & Trim","block":5,"q":"The push-in 'back-wire' holes on the back of many 15-amp residential receptacles are generally limited to conductors of what size?","opts":["12 AWG solid only","14 AWG solid only","10 AWG stranded","8 AWG solid"],"correct":1,"re":"The screwless push-in (back-wire) terminals on standard 15-amp receptacles are typically listed for 14 AWG solid copper only; larger conductors must use the screw terminals."},
  {"id":471,"sec":"Rough Wiring","block":5,"q":"Direct-buried conductors and cables emerging from grade must be protected by an enclosure or raceway extending from the required cover depth up to at least what height above finished grade?","opts":["4 ft","6 ft","8 ft","3 ft"],"correct":2,"re":"NEC 300.5(D)(1) requires protection from the required cover depth to at least 8 ft above finished grade."},
  {"id":472,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"To isolate whether a tripping breaker is caused by a wiring fault or by a connected appliance, a sound troubleshooting step is to:","opts":["Disconnect all loads and reset; if it holds, reconnect loads one at a time","Increase the breaker rating and retest","Replace the neutral bus","Bridge the breaker with a jumper"],"correct":0,"re":"Disconnecting loads and reconnecting them one at a time logically narrows the fault to either the wiring or a specific device, following a systematic isolation method."},
  {"id":473,"sec":"Planning & Estimation","block":5,"q":"A continuous load of 30 A is fed by conductors terminating at 75°C equipment; what minimum copper conductor size is required from the 75°C column of Table 310.16 to carry 125% of the load?","opts":["6 AWG","4 AWG","8 AWG","10 AWG"],"correct":2,"re":"30 A × 1.25 = 37.5 A; in the 75°C column, 8 AWG copper (50 A) is the smallest conductor that meets this, since 10 AWG is only 35 A."},
  {"id":474,"sec":"Safety","block":5,"q":"Regarding measurement category ratings, why can a meter rated CAT III 600 V be safer than a meter rated CAT II 1000 V when measuring at a distribution panel?","opts":["The CAT II meter cannot physically read 600 volts","The steady-state voltage rating is the only factor that matters for safety","CAT II always means a higher-quality meter","The CAT III rating reflects a higher transient-overvoltage withstand for that location, which matters more than the steady-state voltage number"],"correct":3,"re":"The CAT rating reflects the meter's ability to withstand transient overvoltages and available fault energy at a given location; a higher CAT number suited to the location is more protective than a higher steady-state voltage rating at a lower category."},
  {"id":475,"sec":"Rough Wiring","block":5,"q":"When a direct-buried cable is installed under a building, it must be:","opts":["Buried at 36 in regardless","Installed in a raceway","Left without any protection","Spliced every 10 ft"],"correct":1,"re":"Table 300.5 and 300.5(C) require cables routed under a building to be installed in a raceway extending beyond the building."},
  {"id":476,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Reading 240 volts across the two ungrounded legs but only 95 volts on one leg to neutral and 145 volts on the other leg to neutral in a multiwire circuit indicates:","opts":["A normal balanced condition","A short circuit between the legs","An open or lost neutral causing unequal voltage division","A failed GFCI device"],"correct":2,"re":"Total line-to-line voltage is correct, but the unequal line-to-neutral readings that still sum to 240 V reveal an open neutral letting voltage divide by load impedance."},
  {"id":477,"sec":"Planning & Estimation","block":5,"q":"When the ampacity of a conductor does not correspond to a standard OCPD rating and the circuit is not a multioutlet receptacle branch circuit, NEC 240.4(B) permits what action for ratings of 800 A or less?","opts":["Use the next lower standard OCPD only","Round the ampacity to the nearest 5 A","Use the next higher standard OCPD","No OCPD adjustment is allowed"],"correct":2,"re":"NEC 240.4(B) allows the next higher standard OCPD rating when the conductor ampacity does not match a standard size, subject to the 800 A limit and other conditions."},
  {"id":478,"sec":"Rough Wiring","block":5,"q":"A warning ribbon placed in the trench above an underground service is generally required to be located at least how far above the conductors?","opts":["12 in above the underground installation","Directly on top of the conductors","At the surface only","24 in above the conductors"],"correct":0,"re":"NEC 300.5(D)(3) requires a warning ribbon at least 12 in above underground service conductors not encased in concrete."},
  {"id":479,"sec":"Finish Wiring & Trim","block":5,"q":"When looping a solid conductor under a binding screw of a device, the loop should be formed so that it wraps around the screw in which direction?","opts":["Counterclockwise","Clockwise, the direction the screw tightens","Straight across without a loop","It does not matter"],"correct":1,"re":"A conductor loop should be wrapped clockwise (the tightening direction) around the binding screw so the screw draws the wire in rather than pushing it out as it is tightened."},
  {"id":480,"sec":"Safety","block":5,"q":"Before using a digital multimeter to verify that a circuit is de-energized as part of a lockout/tagout procedure, what is the best practice to confirm the meter itself is functioning?","opts":["Tap the meter on a hard surface to reset it","Assume the meter works if its display powered on","Read the meter only once on the suspected dead circuit","Use the live-dead-live test by checking a known live source before and after the measurement"],"correct":3,"re":"The live-dead-live (test-before-touch) method confirms the meter reads a known energized source, then the suspected dead circuit, then the live source again to verify the meter did not fail during the test."},
  {"id":481,"sec":"Planning & Estimation","block":5,"q":"A box contains four 12 AWG conductors and two 14 AWG conductors with no devices or clamps; what total box volume is required per NEC 314.16(B)?","opts":["11.0 in³","13.0 in³","13.5 in³","15.0 in³"],"correct":1,"re":"Four 12 AWG at 2.25 = 9.0 in³ plus two 14 AWG at 2.00 = 4.0 in³, totaling 13.0 cubic inches."},
  {"id":482,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Manufacturers recommend that GFCI and AFCI devices be tested using their test buttons how often as a maintenance practice?","opts":["Only once at installation","Only when a fault occurs","Periodically, such as monthly","Never, since they are maintenance-free"],"correct":2,"re":"Because these protective devices can fail silently, manufacturers commonly advise testing the TEST button periodically, typically monthly, to confirm protection remains functional."},
  {"id":483,"sec":"Rough Wiring","block":5,"q":"Where an underground raceway enters a building or stub-up, the open end must be:","opts":["Left fully open for ventilation","Sealed to prevent the entrance of moisture","Filled with concrete","Capped with tape only"],"correct":1,"re":"NEC 300.5(G) requires raceways and conductor ends to be sealed to prevent moisture or gases from entering."},
  {"id":484,"sec":"Safety","block":5,"q":"Which type of ladder should an electrician select when working near exposed energized electrical conductors or equipment?","opts":["A fiberglass ladder","An aluminum extension ladder","A steel platform ladder","A wet wooden ladder"],"correct":0,"re":"Fiberglass ladders are non-conductive and are the appropriate choice for electrical work near energized parts; metal ladders are conductive and should be avoided."},
  {"id":485,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.6(A), which sequence correctly lists three consecutive standard fuse/breaker ampere ratings?","opts":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"correct":0,"re":"Standard ratings in NEC 240.6(A) include 30, 40, and 50 A consecutively; 55 A is not standard, so 50/55/60 is invalid."},
  {"id":486,"sec":"Rough Wiring","block":5,"q":"When roughing in a service mast used to support service-drop conductors, the mast and its attachments must be:","opts":["No larger than 1/2 in conduit","Made of plastic only","Of adequate strength to withstand the conductor strain","Limited to interior use"],"correct":2,"re":"NEC 230.28 requires the service mast to have adequate strength or be supported to withstand the strain of the service-drop conductors."},
  {"id":487,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A circuit feels warm at the breaker and the breaker trips after long runtime, yet a short-circuit test shows no bolted fault; this combination best fits which diagnosis?","opts":["An overload, possibly worsened by a loose connection adding heat","A dead short to ground","A failed AFCI sensor only","An open circuit"],"correct":0,"re":"Heat building over runtime with delayed tripping and no bolted short points to overload conditions, and a loose connection can add resistive heating that accelerates the trip."},
  {"id":488,"sec":"Finish Wiring & Trim","block":5,"q":"In a standard 120-volt branch circuit using NM cable, what is the required color of the equipment grounding conductor?","opts":["White or gray","Black or red","Green, green with a yellow stripe, or bare","Blue or yellow"],"correct":2,"re":"Per NEC 250.119, equipment grounding conductors must be green, green with one or more yellow stripes, or bare; white/gray is reserved for the grounded (neutral) conductor."},
  {"id":489,"sec":"Safety","block":5,"q":"Following the 4-to-1 rule for a straight or extension ladder, where should the base be placed if the ladder contacts the wall at a point 12 feet up?","opts":["1 foot away from the wall","3 feet away from the wall","6 feet away from the wall","12 feet away from the wall"],"correct":1,"re":"The 4-to-1 rule places the base 1 foot away from the wall for every 4 feet of working height; 12 feet divided by 4 equals 3 feet from the wall."},
  {"id":490,"sec":"Rough Wiring","block":5,"q":"Only which of the following may be attached to a service mast?","opts":["Television antennas","Clothesline hardware","Communication cables","Service-drop or overhead service conductors"],"correct":3,"re":"NEC 230.28(B) permits only service-drop or overhead service conductors to be attached to the service mast."},
  {"id":491,"sec":"Planning & Estimation","block":5,"q":"A branch circuit serves a 12 A continuous load plus an 8 A noncontinuous load; what minimum OCPD rating is required?","opts":["25 A","23 A","20 A","30 A"],"correct":0,"re":"Per NEC 210.20(A), OCPD ≥ (12 A × 1.25) + 8 A = 23 A, and the next standard size is 25 A."},
  {"id":492,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"When a 120-volt circuit shows correct voltage with no load but voltage collapses far below normal the moment a load is applied, the fault most likely lies in:","opts":["A high-resistance (loose or corroded) connection in the supply path","The load device being undersized","The GFCI test button","The grounding electrode conductor"],"correct":0,"re":"Voltage that is normal at no load but sags badly under load indicates a high-resistance series connection that drops voltage only when current flows."},
  {"id":493,"sec":"Rough Wiring","block":5,"q":"What is the minimum vertical clearance for service-drop conductors passing over a residential driveway, where the voltage does not exceed 300 volts to ground?","opts":["10 ft","18 ft","15 ft","12 ft"],"correct":3,"re":"NEC 230.24(B) requires 12 ft of clearance over residential driveways and areas subject to vehicular traffic for circuits not exceeding 300 volts to ground."},
  {"id":494,"sec":"Planning & Estimation","block":5,"q":"In voltage-drop calculations using the formula VD = 2 × K × I × L / CM, what does the variable 'CM' represent?","opts":["Conduit material","Conductor temperature in Celsius","Continuous-load multiplier","Circular mils of the conductor"],"correct":3,"re":"In the voltage-drop formula, CM is the conductor's cross-sectional area expressed in circular mils."},
  {"id":495,"sec":"Safety","block":5,"q":"Under the OSHA general industry standard (29 CFR 1910), at approximately what height above a lower level is fall protection generally required for workers on an elevated working surface?","opts":["2 feet","6 feet","4 feet","10 feet"],"correct":2,"re":"OSHA 29 CFR 1910.28 (general industry) generally requires fall protection at 4 feet above a lower level; the construction standard (1926) uses 6 feet."},
  {"id":496,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"After verifying a symptom and gathering information, the next logical step in a structured troubleshooting process is to:","opts":["Form a hypothesis about the probable cause and test it","Replace random components until it works","Document the repair before testing","Energize the circuit and walk away"],"correct":0,"re":"Effective troubleshooting follows a logical sequence: observe the symptom, gather data, hypothesize the likely cause, then test to confirm before repairing."},
  {"id":497,"sec":"Finish Wiring & Trim","block":5,"q":"Which of the following best describes the primary protective function of a GFCI (ground-fault circuit interrupter) receptacle?","opts":["It protects equipment from overheating due to overload","It detects arcing faults in the branch-circuit wiring","It protects people from electric shock by detecting small current imbalances between the hot and neutral conductors","It limits voltage spikes from lightning or switching surges"],"correct":2,"re":"A GFCI compares current on the hot and neutral and trips at a small imbalance (about 4-6 mA), protecting people from shock; an AFCI detects arcing and a surge device handles voltage spikes (NEC 210.8)."},
  {"id":498,"sec":"Rough Wiring","block":5,"q":"What is the minimum depth of clear working space required in front of electrical equipment likely to require examination while energized, under typical Condition 1 (600 volts or less), per 110.26?","opts":["2 ft","5 ft","4 ft","3 ft"],"correct":3,"re":"Table 110.26(A)(1) requires a minimum 3 ft (900 mm) of clear working depth under Condition 1."},
  {"id":499,"sec":"Planning & Estimation","block":5,"q":"For an existing one-gang device box, which value must be known to perform a box-fill calculation when the box is not listed in NEC Table 314.16(A)?","opts":["The box color","The conduit trade size","The breaker rating","The marked cubic-inch volume of the box"],"correct":3,"re":"Per NEC 314.16(A), nonstandard boxes must be durably marked with their volume in cubic inches for use in the calculation."},
  {"id":500,"sec":"Safety","block":5,"q":"Which combination of personal protective equipment is most appropriate when an electrician must perform an arc-flash-risk task such as racking a 480-volt breaker that cannot be de-energized?","opts":["Cotton T-shirt, standard sunglasses, and leather work gloves","Synthetic nylon jacket and latex examination gloves","Reflective vest, hard hat, and bare hands for better dexterity","Arc-rated clothing, a face shield or hood rated for the incident energy, and voltage-rated rubber gloves with leather protectors"],"correct":3,"re":"Energized work with arc-flash risk requires arc-rated clothing and face protection matched to the incident energy, plus voltage-rated rubber insulating gloves with leather protectors per NFPA 70E."}
];
